                    <div class="flow-tile" onclick="showFlow('preauth')">
                        <div class="tile-icon">
                            <svg width="48" height="48" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg">
                                <path d="M13.334 2.66699C14.0739 2.66699 14.6668 3.26016 14.667 4V7.30371C13.8538 6.49796 12.7352 6 11.5 6C9.93999 6 8.56609 6.79428 7.75879 8H2.66797V12H7.25781C7.43068 12.4889 7.68441 12.9392 8.00488 13.334H2.66797C1.92797 13.334 1.33398 12.74 1.33398 12L1.34082 4C1.34101 3.26016 1.92809 2.66699 2.66797 2.66699H13.334ZM2.66797 5.33398H13.334V4H2.66797V5.33398Z" fill="#404C49"/>
