                                    <div class="sm-panel-header">
                                        <span>Response Received</span>
                                        <button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button>
                            </div>
                                    <div id="smMandVerifyStatusBadge" class="sm-status-badge"></div>
                                    <pre><code id="smMandVerifyResponseView"></code></pre>
                                </div>
                                </div>
                            <div class="sm-response-guide" id="smMandVerifyResponseGuide" style="display:none;">
                                <h4>Understanding the Response</h4>
                                <div id="smMandVerifyResponseExplain"></div>
                            </div>
                            <div class="sm-curl-section">
                                <div class="sm-panel-header">
                                    <span>cURL Command</span>
                                    <button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button>
                                </div>
                                <pre><code id="smMandVerifyCurlView"></code></pre>
                                </div>
                            </div>

                        <div class="sm-next-btn-wrapper">
                            <button class="button" onclick="openSeamlessFlow('sm-mandate-status')">Next: Get Mandate Status &rarr;</button>
                                </div>
                                </div>

                    <!-- Section: Get UPI Mandate Status -->
                    <div class="seamless-section" id="sm-mandate-status">
                        <h2>Get UPI Mandate Status</h2>

                        <div class="sm-step-guide">
                            <div class="sm-guide-overview">
                                <h3>Overview</h3>
                                <p>After registering a UPI mandate, use the <code>upi_mandate_status</code> command to check the current status of the mandate. This API returns the mandate's approval status, active/inactive state, and other details. It uses POST to <code>postservice.php</code> with SHA-512 hash authentication.</p>
                            </div>

                            <div class="sm-guide-prereqs">
                                <h3>Prerequisites</h3>
                                <div class="sm-prereq-list">
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">&#10003;</span>
                                        <div><strong>Merchant Key &amp; Salt</strong><br>Your PayU test/UAT credentials</div>
                                    </div>
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">&#10003;</span>
                                        <div><strong>Successful Mandate Registration</strong><br>A UPI mandate must be registered first</div>
                                    </div>
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">&#10003;</span>
                                        <div><strong>authPayuId (mihpayid)</strong><br>The PayU ID from the mandate registration response</div>
                                    </div>
                                </div>
                            </div>

                            <div class="sm-guide-flow">
                                <h3>How It Works</h3>
                                <div class="sm-flow-diagram">
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">1</div>
                                        <div class="sm-flow-label">Merchant<br><small>Sends status request</small></div>
                                    </div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">2</div>
                                        <div class="sm-flow-label">PayU API<br><small>postservice.php</small></div>
                                    </div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">3</div>
                                        <div class="sm-flow-label">UPI Network<br><small>Checks mandate</small></div>
                                    </div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">4</div>
                                        <div class="sm-flow-label">Status Returned<br><small>Active / Paused / Revoked</small></div>
                                    </div>
                                </div>
                            </div>

                            <div class="sm-guide-steps">
                                <h3>Step-by-Step Guide</h3>
                                <div class="sm-numbered-steps">
                                    <div class="sm-step">
                                        <div class="sm-step-num">1</div>
                                        <div class="sm-step-content">
                                            <strong>Get the authPayuId</strong>
                                            <p>From your mandate registration response, get the <code>mihpayid</code> (this is your <code>authPayuId</code>).</p>
                                        </div>
                                    </div>
                                    <div class="sm-step">
                                        <div class="sm-step-num">2</div>
                                        <div class="sm-step-content">
                                            <strong>Build the var1 JSON</strong>
                                            <p>Create a JSON object with <code>authPayuId</code> and a unique <code>requestId</code>.</p>
                                        </div>
                                    </div>
                                    <div class="sm-step">
                                        <div class="sm-step-num">3</div>
                                        <div class="sm-step-content">
                                            <strong>Generate the hash</strong>
                                            <p>Compute <code>sha512(key|command|var1|salt)</code> where command is <code>upi_mandate_status</code>.</p>
                                        </div>
                                    </div>
                                    <div class="sm-step">
                                        <div class="sm-step-num">4</div>
                                        <div class="sm-step-content">
                                            <strong>POST to postservice.php</strong>
                                            <p>Send key, command, var1 (JSON string), and hash to the postservice endpoint.</p>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>

                        <h3>API Reference</h3>
                        <table class="sm-table">
                            <thead><tr><th>Parameter</th><th>Required</th><th>Description</th><th>Example</th></tr></thead>
                            <tbody>
                                <tr><td><code>key</code></td><td>Yes</td><td>Merchant key from PayU dashboard</td><td>a4vGC2</td></tr>
                                <tr><td><code>command</code></td><td>Yes</td><td>API command</td><td><strong>upi_mandate_status</strong></td></tr>
                                <tr><td><code>var1</code></td><td>Yes</td><td>JSON with authPayuId and requestId</td><td>{"authPayuId":"...","requestId":"..."}</td></tr>
                                <tr><td><code>hash</code></td><td>Yes</td><td>SHA-512 hash</td><td><em>(computed)</em></td></tr>
                            </tbody>
                        </table>

                        <div class="sm-code-block" style="margin-top:1rem;">
                            <div class="sm-code-header"><span>var1 JSON for upi_mandate_status</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>{
  "authPayuId": "403993715535364356",
  "requestId": "1892432asds15g6"
}</code></pre>
                        </div>

                        <div class="sm-code-block" style="margin-top:1rem;">
                            <div class="sm-code-header"><span>Hash Formula</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>sha512(key|command|var1|salt)
sha512(merchantKey|upi_mandate_status|{"authPayuId":"...","requestId":"..."}|merchantSalt)</code></pre>
                        </div>

