                    <!-- Section: UPI OTM Pre-Authorize -->
                    <div class="seamless-section" id="sm-otm">
                        <h2>UPI OTM Pre-Authorize</h2>

                        <!-- GUIDE: Overview -->
                        <div class="sm-step-guide">
                            <div class="sm-guide-overview">
                                <h3>Overview</h3>
                                <p>UPI One Time Mandate (OTM) allows pre-authorization of a payment. The amount is blocked in the customer's account and can be captured (fully or partially) later. This uses the <code>_payment</code> endpoint with <code>pre_authorize=1</code> and <code>api_version=7</code>. Supports both <strong>Normal Capture</strong> (single capture) and <strong>Multi Capture</strong> (multiple partial captures).</p>
                            </div>

                            <!-- Documentation Link -->
                            <a href="https://docs.payu.in/docs/upi-intent-one-time-mandate-integration" target="_blank" rel="noopener" class="sm-docs-banner">
                                <div class="sm-docs-banner-icon">&#128214;</div>
                                <div class="sm-docs-banner-body">
                                    <div class="sm-docs-banner-title">PayU Official Documentation <span class="sm-docs-badge">Docs</span></div>
                                    <div class="sm-docs-banner-desc">UPI Intent One-Time Mandate (OTM) &mdash; Pre-auth transaction request, capture flow, multi-capture, status check &amp; cancel integration.</div>
                                </div>
                                <span class="sm-docs-banner-arrow">&rarr;</span>
                            </a>

                            <!-- Prerequisites -->
                            <div class="sm-guide-prereqs">
                                <h3>Prerequisites</h3>
                                <div class="sm-prereq-list">
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">&#10003;</span>
                                        <div><strong>Merchant Key &amp; Salt</strong><br>Your PayU test/UAT credentials</div>
                                    </div>
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">&#10003;</span>
                                        <div><strong>UPI OTM Enabled</strong><br>Pre-authorization enabled on your PayU merchant account</div>
                                    </div>
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">&#10003;</span>
                                        <div><strong>api_version = 7</strong><br>Required so <code>si_details</code> JSON is included in the hash</div>
                                    </div>
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">&#10003;</span>
                                        <div><strong>si_details JSON</strong><br>Payment start/end dates; optionally <code>multiCapture: "Y"</code></div>
                                    </div>
                                </div>
                            </div>

                            <!-- Flow Diagram -->
                            <div class="sm-guide-flow">
                                <h3>How It Works</h3>
                                <div class="sm-flow-diagram">
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">1</div>
                                        <div class="sm-flow-label">Merchant<br><small>Sends OTM</small></div>
                                    </div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">2</div>
                                        <div class="sm-flow-label">PayU API<br><small>_payment</small></div>
                                    </div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">3</div>
                                        <div class="sm-flow-label">UPI Switch<br><small>Routes request</small></div>
                                    </div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">4</div>
                                        <div class="sm-flow-label">Amount Blocked<br><small>In customer a/c</small></div>
                                    </div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">5</div>
                                        <div class="sm-flow-label">Capture Later<br><small>Full / Partial</small></div>
                                    </div>
                                </div>
                            </div>

                            <!-- Step-by-Step -->
                            <div class="sm-guide-steps">
                                <h3>Step-by-Step Guide</h3>
                                <div class="sm-numbered-steps">
                                    <div class="sm-step">
                                        <div class="sm-step-num">1</div>
                                        <div class="sm-step-content">
                                            <strong>Choose capture type</strong>
                                            <p>Decide between Normal Capture (single full/partial capture) or Multi Capture (multiple partial captures). For multi capture, include <code>"multiCapture": "Y"</code> in <code>si_details</code>.</p>
                                        </div>
                                    </div>
                                    <div class="sm-step">
                                        <div class="sm-step-num">2</div>
                                        <div class="sm-step-content">
                                            <strong>Prepare si_details JSON</strong>
                                            <p>Build the JSON with <code>paymentStartDate</code> and <code>paymentEndDate</code>. Add <code>"multiCapture": "Y"</code> if using multi capture mode.</p>
                                        </div>
                                    </div>
                                    <div class="sm-step">
                                        <div class="sm-step-num">3</div>
                                        <div class="sm-step-content">
                                            <strong>Generate the hash (api_version=7)</strong>
                                            <p>Compute <code>sha512(key|txnid|amount|productinfo|firstname|email|udf1|udf2|udf3|udf4|udf5||||||si_details_json|salt)</code>. The <code>si_details</code> JSON string is appended before the salt.</p>
                                        </div>
                                    </div>
                                    <div class="sm-step">
                                        <div class="sm-step-num">4</div>
                                        <div class="sm-step-content">
                                            <strong>POST to PayU _payment endpoint</strong>
                                            <p>Send all parameters with <code>pre_authorize=1</code>, <code>pg=UPI</code>, <code>bankcode=INTENT</code>, <code>txn_s2s_flow=4</code>, <code>api_version=7</code>, plus <code>s2s_client_ip</code> and <code>s2s_device_info</code>.</p>
                                        </div>
                                    </div>
                                    <div class="sm-step">
                                        <div class="sm-step-num">5</div>
                                        <div class="sm-step-content">
                                            <strong>Amount is blocked &amp; capture later</strong>
                                            <p>Once the customer authorizes, the amount is blocked. Use <code>capture_transaction</code> API to capture the full or partial amount within the validity window.</p>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>

                        <!-- API Reference -->
                        <h3>API Reference</h3>
                        <table class="sm-table">
                            <thead><tr><th>Parameter</th><th>Required</th><th>Description</th><th>Example</th></tr></thead>
                            <tbody>
                                <tr><td><code>key</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Merchant key provided by PayU during onboarding</td><td>a4vGC2</td></tr>
                                <tr><td><code>salt</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Merchant salt for hash generation (never sent in request)</td><td>mGHSxpD2iB&hellip;</td></tr>
                                <tr><td><code>txnid</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Unique transaction/order ID (auto-generated if empty)</td><td>OTM_17345678</td></tr>
                                <tr><td><code>amount</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Block amount for the pre-authorization</td><td>18000</td></tr>
                                <tr><td><code>productinfo</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Brief product description</td><td>iPhone</td></tr>
                                <tr><td><code>firstname</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Customer's first name</td><td>Payu-Admin</td></tr>
                                <tr><td><code>email</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Customer's email address</td><td>test@example.com</td></tr>
                                <tr><td><code>phone</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Customer's phone number</td><td>9876543210</td></tr>
                                <tr><td><code>surl</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Success redirect URL</td><td>https://test.payu.in/admin/test_response</td></tr>
                                <tr><td><code>furl</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Failure redirect URL</td><td>https://test.payu.in/admin/test_response</td></tr>
                                <tr><td><code>pg</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Payment gateway category &mdash; fixed <code>UPI</code></td><td>UPI</td></tr>
                                <tr><td><code>bankcode</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Bank code for UPI Intent &mdash; fixed <code>INTENT</code></td><td>INTENT</td></tr>
                                <tr><td><code>txn_s2s_flow</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>S2S flow type &mdash; fixed <code>4</code> for UPI Intent</td><td>4</td></tr>
                                <tr><td><code>pre_authorize</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Enable pre-authorization &mdash; fixed <code>1</code></td><td>1</td></tr>
                                <tr><td><code>api_version</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>API version &mdash; fixed <code>7</code> (includes si_details in hash)</td><td>7</td></tr>
                                <tr><td><code>si_details</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>JSON with <code>paymentStartDate</code>, <code>paymentEndDate</code>, and optionally <code>multiCapture: "Y"</code></td><td>{"paymentStartDate":"2026-03-28","paymentEndDate":"2026-05-27"}</td></tr>
                                <tr><td><code>hash</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>SHA-512 hash (auto-computed)</td><td><em>(computed)</em></td></tr>
                                <tr><td><code>s2s_client_ip</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Source IP of the customer &mdash; required for UPI Intent flow</td><td>10.200.12.12</td></tr>
