                    <!-- Section: Pre-Debit Notification -->
                    <div class="seamless-section" id="sm-predebit">
                        <h2>Pre-Debit Notification</h2>

                        <!-- GUIDE: Overview -->
                        <div class="sm-step-guide">
                            <div class="sm-guide-overview">
                                <h3>Overview</h3>
                                <p>After a successful UPI Mandate Registration (and optionally checking/modifying the mandate), you must send a pre-debit notification using the <code>pre_debit_SI</code> command at least 24 hours before the scheduled debit. This is an NPCI mandate requirement. The API uses POST to <code>postservice.php</code> with SHA-512 hash authentication, where <code>var1</code> is a JSON string.</p>
                            </div>

                            <!-- Prerequisites -->
                            <div class="sm-guide-prereqs">
                                <h3>Prerequisites</h3>
                                <div class="sm-prereq-list">
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">&#10003;</span>
                                        <div><strong>Merchant Key &amp; Salt</strong><br>Your PayU test/UAT credentials</div>
                                    </div>
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">&#10003;</span>
                                        <div><strong>Successful Mandate Registration</strong><br>A UPI mandate must be registered and verified</div>
                                    </div>
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">&#10003;</span>
                                        <div><strong>authPayuId (mihpayid)</strong><br>The PayU ID from the verify payment response</div>
                                    </div>
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">&#10003;</span>
                                        <div><strong>24-Hour Pre-Debit Window</strong><br>NPCI mandates sending pre-debit notification at least 24h before the scheduled debit</div>
                                    </div>
                                </div>
                            </div>

                            <!-- Flow Diagram -->
                            <div class="sm-guide-flow">
                                <h3>How It Works</h3>
                                <div class="sm-flow-diagram">
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">1</div>
                                        <div class="sm-flow-label">Register<br><small>_payment</small></div>
                                    </div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">2</div>
                                        <div class="sm-flow-label">Verify<br><small>verify_payment</small></div>
                                    </div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">3</div>
                                        <div class="sm-flow-label">Status<br><small>mandate_status</small></div>
                                    </div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">4</div>
                                        <div class="sm-flow-label">Modify<br><small>mandate_modify</small></div>
                                    </div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step sm-flow-step-active">
                                        <div class="sm-flow-num">5</div>
                                        <div class="sm-flow-label">Pre-Debit<br><small>pre_debit_SI</small></div>
                                    </div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">6</div>
                                        <div class="sm-flow-label">SI Transaction<br><small>si_transaction</small></div>
                                    </div>
                                </div>
                            </div>

                            <!-- Step-by-Step -->
                            <div class="sm-guide-steps">
                                <h3>Step-by-Step Guide</h3>
                                <div class="sm-numbered-steps">
                                    <div class="sm-step">
                                        <div class="sm-step-num">1</div>
                                        <div class="sm-step-content">
                                            <strong>Enter authPayuId</strong>
                                            <p>Use the <code>mihpayid</code> from the Verify Payment response (auto-filled if you followed the flow).</p>
                                        </div>
                                    </div>
                                    <div class="sm-step">
                                        <div class="sm-step-num">2</div>
                                        <div class="sm-step-content">
                                            <strong>Set debit date and amount</strong>
                                            <p>The debit date must be at least 24 hours in the future. Amount should be within the mandate limits.</p>
                                        </div>
                                    </div>
                                    <div class="sm-step">
                                        <div class="sm-step-num">3</div>
                                        <div class="sm-step-content">
                                            <strong>Send pre-debit notification</strong>
                                            <p>Click &ldquo;Send to PayU&rdquo; to send the <code>pre_debit_SI</code> command. The customer will be notified of the upcoming debit.</p>
                                        </div>
                                    </div>
                                    <div class="sm-step">
                                        <div class="sm-step-num">4</div>
                                        <div class="sm-step-content">
                                            <strong>Proceed to SI Transaction</strong>
                                            <p>After the pre-debit notification is acknowledged, proceed to execute the actual recurring payment.</p>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>

                        <!-- API Reference: pre_debit_SI -->
                        <h3>API Reference &mdash; pre_debit_SI (Pre-Debit Notification)</h3>
                        <div class="sm-info-box warning">
                            <strong>Mandatory for UPI Recurring</strong>
                            <p>NPCI mandates sending a pre-debit notification to the customer at least 24 hours before the scheduled debit.</p>
                        </div>
                        <table class="sm-table">
                            <thead><tr><th>Parameter</th><th>Required</th><th>Description</th><th>Example</th></tr></thead>
                            <tbody>
                                <tr><td><code>key</code></td><td>Yes</td><td>Merchant key from PayU dashboard</td><td>a4vGC2</td></tr>
                                <tr><td><code>command</code></td><td>Yes</td><td>API command</td><td><strong>pre_debit_SI</strong></td></tr>
                                <tr><td><code>var1</code></td><td>Yes</td><td>JSON with pre-debit details: <code>authPayuId</code>, <code>requestId</code>, <code>debitDate</code> (YYYY-MM-DD), <code>amount</code></td><td>{"authPayuId":"...","requestId":"...","debitDate":"...","amount":"..."}</td></tr>
                                <tr><td><code>hash</code></td><td>Yes</td><td>SHA-512 hash (var1 is the JSON string)</td><td><em>(computed)</em></td></tr>
                            </tbody>
                        </table>

                        <!-- var1 JSON reference for pre_debit_SI -->
                        <div class="sm-code-block">
                            <div class="sm-code-header"><span>var1 JSON for pre_debit_SI</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>{
  "authPayuId": "403993715534484661",
  "requestId": "403993715534484661_1",
  "debitDate": "2025-09-06",
  "amount": "2.00"
}</code></pre>
                        </div>

                        <!-- Hash Formula for pre_debit_SI -->
                        <h3>Hash Formula (pre_debit_SI)</h3>
                        <div class="sm-code-block">
                            <div class="sm-code-header"><span>Pre-Debit Hash</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>sha512(key|command|var1|salt)
sha512(merchantKey|pre_debit_SI|{"authPayuId":"...","requestId":"...","debitDate":"...","amount":"..."}|merchantSalt)</code></pre>
                        </div>

                        <!-- INTERACTIVE FORM: Pre-Debit -->
                        <h3>Try It &mdash; Pre-Debit Notification</h3>
                        <div class="sm-interactive-form" id="smPreDebitForm">
                            <div class="sm-pay-section sm-pay-section-mandatory">
                                <h4>Mandatory Parameters</h4>
                            <div class="sm-form-row">
                                <div class="sm-form-group">
                                        <label>Merchant Key (key) <span class="sm-required">*</span></label>
                                    <input type="text" id="sm_predebit_key" value="a4vGC2">
                                </div>
                                <div class="sm-form-group">
                                        <label>Merchant Salt <span class="sm-required">*</span></label>
                                    <input type="password" id="sm_predebit_salt" value="hKvGJP28d2ZUuCRz5BnDag58QBdCxBli" placeholder="Enter your salt">
                                </div>
                            </div>
                            <div class="sm-form-row">
                                <div class="sm-form-group">
                                        <label>authPayuId (mihpayid) <span class="sm-required">*</span></label>
                                    <input type="text" id="sm_predebit_authPayuId" placeholder="e.g. 403993715534867054">
                                </div>
                                <div class="sm-form-group">
                                        <label>Request ID <span class="sm-required">*</span></label>
                                        <input type="text" id="sm_predebit_requestId" value="" placeholder="Auto-generated (authPayuId_1)">
                                </div>
                            </div>
                            <div class="sm-form-row">
                                <div class="sm-form-group">
                                        <label>Debit Date <span class="sm-required">*</span></label>
                                    <input type="text" id="sm_predebit_debitDate" placeholder="YYYY-MM-DD">
                                </div>
                                <div class="sm-form-group">
                                        <label>Amount <span class="sm-required">*</span></label>
                                        <input type="text" id="sm_predebit_amount" value="1000" placeholder="Amount">
                                </div>
                            </div>
                            </div>
                            <div class="sm-pay-section sm-pay-section-optional">
                                <h4>Optional Parameters</h4>
                            <div class="sm-form-row">
                                <div class="sm-form-group">
                                        <label>Invoice Display Number</label>
                                    <input type="text" id="sm_predebit_invoiceDisplayNumber" placeholder="e.g. INV_001">
                                </div>
                                </div>
                            </div>
                            <div class="sm-form-actions">
                                <button class="button sm-btn-fill-sample" onclick="smFillSampleData('predebit')">&#9889; Fill Sample Data</button>
                                <button class="button sm-btn-secondary" onclick="smPreviewPreDebitRequest()">Preview Request</button>
                                <button class="button sm-btn-primary" onclick="smSendPreDebitRequest()">Send to PayU &rarr;</button>
                            </div>
                        </div>

                        <!-- REQUEST & RESPONSE VIEWER: Pre-Debit -->
                        <div id="smPreDebitReqRes" class="sm-req-res-panel" style="display:none;">
                            <div class="sm-req-res-grid">
                                <div class="sm-req-panel">
                                    <div class="sm-panel-header">
                                        <span>Request Sent</span>
                                        <button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button>
                                    </div>
                                    <pre><code id="smPreDebitRequestView"></code></pre>
                                </div>
                                <div class="sm-res-panel">
                                    <div class="sm-panel-header">
                                        <span>Response Received</span>
                                        <button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button>
                                    </div>
                                    <div id="smPreDebitStatusBadge" class="sm-status-badge"></div>
                                    <pre><code id="smPreDebitResponseView"></code></pre>
                                </div>
                            </div>
                            <!-- Response Guide -->
                            <div class="sm-response-guide" id="smPreDebitResponseGuide" style="display:none;">
                                <h4>Understanding the Response</h4>
                                <div id="smPreDebitResponseExplain"></div>
                            </div>
                            <!-- cURL for reference -->
                            <div class="sm-curl-section">
                                <div class="sm-panel-header">
                                    <span>cURL Command</span>
                                    <button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button>
                                </div>
                                <pre><code id="smPreDebitCurlView"></code></pre>
                            </div>
                        </div>

                        <div class="sm-next-btn-wrapper">
                            <button class="button" onclick="openSeamlessFlow('sm-si')">Next: SI Transaction &rarr;</button>
                        </div>
                    </div>

                    <!-- Section: SI Transaction (Recurring Payment) -->
                    <div class="seamless-section" id="sm-si">
                        <h2>SI Transaction (Recurring Payment)</h2>

                        <!-- GUIDE: Overview -->
                        <div class="sm-step-guide">
                            <div class="sm-guide-overview">
                                <h3>Overview</h3>
                                <p>After sending the pre-debit notification, execute the actual recurring payment using the <code>si_transaction</code> command. This API debits the customer&rsquo;s account based on the registered UPI mandate. It uses POST to <code>postservice.php</code> with SHA-512 hash authentication, where <code>var1</code> is a JSON string containing transaction details.</p>
                            </div>

                            <!-- Prerequisites -->
                            <div class="sm-guide-prereqs">
                                <h3>Prerequisites</h3>
                                <div class="sm-prereq-list">
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">&#10003;</span>
                                        <div><strong>Merchant Key &amp; Salt</strong><br>Your PayU test/UAT credentials</div>
                                    </div>
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">&#10003;</span>
                                        <div><strong>Pre-Debit Notification Sent</strong><br>A pre_debit_SI must have been sent at least 24h before</div>
                                    </div>
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">&#10003;</span>
                                        <div><strong>authpayuid (mihpayid)</strong><br>The PayU ID from the verify payment response</div>
                                    </div>
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">&#10003;</span>
                                        <div><strong>Customer Details</strong><br>Name, email, and address information for the transaction</div>
                                    </div>
                                </div>
                            </div>

                            <!-- Flow Diagram -->
                            <div class="sm-guide-flow">
                                <h3>How It Works</h3>
                                <div class="sm-flow-diagram">
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">1</div>
                                        <div class="sm-flow-label">Register<br><small>_payment</small></div>
                                    </div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">2</div>
                                        <div class="sm-flow-label">Verify<br><small>verify_payment</small></div>
                                    </div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">3</div>
                                        <div class="sm-flow-label">Status<br><small>mandate_status</small></div>
                                    </div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">4</div>
                                        <div class="sm-flow-label">Modify<br><small>mandate_modify</small></div>
                                    </div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">5</div>
                                        <div class="sm-flow-label">Pre-Debit<br><small>pre_debit_SI</small></div>
                                    </div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step sm-flow-step-active">
                                        <div class="sm-flow-num">6</div>
                                        <div class="sm-flow-label">SI Transaction<br><small>si_transaction</small></div>
                                    </div>
                                </div>
                            </div>

                            <!-- Step-by-Step -->
                            <div class="sm-guide-steps">
                                <h3>Step-by-Step Guide</h3>
                                <div class="sm-numbered-steps">
                                    <div class="sm-step">
                                        <div class="sm-step-num">1</div>
                                        <div class="sm-step-content">
                                            <strong>Enter authpayuid</strong>
                                            <p>Use the <code>mihpayid</code> from the Verify Payment response (auto-filled if you followed the flow).</p>
                                        </div>
                                    </div>
                                    <div class="sm-step">
                                        <div class="sm-step-num">2</div>
                                        <div class="sm-step-content">
                                            <strong>Set amount and transaction details</strong>
                                            <p>Enter the recurring amount, a unique transaction ID, and customer details (name, email, address).</p>
                                        </div>
                                    </div>
                                    <div class="sm-step">
                                        <div class="sm-step-num">3</div>
                                        <div class="sm-step-content">
                                            <strong>Execute SI transaction</strong>
                                            <p>Click &ldquo;Send to PayU&rdquo; to execute the <code>si_transaction</code> command and debit the customer.</p>
                                        </div>
                                    </div>
                                    <div class="sm-step">
                                        <div class="sm-step-num">4</div>
                                        <div class="sm-step-content">
                                            <strong>Verify the payment</strong>
                                            <p>Use <code>verify_payment</code> with the SI txnid to confirm the payment was successful.</p>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>

                        <!-- API Reference: si_transaction -->
                        <h3>API Reference &mdash; si_transaction (Execute Recurring Payment)</h3>
                        <table class="sm-table">
                            <thead><tr><th>Parameter</th><th>Required</th><th>Description</th><th>Example</th></tr></thead>
                            <tbody>
                                <tr><td><code>key</code></td><td>Yes</td><td>Merchant key from PayU dashboard</td><td>a4vGC2</td></tr>
                                <tr><td><code>command</code></td><td>Yes</td><td>API command &mdash; fixed <code>si_transaction</code></td><td><strong>si_transaction</strong></td></tr>
                                <tr><td><code>var1</code></td><td>Yes</td><td>JSON object with transaction details (see var1 fields below)</td><td><em>(see below)</em></td></tr>
                                <tr><td><code>hash</code></td><td>Yes</td><td>SHA-512 hash: <code>sha512(key|command|var1|salt)</code></td><td><em>(computed)</em></td></tr>
                            </tbody>
                        </table>

                        <h4 style="margin-top:1rem;">var1 JSON Fields</h4>
                        <table class="sm-table">
                            <thead><tr><th>Field</th><th>Required</th><th>Description</th><th>Example</th></tr></thead>
                            <tbody>
                                <tr><td><code>authpayuid</code></td><td>Yes</td><td>Unique authentication payment ID from the registration transaction</td><td>403993715534484661</td></tr>
                                <tr><td><code>amount</code></td><td>Yes</td><td>Monetary value of the recurring transaction</td><td>100.00</td></tr>
                                <tr><td><code>txnid</code></td><td>Yes</td><td>Merchant-generated unique transaction ID</td><td>SI_1234567890</td></tr>
                                <tr><td><code>firstname</code></td><td>Yes</td><td>Customer&rsquo;s first name</td><td>Sudhanshu</td></tr>
                                <tr><td><code>email</code></td><td>Yes</td><td>Customer&rsquo;s email for communication and receipts</td><td>test@example.com</td></tr>
                                <tr><td><code>phone</code></td><td>Yes</td><td>Customer&rsquo;s contact number (echoed back in response)</td><td>9999999999</td></tr>
                                <tr><td><code>udf1</code></td><td>Yes</td><td>PAN and DOB separated by <code>||</code>: <code>PAN||DOB</code></td><td>ABCDE1234F||1990-01-01</td></tr>
                                <tr><td><code>udf3</code></td><td>Yes</td><td>Invoice ID and seller name separated by <code>||</code>: <code>invoiceId||sellerName</code></td><td>INV789||SellerName</td></tr>
                                <tr><td><code>lastname</code></td><td>No</td><td>Customer&rsquo;s last name</td><td>Kumar</td></tr>
                                <tr><td><code>address1</code></td><td>No</td><td>Customer&rsquo;s address line 1</td><td>308 third floor</td></tr>
                                <tr><td><code>address2</code></td><td>No</td><td>Customer&rsquo;s address line 2</td><td>my lane</td></tr>
                                <tr><td><code>city</code></td><td>No</td><td>Customer&rsquo;s city</td><td>Delhi</td></tr>
                                <tr><td><code>state</code></td><td>No</td><td>Customer&rsquo;s state</td><td>Delhi</td></tr>
                                <tr><td><code>country</code></td><td>No</td><td>Customer&rsquo;s country</td><td>India</td></tr>
                                <tr><td><code>zipcode</code></td><td>No</td><td>Customer&rsquo;s zipcode</td><td>110092</td></tr>
                                <tr><td><code>invoiceDisplayNumber</code></td><td>No</td><td>User-friendly invoice number displayed to the customer</td><td>INV-2024-001</td></tr>
                                <tr><td><code>udf2</code></td><td>No</td><td>Custom user-defined field (echoed back)</td><td></td></tr>
                                <tr><td><code>udf4</code></td><td>No</td><td>Custom user-defined field (echoed back)</td><td></td></tr>
                                <tr><td><code>udf5</code></td><td>No</td><td>Custom user-defined field (echoed back)</td><td></td></tr>
                            </tbody>
                        </table>

                        <div class="sm-info-box warning" style="margin-top:0.75rem;">
                            <strong>UDF Note:</strong> If the first value in a UDF is absent, it will be sent as <code>NULL||&lt;VALUE&gt;</code>. If the second value is absent, it will be sent as <code>&lt;VALUE&gt;</code>.
                        </div>

                        <!-- var1 JSON reference for si_transaction -->
                        <div class="sm-code-block" style="margin-top:1rem;">
                            <div class="sm-code-header"><span>var1 JSON for si_transaction (UPI)</span><button onclick="smCopyCode(this)">Copy</button></div>
