                    <!-- Section: Verify SI Payment -->
                    <div class="seamless-section" id="sm-si-verify">
                        <h2>Verify SI Payment (Autopay)</h2>

                        <div class="sm-step-guide">
                            <div class="sm-guide-overview">
                                <h3>Overview</h3>
                                <p>After executing a recurring SI Transaction, use the <code>verify_payment</code> command to confirm the debit status. This verifies whether the customer's account was successfully debited for the recurring payment.</p>
                            </div>

                            <div class="sm-guide-prereqs">
                                <h3>Prerequisites</h3>
                                <div class="sm-prereq-list">
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">&#10003;</span>
                                        <div><strong>Merchant Key &amp; Salt</strong><br>Your PayU test/UAT credentials</div>
                                    </div>
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">&#10003;</span>
                                        <div><strong>SI Transaction ID (txnid)</strong><br>The txnid used in the SI Transaction request</div>
                                    </div>
                                </div>
                            </div>

                            <div class="sm-guide-flow">
                                <h3>How It Works</h3>
                                <div class="sm-flow-diagram">
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">1</div>
                                        <div class="sm-flow-label">SI Transaction<br><small>Debit executed</small></div>
                                    </div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">2</div>
                                        <div class="sm-flow-label">Verify Payment<br><small>postservice.php</small></div>
                                    </div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">3</div>
                                        <div class="sm-flow-label">Response<br><small>Status returned</small></div>
                                    </div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step">
                                        <div class="sm-flow-num">4</div>
                                        <div class="sm-flow-label">Confirm<br><small>Debit success/fail</small></div>
                                    </div>
                                </div>
                            </div>

                            <div class="sm-guide-steps">
                                <h3>Step-by-Step Guide</h3>
                                <div class="sm-numbered-steps">
                                    <div class="sm-step">
                                        <div class="sm-step-num">1</div>
                                        <div class="sm-step-content">
                                            <strong>Get the SI txnid</strong>
                                            <p>Use the same transaction ID (<code>txnid</code>) that was used in the <code>si_transaction</code> request.</p>
                                        </div>
                                    </div>
                                    <div class="sm-step">
                                        <div class="sm-step-num">2</div>
                                        <div class="sm-step-content">
                                            <strong>Generate the hash</strong>
                                            <p>Compute <code>sha512(key|command|var1|salt)</code> where command is <code>verify_payment</code> and var1 is the SI txnid.</p>
                                        </div>
                                    </div>
                                    <div class="sm-step">
                                        <div class="sm-step-num">3</div>
                                        <div class="sm-step-content">
                                            <strong>POST to postservice.php</strong>
                                            <p>Send key, command (<code>verify_payment</code>), var1 (txnid), and hash.</p>
                                        </div>
                                    </div>
                                    <div class="sm-step">
                                        <div class="sm-step-num">4</div>
                                        <div class="sm-step-content">
                                            <strong>Check the response status</strong>
                                            <p>Look for <code>status</code> = <code>success</code> or <code>failure</code> to confirm whether the recurring debit was completed.</p>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>

                        <h3>API Reference</h3>
                        <table class="sm-table">
                            <thead><tr><th>Parameter</th><th>Required</th><th>Description</th><th>Example</th></tr></thead>
                            <tbody>
                                <tr><td><code>key</code></td><td>Yes</td><td>Merchant key from PayU dashboard</td><td>a4vGC2</td></tr>
                                <tr><td><code>command</code></td><td>Yes</td><td>API command</td><td><strong>verify_payment</strong></td></tr>
                                <tr><td><code>var1</code></td><td>Yes</td><td>Transaction ID (txnid) from SI Transaction</td><td>Rec_40399715537_1</td></tr>
                                <tr><td><code>hash</code></td><td>Yes</td><td>SHA-512 hash</td><td><em>(computed)</em></td></tr>
                            </tbody>
                        </table>

                        <div class="sm-code-block" style="margin-top:1rem;">
                            <div class="sm-code-header"><span>Hash Formula</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>sha512(key|command|var1|salt)
sha512(merchantKey|verify_payment|si_txnid|merchantSalt)</code></pre>
                        </div>

