                    <!-- Cards Flow Sections (each is a seamless-section) -->
                    <div id="seamlessCardsDetailContent">

                    <!-- ============================================ -->
                    <!-- NORMAL S2S CARD PAYMENT FLOW                 -->
                    <!-- ============================================ -->
                    <div class="seamless-section" id="sm-cards-normal">
                        <h2>Normal S2S Card Payment</h2>

                        <!-- Documentation Links -->
                        <div class="sm-doc-links" style="margin-bottom:1.5rem; padding:1rem; background:linear-gradient(135deg, #ecfdf5 0%, #d1fae5 100%); border:1px solid #34d399; border-radius:8px;">
                            <strong style="color:#065f46;">&#128213; Documentation</strong>
                            <div style="margin-top:0.5rem; display:flex; flex-wrap:wrap; gap:0.75rem;">
                                <a href="https://docs.payu.in/reference/_payment_s2s_classic_integration" target="_blank" style="color:#047857; text-decoration:none; font-size:0.9rem;">&#128279; S2S Classic Integration Guide</a>
                            </div>
                        </div>

                        <div class="sm-info-box">
                            <strong>Complete Card Payment Lifecycle</strong>
                            <p>This flow walks you through every API call needed for a standard server-to-server credit/debit card payment &mdash; from BIN validation to final verification.</p>
                            <p><strong>Prerequisite:</strong> You must be PCI DSS compliant (or use a PCI-compliant vault/tokenization solution) before handling raw card data in this seamless cards flow.</p>
                        </div>

                        <div class="sm-step-guide" style="margin-top:1.25rem;">
                            <div class="sm-guide-overview">
                                <h3>Seamless Cards Flow (S2S)</h3>
                                <p>3 phases: <strong>Pre-Payment</strong> (BIN checks + payment hash), <strong>Payment</strong> (initiate 3DS + optional OTP submission), and <strong>Post-Payment</strong> (verify final status and reconcile).</p>
                            </div>
                            <div class="sm-guide-prereqs">
                                <h3>Prerequisites</h3>
                                <div class="sm-prereq-list">
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">1</span>
                                        <div><strong>Merchant Key</strong><br>Used to authenticate PayU</div>
                                    </div>
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">2</span>
                                        <div><strong>Merchant Salt</strong><br>Used in hash generation</div>
                                    </div>
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">3</span>
                                        <div><strong>Card BIN / Card Details</strong><br>Required for getBinInfo and _payment</div>
                                    </div>
                                </div>
                            </div>
                        </div>

                        <div class="sm-phase-tabs">
                            <button class="sm-phase-tab active" onclick="smSwitchCardPhase(this,'cards-normal','pre')">
                                <span class="sm-phase-num">1</span> Pre-Payment
                            </button>
                            <button class="sm-phase-tab" onclick="smSwitchCardPhase(this,'cards-normal','pay')">
                                <span class="sm-phase-num">2</span> Payment
                            </button>
                            <button class="sm-phase-tab" onclick="smSwitchCardPhase(this,'cards-normal','post')">
                                <span class="sm-phase-num">3</span> Post-Payment
                            </button>
                        </div>

                        <!-- PRE-PAYMENT PHASE -->
                        <div class="sm-phase-content active" id="cards-normal-pre">
                            <div class="sm-step-guide">
                                <div class="sm-guide-overview">
                                    <h3>Pre-Payment: Validate &amp; Prepare</h3>
                                    <p>Validate BIN capabilities, check domestic/international applicability, and keep the correct SHA-512 payment hash ready for <code>_payment</code>.</p>
                                </div>
                                <div class="sm-guide-prereqs">
                                    <h3>What you do here</h3>
                                    <div class="sm-prereq-list">
                                        <div class="sm-prereq-item">
                                            <span class="sm-prereq-icon">1</span>
                                            <div><strong>getBinInfo</strong><br>Inspect network &amp; capabilities</div>
                                        </div>
                                        <div class="sm-prereq-item">
                                            <span class="sm-prereq-icon">2</span>
                                            <div><strong>check_isDomestic</strong> <span style="font-size:0.75rem;color:#856404;">(optional)</span><br>Decide applicability</div>
                                        </div>
                                        <div class="sm-prereq-item">
                                            <span class="sm-prereq-icon">3</span>
                                            <div><strong>Payment hash</strong><br>Generate the correct SHA-512 hash</div>
                                        </div>
                                    </div>
                                </div>
                            </div>

                            <div class="sm-timeline">
                                <div class="sm-timeline-item" id="nav-n-bininfo">
                                    <div class="sm-timeline-marker">1</div>
                                    <div class="sm-timeline-content">
                                        <strong>Get BIN Info API</strong>
                                        <p>Retrieve card BIN details &mdash; issuing bank, card type (credit/debit), network (Visa/Mastercard/Rupay), and capabilities (ATM PIN, OTP, Zero Redirect, SI support). Supports three modes: <strong>single BIN lookup</strong>, <strong>feature-based filtering</strong>, and <strong>bulk retrieval</strong> with pagination.</p>
                                        <div class="sm-api-badge">POST <code>https://test.payu.in/merchant/postservice.php?form=2</code> &nbsp;|&nbsp; Command: <code>getBinInfo</code></div>
                                        <div class="sm-api-badge">Hash: <code>sha512(key|command|var1|salt)</code></div>
                                        <table class="sm-table" style="margin-top:0.75rem;">
                                            <thead><tr><th>Parameter</th><th>Required</th><th>Description</th><th>Example</th></tr></thead>
                                            <tbody>
                                                <tr><td><code>key</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Merchant key provided by PayU</td><td><code>JPg****f</code></td></tr>
                                                <tr><td><code>command</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td><code>getBinInfo</code></td><td><code>getBinInfo</code></td></tr>
                                                <tr><td><code>var1</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Request type: <code>1</code> = single BIN lookup, <code>2</code> = feature-based BIN list, <code>3</code> = all BIN information</td><td><code>1</code></td></tr>
                                                <tr><td><code>var2</code></td><td><span class="sm-badge-conditional">Conditional</span></td><td>If var1=1: BIN number (e.g. 512345). If var1=2: <code>1</code> (ATM PIN support) or <code>2</code> (OTP-on-the-fly). If var1=3: leave empty.</td><td><code>512345</code></td></tr>
                                                <tr><td><code>var3</code></td><td><span class="sm-badge-optional">Optional</span></td><td>Start index for pagination (default: <code>0</code>). Used when var1=2 or var1=3.</td><td><code>0</code></td></tr>
                                                <tr><td><code>var4</code></td><td><span class="sm-badge-optional">Optional</span></td><td>Records per page / offset (default: <code>100</code>, range: 1&ndash;1000). Used when var1=2 or var1=3.</td><td><code>100</code></td></tr>
                                                <tr><td><code>var5</code></td><td><span class="sm-badge-optional">Optional</span></td><td>Set to <code>1</code> to get enhanced features: <code>is_zero_redirect_supported</code>, <code>is_si_supported</code>.</td><td><code>1</code></td></tr>
                                                <tr><td><code>hash</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td><code>sha512(key|getBinInfo|var1|salt)</code></td><td><em>(computed)</em></td></tr>
                                            </tbody>
                                        </table>
                                        <div class="sm-info-box" style="margin-top:1rem;">
                                            <strong>BIN API Use Cases</strong>
                                            <table class="sm-table" style="margin-top:0.5rem;font-size:0.85rem;">
                                                <thead><tr><th>Use Case</th><th>var1</th><th>var2</th><th>var3</th><th>var4</th><th>var5</th><th>Description</th></tr></thead>
                                                <tbody>
                                                    <tr><td>Single BIN Query</td><td>1</td><td>512345</td><td>0</td><td>0</td><td>0</td><td>Get info for a specific BIN</td></tr>
                                                    <tr><td>Single BIN + Enhanced</td><td>1</td><td>512345</td><td>0</td><td>0</td><td>1</td><td>Single BIN with zero redirect &amp; SI support</td></tr>
                                                    <tr><td>ATM PIN Support Cards</td><td>2</td><td>1</td><td>1</td><td>20</td><td>0</td><td>Get BINs with ATM PIN support</td></tr>
                                                    <tr><td>OTP Support Cards</td><td>2</td><td>2</td><td>1</td><td>20</td><td>0</td><td>Get BINs with OTP-on-the-fly support</td></tr>
                                                    <tr><td>All Cards &ndash; Page 1</td><td>3</td><td>&nbsp;</td><td>1</td><td>20</td><td>0</td><td>First 20 cards (records 1&ndash;20)</td></tr>
                                                    <tr><td>All Cards &ndash; Page 2</td><td>3</td><td>&nbsp;</td><td>21</td><td>20</td><td>0</td><td>Next 20 cards (records 21&ndash;40)</td></tr>
                                                    <tr><td>All Cards &ndash; Page 3</td><td>3</td><td>&nbsp;</td><td>41</td><td>20</td><td>0</td><td>Next 20 cards (records 41&ndash;60)</td></tr>
                                                    <tr><td>Large Batch Query</td><td>3</td><td>&nbsp;</td><td>1</td><td>100</td><td>0</td><td>Get 100 cards at once</td></tr>
                                                    <tr><td>Custom Range</td><td>3</td><td>&nbsp;</td><td>501</td><td>50</td><td>0</td><td>Cards 501&ndash;550</td></tr>
                                                </tbody>
                                            </table>
                                        </div>
                                        <div class="sm-interactive-form" style="margin-top:1rem;">
                                            <div class="sm-pay-section sm-pay-section-mandatory"><h4>Mandatory Parameters</h4>
                                            <div class="sm-form-row">
                                                <div class="sm-form-group">
                                                    <label>Merchant Key <span class="required">*</span></label>
                                                    <input type="text" id="sc_bin_key" value="a4vGC2">
                                                </div>
                                                <div class="sm-form-group">
                                                    <label>Merchant Salt <span class="required">*</span></label>
                                                    <input type="password" id="sc_bin_salt" value="hKvGJP28d2ZUuCRz5BnDag58QBdCxBli">
                                                </div>
                                            </div>
                                            <div class="sm-form-row">
                                                <div class="sm-form-group">
                                                    <label>var1 &ndash; Request Type <span class="required">*</span></label>
                                                    <input type="text" id="sc_bin_var1" value="1">
                                                    <small class="sm-field-hint">1 = Single BIN lookup</small>
                                                </div>
                                                <div class="sm-form-group" id="sc_bin_var2_group">
                                                    <label>var2 &ndash; BIN / Feature Code</label>
                                                    <input type="text" id="sc_bin_value" value="550690" maxlength="9" placeholder="e.g. 550690">
                                                    <small class="sm-field-hint" id="sc_bin_var2_hint">BIN number (first 6&ndash;9 digits) for single lookup</small>
                                                </div>
                                            </div>
                                            <div class="sm-form-row">
                                                <div class="sm-form-group">
                                                    <label>var3 &ndash; Start Index</label>
                                                    <input type="text" id="sc_bin_var3" value="0" placeholder="0">
                                                    <small class="sm-field-hint">Pagination start index (default: 0)</small>
                                                </div>
                                                <div class="sm-form-group">
                                                    <label>var4 &ndash; Records Per Page</label>
                                                    <input type="text" id="sc_bin_var4" value="0" placeholder="100">
                                                    <small class="sm-field-hint">Number of records to fetch (1&ndash;1000, default: 100)</small>
                                                </div>
                                            </div>
                                            <div class="sm-form-row">
                                                <div class="sm-form-group">
                                                    <label>var5 &ndash; Enhanced Features</label>
                                                    <select id="sc_bin_var5">
                                                        <option value="0">0 &ndash; Standard response</option>
                                                        <option value="1" selected>1 &ndash; Include zero redirect &amp; SI support</option>
                                                    </select>
                                                    <small class="sm-field-hint">Set to 1 for additional fields like is_zero_redirect_supported</small>
                                                </div>
                                            </div>
                                            </div>
                                            <div class="sm-form-actions">
                                                <button class="button" onclick="smCardGetBinInfoPreview()">Preview Request</button>
                                                <button class="button sm-btn-primary" onclick="smCardGetBinInfo()">Send getBinInfo Request</button>
                                            </div>
                                        </div>
                                        <div id="scBinReqRes" style="display:none;margin-top:1rem;">
                                            <div class="sm-req-res-grid">
                                                <div class="sm-req-panel">
                                                    <div class="sm-panel-header"><span>Request Sent</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div>
                                                    <pre><code id="scBinRequestView"></code></pre>
                                                </div>
                                                <div class="sm-res-panel">
                                                    <div class="sm-panel-header"><span>Response Received</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div>
                                                    <div id="scBinStatusBadge" class="sm-status-badge"></div>
                                                    <pre><code id="scBinResponseView"></code></pre>
                                                </div>
                                            </div>
                                            <div class="sm-curl-section">
                                                <div class="sm-panel-header"><span>cURL Command</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div>
                                                <pre><code id="scBinCurlView"></code></pre>
                                            </div>
                                        </div>
                                        <div id="scBinSummary" style="display:none;margin-top:1rem;padding:1rem 1.25rem;background:#fff;border:1px solid #e0e0e0;border-radius:10px;box-shadow:0 2px 8px rgba(0,0,0,0.04);"></div>
                                        <div class="sm-info-box" style="margin-top:1rem;border-left:4px solid #1976d2;padding:1rem 1.25rem;background:rgba(25,118,210,0.03);">
                                            <h4 style="color:#1976d2;margin:0 0 0.75rem;">Response Parameters &mdash; Use in Normal S2S Payment</h4>
                                            <table class="sm-table" style="font-size:0.85rem;">
                                                <thead><tr><th>Parameter</th><th>Values</th><th>Use Case in Normal S2S Flow</th></tr></thead>
                                                <tbody>
                                                    <tr><td><code>issuing_bank</code></td><td>e.g. <code>HDFC</code>, <code>ICICI</code></td><td>Identify the issuing bank for display and routing decisions</td></tr>
                                                    <tr><td><code>bin</code></td><td>BIN number</td><td>The matched BIN (6&ndash;9 digits). Use to confirm which BIN PayU resolved</td></tr>
                                                    <tr><td><code>category</code></td><td><code>creditcard</code> / <code>debitcard</code></td><td>Determine card type for surcharge rules or payment restrictions</td></tr>
                                                    <tr><td><code>card_type</code></td><td><code>VISA</code>, <code>MAST</code>, <code>AMEX</code>, <code>MAES</code>, <code>DINR</code></td><td>Set <code>bankcode</code> parameter in <code>_payment</code> API (e.g. <code>CC</code> for credit, <code>DC</code> for debit)</td></tr>
                                                    <tr><td><code>is_domestic</code></td><td><code>1</code> = Domestic, <code>0</code> = International</td><td>Domestic cards can use Native OTP. International cards typically redirect to 3DS. Also used by <code>check_isDomestic</code> step</td></tr>
                                                    <tr style="background:rgba(16,132,109,0.06);"><td><code>is_otp_on_the_fly</code></td><td><code>1</code> = Supported, <code>0</code> = Not</td><td><strong>Critical:</strong> If <code>1</code>, card supports <strong>Native OTP</strong> (pureS2S). You can use <code>submit_otp</code> API in Step 5 instead of 3DS redirect. If <code>0</code>, only Bank Page (3DS Redirect) is available</td></tr>
                                                    <tr><td><code>is_atmpin_card</code></td><td><code>1</code> / <code>0</code></td><td>If <code>1</code>, card supports ATM PIN authentication as alternative to OTP</td></tr>
                                                    <tr><td><code>is_zero_redirect_supported</code></td><td><code>1</code> / <code>0</code></td><td>If <code>1</code>, zero redirect (headless) payment is possible. Returned only when <code>var5=1</code></td></tr>
                                                    <tr><td><code>is_si_supported</code></td><td><code>1</code> / <code>0</code></td><td>If <code>1</code>, card supports Standing Instructions (recurring mandates). Returned only when <code>var5=1</code></td></tr>
                                                </tbody>
                                            </table>
                                        </div>
                                    </div>
                                </div>

                                <div class="sm-timeline-item" id="nav-n-isdomestic">
                                    <div class="sm-timeline-marker">2</div>
                                    <div class="sm-timeline-content">
                                        <strong>Check isDomestic (Card BIN API)</strong> <span style="background:#fff3cd;color:#856404;padding:2px 8px;border-radius:4px;font-size:0.8rem;font-weight:600;margin-left:6px;">OPTIONAL</span>
                                        <p>Determines whether a card BIN is <strong>domestic</strong> (Indian) or <strong>international</strong>, along with the issuing bank, card type (credit/debit), and card category. This is an <strong>optional</strong> pre-payment check &mdash; use it when you need to:</p>
                                        <ul style="margin:0.5rem 0 0.75rem 1.5rem;font-size:0.92rem;line-height:1.6;">
                                            <li>Apply different surcharges for international vs. domestic cards</li>
                                            <li>Block or allow specific card categories (e.g., only domestic cards)</li>
                                            <li>Show the issuing bank name on your checkout UI</li>
                                            <li>Decide payment routing before initiating the transaction</li>
                                        </ul>
                                        <div class="sm-info-box" style="margin-bottom:0.75rem;">
                                            <strong>When to skip this step:</strong> If you don&rsquo;t need to differentiate between domestic and international cards, you can proceed directly to the Payment Phase. The <code>getBinInfo</code> API in Step 1 already returns card type and bank information.
                                        </div>
                                        <div class="sm-api-badge">POST <code>https://test.payu.in/merchant/postservice.php?form=2</code> &nbsp;|&nbsp; Command: <code>check_isDomestic</code></div>
                                        <div class="sm-api-badge">Hash: <code>sha512(key|command|var1|salt)</code></div>
                                        <table class="sm-table" style="margin-top:0.75rem;">
                                            <thead><tr><th>Parameter</th><th>Required</th><th>Description</th><th>Example</th></tr></thead>
                                            <tbody>
                                                <tr><td><code>key</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Merchant key provided by PayU for authentication</td><td><code>JPg****f</code></td></tr>
                                                <tr><td><code>command</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td><code>check_isDomestic</code> &mdash; fixed value for this API</td><td><code>check_isDomestic</code></td></tr>
                                                <tr><td><code>var1</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>First <strong>6 digits</strong> of the card number (BIN). Must be exactly 6 digits.</td><td><code>512345</code></td></tr>
                                                <tr><td><code>hash</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td><code>sha512(key|check_isDomestic|var1|salt)</code></td><td><em>(computed)</em></td></tr>
                                            </tbody>
                                        </table>
                                        <div class="sm-info-box" style="margin-top:0.75rem;">
                                            <strong>Response Fields</strong>
                                            <table class="sm-table" style="margin-top:0.5rem;font-size:0.85rem;">
                                                <thead><tr><th>Field</th><th>Example</th><th>Description</th></tr></thead>
                                                <tbody>
                                                    <tr><td><code>isDomestic</code></td><td><code>Y</code> / <code>N</code></td><td><strong>Y</strong> = Domestic (Indian) card, <strong>N</strong> = International card</td></tr>
                                                    <tr><td><code>issuingBank</code></td><td><code>HDFC</code></td><td>Name of the card issuing bank</td></tr>
                                                    <tr><td><code>cardType</code></td><td><code>VISA</code></td><td>Card network (VISA, Mastercard, Rupay, etc.)</td></tr>
                                                    <tr><td><code>cardCategory</code></td><td><code>CC</code></td><td><code>CC</code> = Credit Card, <code>DC</code> = Debit Card</td></tr>
                                                </tbody>
                                            </table>
                                        </div>
                                        <div class="sm-interactive-form" style="margin-top:1rem;">
                                            <div class="sm-pay-section sm-pay-section-mandatory"><h4>Mandatory Parameters</h4>
                                            <div class="sm-form-row">
                                                <div class="sm-form-group">
                                                    <label>Merchant Key <span class="required">*</span></label>
                                                    <input type="text" id="sc_domestic_key" value="a4vGC2">
                                                </div>
                                                <div class="sm-form-group">
                                                    <label>Merchant Salt <span class="required">*</span></label>
                                                    <input type="password" id="sc_domestic_salt" value="hKvGJP28d2ZUuCRz5BnDag58QBdCxBli">
                                                </div>
                                            </div>
                                            <div class="sm-form-row">
                                                <div class="sm-form-group">
                                                    <label>var1 &ndash; Card BIN (first 6 digits) <span class="required">*</span></label>
                                                    <input type="text" id="sc_domestic_bin" value="550690" maxlength="6" placeholder="e.g. 550690">
                                                    <small class="sm-field-hint">Enter exactly the first 6 digits of the card number</small>
                                                </div>
                                            </div>
                                            </div>
                                            <div class="sm-form-actions">
                                                <button class="button" onclick="smCardCheckDomesticPreview()">Preview Request</button>
                                                <button class="button sm-btn-primary" onclick="smCardCheckDomestic()">Send check_isDomestic Request</button>
                                            </div>
                                        </div>
                                        <div id="scDomesticReqRes" class="sm-req-res-panel" style="display:none;margin-top:1rem;">
                                            <div class="sm-req-res-grid">
                                                <div class="sm-req-panel">
                                                    <div class="sm-panel-header"><span>Request Sent</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div>
                                                    <pre><code id="scDomesticRequestView"></code></pre>
                                                </div>
                                            <div class="sm-res-panel">
                                                <div class="sm-panel-header"><span>Response Received</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div>
                                                <div id="scDomesticStatusBadge" class="sm-status-badge"></div>
                                                <pre><code id="scDomesticResponseView"></code></pre>
                                            </div>
                                        </div>
                                            <div class="sm-curl-section">
                                                <div class="sm-panel-header"><span>cURL Command</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div>
                                                <pre><code id="scDomesticCurlView"></code></pre>
                                    </div>
                                </div>
                                        </div>
                                        </div>

                            </div>
                            <div class="sm-next-btn-wrapper">
                                <button class="button sm-btn-secondary" onclick="smSwitchCardPhase(document.querySelector('#sm-cards-normal .sm-phase-tab:nth-child(2)'),'cards-normal','pay')">Next: Initiate Payment &rarr;</button>
                            </div>
                        </div>

                        <!-- PAYMENT PHASE -->
                        <div class="sm-phase-content" id="cards-normal-pay">
                            <div class="sm-step-guide">
                                <div class="sm-guide-overview">
                                    <h3>Payment: Execute the Transaction</h3>
                                    <p>Send the card payment request to <code>_payment</code> and handle 3DS via <code>acsTemplate</code> and optional OTP submission.</p>
                                </div>
                                <div class="sm-guide-prereqs">
                                    <h3>Inputs required</h3>
                                    <div class="sm-prereq-list">
                                        <div class="sm-prereq-item">
                                            <span class="sm-prereq-icon">1</span>
                                            <div><strong>Card data + hash</strong><br>Include correct hash</div>
                                        </div>
                                        <div class="sm-prereq-item">
                                            <span class="sm-prereq-icon">2</span>
                                            <div><strong>S2S parameters</strong><br>Success &amp; failure URLs</div>
                                        </div>
                                        <div class="sm-prereq-item">
                                            <span class="sm-prereq-icon">3</span>
                                            <div><strong>OTP (optional)</strong><br>Only for Pure S2S when supported</div>
                                        </div>
                                    </div>
                                </div>
                            </div>

                            <div class="sm-timeline">
                                <div class="sm-timeline-item" id="nav-n-hash">
                                    <div class="sm-timeline-marker">3</div>
                                    <div class="sm-timeline-content">
                                        <strong>Generate Payment Hash</strong>
                                        <p>Before calling the <code>_payment</code> API, you must generate a <strong>SHA-512 hash</strong>. This hash ensures that no one has tampered with the payment request parameters. It acts as a digital signature between your server and PayU.</p>
                                        <div style="margin-top:0.75rem;border:1px solid #1976d2;border-radius:10px;overflow:hidden;">
                                            <div style="padding:0.6rem 1rem;background:#e3f2fd;border-bottom:1px solid #bbdefb;">
                                                <strong style="color:#1565c0;">Hash Formula for <code>_payment</code> API</strong>
                                            </div>
                                            <div style="padding:0.85rem 1rem;">
                                                <code style="display:block;background:#f5f5f5;padding:0.75rem;border-radius:6px;font-size:0.9rem;word-break:break-all;border:1px solid #e0e0e0;">sha512(key|txnid|amount|productinfo|firstname|email|udf1|udf2|udf3|udf4|udf5||||||salt)</code>
                                                <table style="width:100%;border-collapse:collapse;font-size:0.85rem;margin-top:0.75rem;">
                                                    <thead><tr style="background:#f5f5f5;"><th style="padding:0.4rem 0.5rem;text-align:left;border-bottom:1px solid #e0e0e0;">Field</th><th style="padding:0.4rem 0.5rem;text-align:left;border-bottom:1px solid #e0e0e0;">Description</th><th style="padding:0.4rem 0.5rem;text-align:left;border-bottom:1px solid #e0e0e0;">Example</th></tr></thead>
                                                    <tbody>
                                                        <tr style="border-bottom:1px solid #f0f0f0;"><td style="padding:0.35rem 0.5rem;"><code>key</code></td><td style="padding:0.35rem 0.5rem;">Merchant Key provided by PayU</td><td style="padding:0.35rem 0.5rem;font-family:monospace;">a4vGC2</td></tr>
                                                        <tr style="border-bottom:1px solid #f0f0f0;"><td style="padding:0.35rem 0.5rem;"><code>txnid</code></td><td style="padding:0.35rem 0.5rem;">Your unique transaction ID</td><td style="padding:0.35rem 0.5rem;font-family:monospace;">TXN_1234567890</td></tr>
                                                        <tr style="border-bottom:1px solid #f0f0f0;"><td style="padding:0.35rem 0.5rem;"><code>amount</code></td><td style="padding:0.35rem 0.5rem;">Transaction amount</td><td style="padding:0.35rem 0.5rem;font-family:monospace;">10.00</td></tr>
                                                        <tr style="border-bottom:1px solid #f0f0f0;"><td style="padding:0.35rem 0.5rem;"><code>productinfo</code></td><td style="padding:0.35rem 0.5rem;">Product description</td><td style="padding:0.35rem 0.5rem;font-family:monospace;">Test Product</td></tr>
                                                        <tr style="border-bottom:1px solid #f0f0f0;"><td style="padding:0.35rem 0.5rem;"><code>firstname</code></td><td style="padding:0.35rem 0.5rem;">Customer first name</td><td style="padding:0.35rem 0.5rem;font-family:monospace;">Test</td></tr>
                                                        <tr style="border-bottom:1px solid #f0f0f0;"><td style="padding:0.35rem 0.5rem;"><code>email</code></td><td style="padding:0.35rem 0.5rem;">Customer email</td><td style="padding:0.35rem 0.5rem;font-family:monospace;">test@example.com</td></tr>
                                                        <tr style="border-bottom:1px solid #f0f0f0;"><td style="padding:0.35rem 0.5rem;"><code>udf1&ndash;udf5</code></td><td style="padding:0.35rem 0.5rem;">User-defined fields &mdash; pass empty string if not used</td><td style="padding:0.35rem 0.5rem;font-family:monospace;">(empty)</td></tr>
                                                        <tr style="border-bottom:1px solid #f0f0f0;"><td style="padding:0.35rem 0.5rem;"><code>||||||</code></td><td style="padding:0.35rem 0.5rem;">Six pipes for empty udf6&ndash;udf10 (always required)</td><td style="padding:0.35rem 0.5rem;font-family:monospace;">||||||</td></tr>
                                                        <tr><td style="padding:0.35rem 0.5rem;"><code>salt</code></td><td style="padding:0.35rem 0.5rem;">Merchant Salt &mdash; <strong>never expose to client</strong></td><td style="padding:0.35rem 0.5rem;font-family:monospace;">hKvGJP28d2...</td></tr>
                                                    </tbody>
                                                </table>
                                                <div style="margin-top:0.75rem;padding:0.5rem 0.75rem;background:#fce4ec;border-left:3px solid #c62828;border-radius:4px;font-size:0.82rem;color:#b71c1c;line-height:1.5;">
                                                    <strong>&#9888; Security Rules:</strong>
                                                    <ul style="margin:0.25rem 0 0 1rem;padding:0;">
                                                        <li>Hash <strong>MUST</strong> be generated <strong>server-side</strong> &mdash; never expose your Salt on the client/browser</li>
                                                        <li>Empty UDF fields must remain as empty strings (not omitted) in the hash string</li>
                                                        <li>The <code>||||||</code> (six pipes) between <code>udf5</code> and <code>salt</code> are for empty udf6&ndash;udf10 and are <strong>always required</strong></li>
                                                    </ul>
                                                </div>
                                                <div style="margin-top:0.5rem;padding:0.5rem 0.75rem;background:#e3f2fd;border-left:3px solid #1976d2;border-radius:4px;font-size:0.82rem;color:#0d47a1;line-height:1.5;">
                                                    <strong>Not included in hash:</strong> <code>ccnum</code>, <code>ccvv</code>, <code>ccexpmon</code>, <code>ccexpyr</code>, <code>pg</code>, <code>bankcode</code>, <code>surl</code>, <code>furl</code>, <code>txn_s2s_flow</code> &mdash; these are sent as separate parameters but are not part of the hash computation.
                                                </div>
                                                <div style="margin-top:0.5rem;padding:0.5rem 0.75rem;background:#fff8e1;border-left:3px solid #ff8f00;border-radius:4px;font-size:0.82rem;color:#5d4037;line-height:1.5;">
                                                    <strong>In this Integration Lab:</strong> The hash is auto-computed client-side for testing convenience. <strong>In production, always compute the hash on your server.</strong>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </div>

                                <div class="sm-timeline-item" id="nav-n-payment">
                                    <div class="sm-timeline-marker">4</div>
                                    <div class="sm-timeline-content">
                                        <strong>Card Payment API (<code>_payment</code>)</strong>
                                        <p>Submit the card payment request with all card details, S2S flow parameters, and the generated hash. The <code>txn_s2s_flow=4</code> parameter enables the Cards Decoupled (S2S) flow.</p>
                                        <div class="sm-api-badge">POST <code>https://test.payu.in/_payment</code></div>
                                        <div class="sm-api-badge">Content-Type: <code>application/x-www-form-urlencoded</code></div>
                                        <table class="sm-table" style="margin-top:0.75rem;">
                                            <thead><tr><th>Parameter</th><th>Required</th><th>Description</th><th>Example</th></tr></thead>
                                            <tbody>
                                                <tr><td><code>key</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Merchant key provided by PayU during onboarding</td><td><code>JPg****f</code></td></tr>
                                                <tr><td><code>txnid</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Unique transaction ID generated by the merchant. PayU rejects duplicate txnids.</td><td><code>ypl938459435</code></td></tr>
                                                <tr><td><code>amount</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Payment amount for the transaction</td><td><code>10.00</code></td></tr>
                                                <tr><td><code>productinfo</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Brief description of the product</td><td><code>iPhone</code></td></tr>
                                                <tr><td><code>firstname</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Customer first name</td><td><code>Ashish</code></td></tr>
                                                <tr><td><code>email</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Customer email address</td><td><code>test@gmail.com</code></td></tr>
                                                <tr><td><code>phone</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Customer phone number</td><td><code>9876543210</code></td></tr>
                                                <tr><td><code>pg</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Payment gateway type. <code>CC</code> for Credit Card, <code>DC</code> for Debit Card</td><td><code>CC</code></td></tr>
                                                <tr><td><code>bankcode</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Bank code for the card type (e.g. <code>CC</code>, <code>DC</code>, <code>AMEX</code>)</td><td><code>CC</code></td></tr>
                                                <tr><td><code>ccnum</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>13&ndash;19 digit card number (15 for AMEX, 13&ndash;19 for Maestro). Validated with LUHN algorithm.</td><td><code>5123456789012346</code></td></tr>
                                                <tr><td><code>ccname</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Name on card as entered by the customer</td><td><code>Test User</code></td></tr>
                                                <tr><td><code>ccvv</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>3-digit CVV (4-digit CID for AMEX)</td><td><code>123</code></td></tr>
                                                <tr><td><code>ccexpmon</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Card expiry month in MM format (e.g. <code>01</code>, <code>12</code>)</td><td><code>05</code></td></tr>
                                                <tr><td><code>ccexpyr</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Card expiry year in YYYY format (e.g. <code>2030</code>)</td><td><code>2030</code></td></tr>
                                                <tr><td><code>surl</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Success URL &mdash; PayU redirects here on successful transaction</td><td>https://test.payu.in/admin/test_response</td></tr>
                                                <tr><td><code>furl</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Failure URL &mdash; PayU redirects here on failed transaction</td><td>https://test.payu.in/admin/test_response</td></tr>
                                                <tr><td><code>hash</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>SHA-512 hash: <code>sha512(key|txnid|amount|productinfo|firstname|email|udf1|udf2|udf3|udf4|udf5||||||SALT)</code></td><td><em>(computed)</em></td></tr>
                                                <tr><td><code>txn_s2s_flow</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Must be <code>4</code> for Cards Decoupled (S2S) flow</td><td><code>4</code></td></tr>
                                                <tr><td><code>s2s_client_ip</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>The source IP of the customer</td><td><code>10.200.12.12</code></td></tr>
                                                <tr><td><code>s2s_device_info</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>The customer agent&rsquo;s device information (User-Agent string)</td><td>Mozilla/5.0 (Windows NT 10.0; Win64; x64)</td></tr>
                                                <tr><td><code>zipcode</code></td><td><span class="sm-badge-optional">Optional</span></td><td>Customer&rsquo;s PIN code (6 digits)</td><td><code>400004</code></td></tr>
                                                <tr><td><code>address1</code></td><td><span class="sm-badge-optional">Optional</span></td><td>Billing address line 1 (up to 100 characters). Recommended for higher approval rate.</td><td>123 Main Street</td></tr>
                                                <tr><td><code>address2</code></td><td><span class="sm-badge-optional">Optional</span></td><td>Billing address line 2 (up to 100 characters)</td><td>Suite 100</td></tr>
                                                <tr><td><code>city</code></td><td><span class="sm-badge-optional">Optional</span></td><td>Customer city (max 50 characters). Recommended for higher approval rate.</td><td>Mumbai</td></tr>
                                                <tr><td><code>state</code></td><td><span class="sm-badge-optional">Optional</span></td><td>Customer state (max 50 characters)</td><td>Maharashtra</td></tr>
                                                <tr><td><code>country</code></td><td><span class="sm-badge-optional">Optional</span></td><td>Customer country (max 50 characters). Recommended for higher approval rate.</td><td>India</td></tr>
                                                <tr><td><code>lastname</code></td><td><span class="sm-badge-optional">Optional</span></td><td>Customer last name (alphabets only)</td><td>Kumar</td></tr>
                                                <tr><td><code>udf1</code></td><td><span class="sm-badge-optional">Optional</span></td><td>User-defined field 1 (up to 255 characters)</td><td>&mdash;</td></tr>
                                                <tr><td><code>udf2</code></td><td><span class="sm-badge-optional">Optional</span></td><td>User-defined field 2 (up to 255 characters)</td><td>&mdash;</td></tr>
                                                <tr><td><code>udf3</code></td><td><span class="sm-badge-optional">Optional</span></td><td>Date of Birth (DOB) of buyer in DD-MM-YYYY. Recommended for higher approval rate.</td><td>22-08-1990</td></tr>
                                                <tr><td><code>udf4</code></td><td><span class="sm-badge-optional">Optional</span></td><td>User-defined field 4 (up to 255 characters)</td><td>&mdash;</td></tr>
                                                <tr><td><code>udf5</code></td><td><span class="sm-badge-optional">Optional</span></td><td>User-defined field 5 (up to 255 characters)</td><td>&mdash;</td></tr>
                                                <tr><td><code>store_card</code></td><td><span class="sm-badge-optional">Optional</span></td><td>Set to <code>1</code> to tokenize the card for future use</td><td><code>1</code></td></tr>
                                                <tr><td><code>user_credentials</code></td><td><span class="sm-badge-conditional">Conditional</span></td><td>Required if <code>store_card=1</code>. Format: <code>merchantKey:uniqueCustomerId</code></td><td><code>JPg****f:customer1</code></td></tr>
                                            </tbody>
                                        </table>
                                        <div class="sm-interactive-form" style="margin-top:1rem;">
                                            <div class="sm-pay-section sm-pay-section-mandatory">
                                            <h4>Mandatory Parameters</h4>
                                            <div class="sm-form-row">
                                                <div class="sm-form-group">
                                                    <label>Merchant Key <span class="required">*</span></label>
                                                    <input type="text" id="sc_pay_key" value="a4vGC2">
                                                </div>
                                                <div class="sm-form-group">
                                                    <label>Merchant Salt <span class="required">*</span></label>
                                                    <input type="password" id="sc_pay_salt" value="hKvGJP28d2ZUuCRz5BnDag58QBdCxBli">
                                                </div>
                                            </div>
                                            <div class="sm-form-row">
                                                <div class="sm-form-group">
                                                    <label>Transaction ID (txnid) <span class="required">*</span></label>
                                                    <div style="display:flex;gap:0.5rem;align-items:center;">
                                                        <input type="text" id="sc_pay_txnid" placeholder="Auto-generated" style="flex:1;">
                                                        <button type="button" onclick="smNewTxnId('sc_pay_txnid','TXN_')" style="padding:0.5rem 1rem;background:#10846D;color:#fff;border:none;border-radius:8px;cursor:pointer;font-weight:600;font-size:0.85rem;white-space:nowrap;">New Txn ID</button>
                                                    </div>
                                                </div>
                                                <div class="sm-form-group">
                                                    <label>Amount <span class="required">*</span></label>
                                                    <input type="text" id="sc_pay_amount" value="10.00">
                                                </div>
                                            </div>
                                            <div class="sm-form-row">
                                                <div class="sm-form-group">
                                                    <label>Product Info <span class="required">*</span></label>
                                                    <input type="text" id="sc_pay_productinfo" value="Test Product">
                                                </div>
                                                <div class="sm-form-group">
                                                    <label>First Name <span class="required">*</span></label>
                                                    <input type="text" id="sc_pay_firstname" value="Test">
                                                </div>
                                            </div>
                                            <div class="sm-form-row">
                                                <div class="sm-form-group">
                                                    <label>Email <span class="required">*</span></label>
                                                    <input type="text" id="sc_pay_email" value="test@example.com">
                                                </div>
                                                <div class="sm-form-group">
                                                    <label>Phone <span class="required">*</span></label>
                                                    <input type="text" id="sc_pay_phone" value="9876543210">
                                                </div>
                                            </div>
                                            <div class="sm-form-row">
                                                <div class="sm-form-group">
                                                    <label>Card Number <span class="required">*</span></label>
                                                    <input type="text" id="sc_pay_ccnum" value="5123456789012346" placeholder="13-19 digits">
                                                </div>
                                                <div class="sm-form-group">
                                                    <label>Name on Card (ccname) <span class="required">*</span></label>
                                                    <input type="text" id="sc_pay_ccname" value="Ashish Kumar">
                                                </div>
                                            </div>
                                            <div class="sm-form-row">
                                                <div class="sm-form-group">
                                                    <label>Expiry Month <span class="required">*</span></label>
                                                    <input type="text" id="sc_pay_ccexpmon" value="05" placeholder="MM">
                                                </div>
                                                <div class="sm-form-group">
                                                    <label>Expiry Year <span class="required">*</span></label>
                                                    <input type="text" id="sc_pay_ccexpyr" value="2030" placeholder="YYYY">
                                                </div>
                                            </div>
                                            <div class="sm-form-row">
                                                <div class="sm-form-group">
                                                    <label>CVV <span class="required">*</span></label>
                                                    <input type="password" id="sc_pay_ccvv" value="123" placeholder="3-4 digits">
                                                </div>
                                                <div class="sm-form-group">
                                                    <label>PG <span class="required">*</span></label>
                                                    <input type="text" id="sc_pay_pg" value="CC" placeholder="e.g. CC, DC">
                                                </div>
                                            </div>
                                            <div class="sm-form-row">
                                                <div class="sm-form-group">
                                                    <label>Bank Code (bankcode) <span class="required">*</span></label>
                                                    <input type="text" id="sc_pay_bankcode" value="CC" placeholder="e.g. CC, DC, AMEX">
                                                </div>
                                            </div>
                                            <div class="sm-form-row">
                                                <div class="sm-form-group">
                                                    <label>Success URL (surl) <span class="required">*</span></label>
                                                    <input type="text" id="sc_pay_surl" value="">
                                                </div>
                                                <div class="sm-form-group">
                                                    <label>Failure URL (furl) <span class="required">*</span></label>
                                                    <input type="text" id="sc_pay_furl" value="">
                                                </div>
                                            </div>
                                            <div class="sm-form-row">
                                                <div class="sm-form-group">
                                                    <label>Client IP (s2s_client_ip) <span class="required">*</span></label>
                                                    <input type="text" id="sc_pay_s2s_client_ip" value="10.200.12.12" placeholder="e.g. 10.200.12.12">
                                                </div>
                                                <div class="sm-form-group">
                                                    <label>Device Info (s2s_device_info) <span class="required">*</span></label>
                                                    <input type="text" id="sc_pay_s2s_device_info" value="" placeholder="Auto-filled with User-Agent">
                                                </div>
                                            </div>
                                            </div>
                                            <div class="sm-pay-section sm-pay-section-conditional">
                                            <h4>Conditional Parameters</h4>
                                            <div class="sm-form-row">
                                                <div class="sm-form-group">
                                                    <label>Store Card <small style="color:#92400e;">&mdash; set to 1 to tokenize</small></label>
                                                    <select id="sc_pay_store_card">
                                                        <option value="0">0 - Don't Store</option>
                                                        <option value="1" selected>1 - Store Card</option>
                                                    </select>
                                                    <small class="sm-field-hint">Set to 1 to tokenize the card for future use</small>
                                                </div>
                                                <div class="sm-form-group">
                                                    <label>User Credentials <small style="color:#92400e;">&mdash; required if store_card=1</small></label>
                                                    <input type="text" id="sc_pay_user_cred" value="" placeholder="key:customer_id (for storing)">
                                                    <small class="sm-field-hint">Required if <code>store_card=1</code>. Format: <code>merchantKey:uniqueCustomerId</code></small>
                                                </div>
                                            </div>
                                            </div>
                                            <div class="sm-pay-section sm-pay-section-optional">
                                            <h4>Optional Parameters <small style="font-weight:normal;color:#818cf8;font-size:0.8rem;">(included in request only if filled)</small></h4>
                                            <div class="sm-form-row">
                                                <div class="sm-form-group"><label>Address Line 1 (address1) <span style="color:#e65100;font-size:0.75rem;">recommended</span></label><input type="text" id="sc_pay_address1" value="" placeholder="e.g. PayU, Bestech Business Tower, Gurgaon"></div>
                                                <div class="sm-form-group"><label>Address Line 2 (address2)</label><input type="text" id="sc_pay_address2" value="" placeholder="e.g. Sohna Road"></div>
                                            </div>
                                            <div class="sm-form-row">
                                                <div class="sm-form-group"><label>City <span style="color:#e65100;font-size:0.75rem;">recommended</span></label><input type="text" id="sc_pay_city" value="" placeholder="e.g. Gurgaon"></div>
                                                <div class="sm-form-group"><label>State</label><input type="text" id="sc_pay_state" value="" placeholder="e.g. Haryana"></div>
                                            </div>
                                            <div class="sm-form-row">
                                                <div class="sm-form-group"><label>Country <span style="color:#e65100;font-size:0.75rem;">recommended</span></label><input type="text" id="sc_pay_country" value="" placeholder="e.g. India"></div>
                                                <div class="sm-form-group"><label>Zipcode</label><input type="text" id="sc_pay_zipcode" value="" placeholder="6-digit PIN code e.g. 122018"></div>
                                            </div>
                                            <div class="sm-form-row">
                                                <div class="sm-form-group"><label>UDF1</label><input type="text" id="sc_pay_udf1" value="" placeholder="User Defined Field 1"></div>
                                                <div class="sm-form-group"><label>UDF2</label><input type="text" id="sc_pay_udf2" value="" placeholder="User Defined Field 2"></div>
                                            </div>
                                            <div class="sm-form-row">
                                                <div class="sm-form-group"><label>UDF3</label><input type="text" id="sc_pay_udf3" value="" placeholder="User Defined Field 3"></div>
                                                <div class="sm-form-group"><label>UDF4</label><input type="text" id="sc_pay_udf4" value="" placeholder="User Defined Field 4"></div>
                                            </div>
                                            <div class="sm-form-row">
                                                <div class="sm-form-group"><label>UDF5</label><input type="text" id="sc_pay_udf5" value="" placeholder="User Defined Field 5"></div>
                                                <div class="sm-form-group"><label>Last Name (lastname)</label><input type="text" id="sc_pay_lastname" value="" placeholder="Customer last name"></div>
                                            </div>
                                            </div>
                                            <div class="sm-form-actions">
                                                <button class="button sm-btn-secondary" onclick="smCardPreviewPayment('normal')">Preview Request</button>
                                                <button class="button sm-btn-primary" onclick="smCardSendPayment('normal')">Send to PayU</button>
                                            </div>
                                        </div>
                                        <div id="scPayReqRes" class="sm-req-res-panel" style="display:none;margin-top:1rem;">
                                            <div class="sm-req-res-grid">
                                                <div class="sm-req-panel">
                                                    <div class="sm-panel-header"><span>Request Sent</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div>
                                                    <pre><code id="scPayRequestView"></code></pre>
                                                </div>
                                                <div class="sm-res-panel">
                                                    <div class="sm-panel-header"><span>Response Received</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div>
                                                    <div id="scPayStatusBadge" class="sm-status-badge"></div>
                                                    <pre><code id="scPayResponseView"></code></pre>
                                                </div>
                                            </div>
                                            <div class="sm-response-guide" id="scPayResponseGuide" style="display:none;">
                                                <h4>Understanding the Response</h4>
                                                <div id="scPayResponseExplain"></div>
                                            </div>
                                            <div class="sm-curl-section">
                                                <div class="sm-panel-header"><span>cURL Command</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div>
                                                <pre><code id="scPayCurlView"></code></pre>
                                            </div>
                                        </div>
                                    </div>
                                </div>

                                <div class="sm-timeline-item" id="nav-n-3ds">
                                    <div class="sm-timeline-marker">5</div>
                                    <div class="sm-timeline-content">
                                        <strong>Handle 3DS / Submit OTP</strong>
                                        <p>After the payment API call, check <code>binData.pureS2SSupported</code> in the response to determine how the customer completes 3DS authentication:</p>

                                        <!-- pureS2SSupported status indicator -->
                                        <div id="scNOtpS2sStatus" style="display:none;margin:0.75rem 0;">
                                            <div id="scNOtpS2sTrue" style="display:none;padding:0.75rem 1rem;border-radius:8px;border-left:4px solid #10846D;background:rgba(16,132,109,0.06);">
                                                <strong style="color:#10846D;">&#10003; pureS2SSupported = true &mdash; Native OTP Supported</strong>
                                                <p style="margin:0.25rem 0 0;font-size:0.9rem;">This card supports <strong>Native OTP</strong>. You have <strong>two choices</strong> below to complete authentication. Pick whichever method you prefer.</p>
                                            </div>
                                            <div id="scNOtpS2sFalse" style="display:none;padding:0.75rem 1rem;border-radius:8px;border-left:4px solid #e53e3e;background:rgba(229,62,62,0.06);">
                                                <strong style="color:#e53e3e;">&#10007; pureS2SSupported = false &mdash; Native OTP NOT Supported</strong>
                                                <p style="margin:0.25rem 0 0;font-size:0.9rem;">This card/bank does <strong>not</strong> support native OTP. Only <strong>Pay on Bank Page (3DS Redirect)</strong> is available. The bank&rsquo;s 3DS page will load below.</p>
                                            </div>
                                        </div>

                                        <!-- Choose OTP method — button selectors -->
                                        <div id="scNOtpMethodSelector" style="display:none;margin-top:1rem;">
                                            <p style="margin:0 0 0.75rem;font-weight:600;font-size:1rem;color:#333;">Choose how to complete 3DS authentication:</p>
                                            <div style="display:flex;gap:1rem;flex-wrap:wrap;">
                                                <button id="scNOtpBtnA" class="sm-otp-method-btn" onclick="smSelectOtpMethod('scNOtp','A')" style="flex:1;min-width:220px;padding:1rem 1.25rem;border:2px solid #10846D;border-radius:10px;background:#fff;cursor:pointer;text-align:left;transition:all 0.2s;">
                                                    <span style="display:block;font-size:1.1rem;font-weight:700;color:#10846D;margin-bottom:0.3rem;">&#9312; Native OTP (Submit OTP API)</span>
                                                    <span style="display:block;font-size:0.85rem;color:#555;line-height:1.4;">Collect OTP on your own page &amp; submit server-to-server. Best UX &mdash; no redirects.<br><strong>Test OTP: 123456</strong></span>
                                                </button>
                                                <button id="scNOtpBtnB" class="sm-otp-method-btn" onclick="smSelectOtpMethod('scNOtp','B')" style="flex:1;min-width:220px;padding:1rem 1.25rem;border:2px solid #ff9800;border-radius:10px;background:#fff;cursor:pointer;text-align:left;transition:all 0.2s;">
                                                    <span style="display:block;font-size:1.1rem;font-weight:700;color:#ff9800;margin-bottom:0.3rem;">&#9313; Pay on Bank Page (3DS Redirect)</span>
                                                    <span style="display:block;font-size:0.85rem;color:#555;line-height:1.4;">Redirect to bank&rsquo;s 3DS page via decoded <code style="font-size:0.82rem;">acsTemplate</code>. Customer completes OTP on bank site.</span>
                                                </button>
                                    </div>
                                </div>

                                        <!-- Waiting state before payment response -->
                                        <div id="scNOtpWaiting" style="margin-top:1rem;">
                                            <div class="sm-info-box" style="padding:1rem;background:#f8f9fa;border:1px dashed #ccc;text-align:center;">
                                                <p style="margin:0;color:#666;font-size:0.95rem;">&#9203; Waiting for payment response&hellip; Send a card payment request in the previous step. The authentication options will appear here automatically.</p>
                                                </div>
                                                </div>

                                        <!-- Option A: Native OTP Form -->
                                        <div id="scNOtpNativeSection" style="display:none;margin-top:1rem;">
                                            <h4 style="color:#10846D;margin:0 0 0.75rem;">&#9312; Native OTP &mdash; Submit OTP API</h4>
                                            <div class="sm-info-box" style="border-left:4px solid #10846D;padding:0.75rem 1rem;background:rgba(16,132,109,0.04);margin-bottom:0.75rem;">
                                                <strong>How it works:</strong> Your server sends the customer&rsquo;s OTP to PayU via the <code>ResponseHandler.php</code> endpoint. The customer stays on your checkout page throughout &mdash; no redirects.
                                            </div>
                                            <div class="sm-api-badge">POST <code>https://test.payu.in/ResponseHandler.php</code> &nbsp;|&nbsp; Submit OTP</div>
                                            <table class="sm-table" style="margin-top:0.75rem;">
                                                <thead><tr><th>Parameter</th><th>Description</th><th>Value</th></tr></thead>
                                                <tbody>
                                                    <tr><td><code>referenceId</code></td><td>Unique reference from payment response &mdash; auto-filled from <code>metaData.referenceId</code></td><td><em>Auto-filled</em></td></tr>
                                                    <tr><td><code>otp</code></td><td>OTP entered by the customer on your page</td><td>Test: <code>123456</code></td></tr>
                                                    <tr><td><code>data</code></td><td>Must include <code>payuPureS2S</code> flag</td><td><code>{&quot;payuPureS2S&quot;:&quot;1&quot;}</code></td></tr>
                                                </tbody>
                                            </table>
                                            <div class="sm-interactive-form" style="margin-top:0.75rem;">
                                                <div class="sm-pay-section sm-pay-section-mandatory"><h4>Mandatory Parameters</h4>
                                                <div class="sm-form-row">
                                                    <div class="sm-form-group"><label>Reference ID <span class="required">*</span></label><input type="text" id="sc_otp_refid" placeholder="Auto-filled from payment response"><small class="sm-field-hint">From <code>metaData.referenceId</code> in the payment response</small></div>
                                                    <div class="sm-form-group"><label>OTP <span class="required">*</span></label><input type="text" id="sc_otp_value" value="123456"><small class="sm-field-hint">Test environment OTP: <code>123456</code></small></div>
                                            </div>
                                            </div>
                                            <div class="sm-form-actions">
                                                    <button class="button sm-btn-primary" onclick="smCardSubmitOtp('normal')">&#9658; Submit OTP</button>
                                                    <button class="button" onclick="smCardResendOtp('normal')">&#8635; Resend OTP</button>
                                            </div>
                                        </div>
                                            <div id="scNOtpReqRes" class="sm-req-res-panel" style="display:none;margin-top:1rem;">
                                            <div class="sm-res-panel">
                                                <div class="sm-panel-header"><span>Response Received</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div>
                                                    <div id="scNOtpStatusBadge" class="sm-status-badge"></div>
                                                    <pre><code id="scNOtpResponseView"></code></pre>
                                            </div>
                                        </div>
                                    </div>

                                        <!-- Option B: Bank Redirect / ACS -->
                                        <div id="scNOtpBankSection" style="display:none;margin-top:1rem;">
                                            <h4 style="color:#ff9800;margin:0 0 0.75rem;">&#9313; Pay on Bank Page &mdash; 3DS Redirect</h4>
                                            <div class="sm-info-box" style="border-left:4px solid #ff9800;padding:0.75rem 1rem;background:rgba(255,152,0,0.04);margin-bottom:0.75rem;">
                                                <strong>How it works:</strong> The payment response contains an <code>acsTemplate</code> (base64-encoded HTML). When decoded and rendered, it auto-submits a form that redirects the customer to the bank&rsquo;s 3DS page. After authentication, the bank redirects back to your <code>surl</code>/<code>furl</code>.
                                            </div>
                                            <div id="scNOtpAcsContainer" style="display:none;margin-top:0.75rem;">
                                                <div class="sm-info-box" style="border-left:4px solid #10846D;padding:0.75rem 1rem;background:rgba(16,132,109,0.04);margin-bottom:0.75rem;">
                                                    <strong style="color:#10846D;">&#10003; ACS Template Received</strong>
                                                    <p style="margin:0.25rem 0 0;font-size:0.9rem;">The bank&rsquo;s 3DS authentication page is ready. Click the button below to open it in a new tab. After completing OTP on the bank page, you will be redirected to the callback page.</p>
                                                </div>
                                                <div id="scNOtpAcsFrame" style="text-align:center;padding:1.5rem;background:#f8f9fa;border:2px dashed #ddd;border-radius:10px;"></div>
                                            </div>
                                            <div id="scNOtpAcsEmpty" style="margin-top:0.75rem;">
                                                <div class="sm-info-box" style="padding:1rem;background:#fff8e1;border:1px dashed #ff9800;">
                                                    <p style="margin:0;color:#666;">&#9888; No ACS template received yet. This will load automatically after you send the payment request in the previous step.</p>
                                                </div>
                                            </div>
                                            <div class="sm-info-box" style="margin-top:1rem;border-left:4px solid #10846D;padding:1rem 1.25rem;background:rgba(16,132,109,0.04);">
                                                <h4 style="color:#10846D;margin:0 0 0.5rem;">&#128274; ACS Template Decode Guide</h4>
                                                <p style="margin:0 0 0.75rem;font-size:0.9rem;">The <code>acsTemplate</code> is a <strong>Base64-encoded HTML string</strong>. Decode it to get the bank redirect form.</p>
                                                <details style="margin-top:0.5rem;">
                                                    <summary style="cursor:pointer;font-weight:600;color:#10846D;">&#9660; How to Decode Base64 acsTemplate</summary>
                                                    <pre style="margin:0.75rem 0;padding:1rem;background:#f0fdf4;border-radius:8px;font-size:0.82rem;overflow-x:auto;border:1px solid #d1fae5;"><code style="color:#065f46;">// JavaScript &ndash; Decode Base64 acsTemplate
const acsTemplate = response.result.acsTemplate;
const decodedHtml = atob(acsTemplate);

// Open decoded HTML in popup window
const bankWindow = window.open('', 'BankAuth', 'width=800,height=600');
bankWindow.document.write(decodedHtml);
bankWindow.document.close();</code></pre>
                                                    <p style="margin:0.75rem 0 0.25rem;font-weight:600;font-size:0.9rem;">Decoded HTML Structure:</p>
                                                    <pre style="margin:0;padding:1rem;background:#f0fdf4;border-radius:8px;font-size:0.82rem;overflow-x:auto;border:1px solid #d1fae5;"><code style="color:#065f46;">&lt;html&gt;&lt;body&gt;
&lt;form name="payment_post" action="https://pgsim01.payu.in/initiate" method="post"&gt;
  &lt;input type="hidden" name="merchantName" value="PAYU"&gt;
  &lt;input type="hidden" name="txnAmount" value="1.00"&gt;
  &lt;input type="hidden" name="txnRefId" value="MANDATE_xxx"&gt;
  &lt;input type="hidden" name="ibibo_code" value="ICICENCC"&gt;
  &lt;!-- ... more hidden fields ... --&gt;
&lt;/form&gt;
&lt;script&gt;
  window.onload = function() {
    document.forms['payment_post'].submit();  // Auto-submits to bank
  }
&lt;/script&gt;
&lt;/body&gt;&lt;/html&gt;</code></pre>
                                                </details>
                                            </div>
                                        </div>

                                        <div class="sm-info-box" style="border-left:4px solid #ff9800;padding:0.75rem 1rem;margin:1rem 0 0;background:rgba(255,152,0,0.06);">
                                            <strong style="color:#e65100;">&#9888; Troubleshooting OTP Errors</strong>
                                            <ul style="margin:0.5rem 0 0;padding-left:1.25rem;line-height:1.8;font-size:0.9rem;">
                                                <li><strong>E2502</strong> &ldquo;Payu unable to parse ACS page for native&rdquo; &mdash; PayU test environment issue. Retry or use a different test card.</li>
                                                <li><strong>E501</strong> &ldquo;Bank was unable to authenticate&rdquo; &mdash; the card may not support native OTP. Use the Bank Page option instead.</li>
                                                <li><strong>E802</strong> &ldquo;Issuing Bank was temporarily not available&rdquo; &mdash; transient bank simulator issue. Retry after a few moments.</li>
                                            </ul>
                                        </div>
                                    </div>
                                </div>
                            </div>
                            <div class="sm-next-btn-wrapper">
                                <button class="button sm-btn-secondary" onclick="smSwitchCardPhase(document.querySelector('#sm-cards-normal .sm-phase-tab:nth-child(3)'),'cards-normal','post')">Next: Verify Payment &rarr;</button>
                            </div>
                        </div>

                        <!-- POST-PAYMENT PHASE -->
                        <div class="sm-phase-content" id="cards-normal-post">
                            <div class="sm-step-guide">
                                <div class="sm-guide-overview">
                                    <h3>Post-Payment: Verify &amp; Reconcile</h3>
                                    <p>Verify via <code>verify_payment</code>, then reconcile status and validate callback integrity using reverse hash.</p>
                                </div>
                                <div class="sm-guide-prereqs">
                                    <h3>What you confirm here</h3>
                                    <div class="sm-prereq-list">
                                        <div class="sm-prereq-item">
                                            <span class="sm-prereq-icon">1</span>
                                            <div><strong>Final status</strong><br>Captured / Auth state</div>
                                        </div>
                                        <div class="sm-prereq-item">
                                            <span class="sm-prereq-icon">2</span>
                                            <div><strong>Reverse hash</strong><br>Verify callback payload</div>
                                        </div>
                                    </div>
                                </div>
                            </div>

                            <div class="sm-timeline">
                                <div class="sm-timeline-item" id="nav-n-verify">
                                    <div class="sm-timeline-marker">6</div>
                                    <div class="sm-timeline-content">
                                        <strong>Verify Payment API</strong>
                                        <p>Always verify the transaction server-side using <code>verify_payment</code> command. Do not rely solely on callback &mdash; network issues can cause missed callbacks. You can verify multiple transaction IDs in a single request by separating them with a pipe (<code>|</code>).</p>
                                        <div class="sm-api-badge">POST <code>https://test.payu.in/merchant/postservice.php?form=2</code></div>
                                        <div class="sm-api-badge">Content-Type: <code>application/x-www-form-urlencoded</code></div>
                                        <div class="sm-api-badge">Hash: <code>sha512(key|command|var1|salt)</code></div>
                                        <table class="sm-table" style="margin-top:0.75rem;">
                                            <thead><tr><th>Parameter</th><th>Required</th><th>Description</th><th>Example</th></tr></thead>
                                            <tbody>
                                                <tr><td><code>key</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Merchant key provided by PayU</td><td><code>JPg****f</code></td></tr>
                                                <tr><td><code>command</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td><code>verify_payment</code> &mdash; fixed value for this API</td><td><code>verify_payment</code></td></tr>
                                                <tr><td><code>var1</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Transaction ID(s) to verify. Multiple txnids can be separated by pipe (<code>|</code>), e.g. <code>TXN_001|TXN_002</code></td><td><code>TXN_001</code></td></tr>
                                                <tr><td><code>hash</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td><code>sha512(key|verify_payment|var1|salt)</code></td><td><em>(computed)</em></td></tr>
                                            </tbody>
                                        </table>
                                        <div class="sm-interactive-form" style="margin-top:1rem;">
                                            <div class="sm-pay-section sm-pay-section-mandatory"><h4>Mandatory Parameters</h4>
                                            <div class="sm-form-row">
                                                <div class="sm-form-group">
                                                    <label>Merchant Key <span class="required">*</span></label>
                                                    <input type="text" id="sc_verify_key" value="a4vGC2">
                                                </div>
                                                <div class="sm-form-group">
                                                    <label>Merchant Salt <span class="required">*</span></label>
                                                    <input type="password" id="sc_verify_salt" value="hKvGJP28d2ZUuCRz5BnDag58QBdCxBli">
                                                </div>
                                            </div>
                                            <div class="sm-form-row">
                                                <div class="sm-form-group">
                                                    <label>Transaction ID <span class="required">*</span></label>
                                                    <input type="text" id="sc_verify_txnid" placeholder="Same txnid used in payment">
                                                </div>
                                            </div>
                                            </div>
                                            <div class="sm-form-actions">
                                                <button class="button sm-btn-primary" onclick="smCardVerifyPayment('normal')">Verify Payment</button>
                                            </div>
                                        </div>
                                        <div id="scVerifyReqRes" class="sm-req-res-panel" style="display:none;margin-top:1rem;">
                                            <div id="scVerifyTxnStatus" style="display:none;margin-bottom:1rem;"></div>
                                            <div class="sm-res-panel">
                                                <div class="sm-panel-header"><span>Response Received</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div>
                                                <div id="scVerifyStatusBadge" class="sm-status-badge"></div>
                                                <pre><code id="scVerifyResponseView"></code></pre>
                                            </div>
                                        </div>
                                    </div>
                                </div>

                                <div class="sm-timeline-item">
                                    <div class="sm-timeline-marker">7</div>
                                    <div class="sm-timeline-content">
                                        <strong>Handle Callback &amp; Reverse Hash</strong>
                                        <p>PayU sends a POST callback to your <code>surl</code> (success) or <code>furl</code> (failure). Verify the response hash before updating your order status.</p>
                                        <div class="sm-code-block"><div class="sm-code-header"><span>Reverse Hash Formula</span></div>
                                            <pre><code>sha512(SALT|status||||||udf5|udf4|udf3|udf2|udf1|email|firstname|productinfo|amount|txnid|key)</code></pre>
                                        </div>
                                        <div class="sm-info-box warning" style="margin-top:1rem;">
                                            <strong>Security Best Practice</strong>
                                            <ul>
                                                <li>Always verify the reverse hash before trusting callback data</li>
                                                <li>Cross-check with <code>verify_payment</code> API for double confirmation</li>
                                                <li>Check <code>status</code>, <code>amount</code>, and <code>txnid</code> match your records</li>
                                            </ul>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>

                    <!-- ============================================ -->
                    <!-- PRE-AUTH CARD PAYMENT FLOW                   -->
                    <!-- ============================================ -->
                    <div class="seamless-section" id="sm-cards-preauth">
                        <h2>Pre-Auth Card Payment</h2>

                        <!-- Documentation Links -->
                        <div class="sm-doc-links" style="margin-bottom:1.5rem; padding:1rem; background:linear-gradient(135deg, #ecfdf5 0%, #d1fae5 100%); border:1px solid #34d399; border-radius:8px;">
                            <strong style="color:#065f46;">&#128213; Documentation</strong>
                            <div style="margin-top:0.5rem; display:flex; flex-wrap:wrap; gap:0.75rem;">
                                <a href="https://docs.payu.in/docs/pre-authorize-card-transactions" target="_blank" style="color:#047857; text-decoration:none; font-size:0.9rem;">&#128279; Pre-Authorize Card Transactions Guide</a>
                            </div>
                        </div>

                        <div class="sm-info-box">
                            <strong>Hold Funds &amp; Capture Later</strong>
                            <p>Pre-authorization holds funds on the customer's card without immediately capturing them. Ideal for hotels, car rentals, and e-commerce where the final amount may change. You capture the actual amount later.</p>
                            <p><strong>Prerequisite:</strong> You must be PCI DSS compliant (or use a PCI-compliant vault/tokenization solution) before handling raw card data in this seamless cards flow.</p>
                        </div>

                        <div style="margin-top:1rem;border:1px solid #e65100;border-radius:10px;overflow:hidden;background:#fff;">
                            <div style="padding:0.7rem 1.1rem;background:linear-gradient(135deg,#e65100,#ff8f00);display:flex;align-items:center;gap:0.6rem;">
                                <span style="font-size:1.3rem;">&#128197;</span>
                                <span style="font-size:1rem;font-weight:700;color:#fff;">Pre-Auth &mdash; 7-Day Authorization Window</span>
                            </div>
                            <div style="padding:1rem 1.25rem;">
                                <table style="width:100%;border-collapse:collapse;font-size:0.88rem;">
                                    <tbody>
                                        <tr style="border-bottom:1px solid #ffe0b2;">
                                            <td style="padding:0.5rem 0.5rem 0.5rem 0;font-weight:600;color:#e65100;width:160px;white-space:nowrap;vertical-align:top;">Authorization Hold</td>
                                            <td style="padding:0.5rem 0;color:#333;line-height:1.5;">Checks fund availability and <strong>holds</strong> the required amount on the payer&rsquo;s card for <strong>up to 7 days</strong>. Funds are not debited at this stage.</td>
                                        </tr>
                                        <tr style="border-bottom:1px solid #ffe0b2;">
                                            <td style="padding:0.5rem 0.5rem 0.5rem 0;font-weight:600;color:#e65100;vertical-align:top;">Capture</td>
                                            <td style="padding:0.5rem 0;color:#333;line-height:1.5;">A <code>capture_transaction</code> request debits the funds from the payer&rsquo;s card. You can capture the <strong>full amount</strong> or a <strong>partial amount</strong> (partial capture). After partial capture, the remaining balance is cancelled immediately.</td>
                                        </tr>
                                        <tr style="border-bottom:1px solid #ffe0b2;">
                                            <td style="padding:0.5rem 0.5rem 0.5rem 0;font-weight:600;color:#e65100;vertical-align:top;">Auto Capture</td>
                                            <td style="padding:0.5rem 0;color:#333;line-height:1.5;">PayU <strong>automatically captures</strong> the authorized amount on the <strong>7th day</strong> if no capture or cancel request is received. Merchants can opt for <strong>Auto Cancel</strong> or set a custom auto-capture window.</td>
                                        </tr>
                                        <tr style="border-bottom:1px solid #ffe0b2;">
                                            <td style="padding:0.5rem 0.5rem 0.5rem 0;font-weight:600;color:#e65100;vertical-align:top;">Cancel</td>
                                            <td style="padding:0.5rem 0;color:#333;line-height:1.5;">Cancel applies <strong>only to authorized (uncaptured)</strong> transactions. Once captured, the transaction can only be <strong>refunded</strong>, not cancelled.</td>
                                        </tr>
                                        <tr>
                                            <td style="padding:0.5rem 0.5rem 0.5rem 0;font-weight:600;color:#e65100;vertical-align:top;">Supported Cards</td>
                                            <td style="padding:0.5rem 0;color:#333;line-height:1.5;">Pre-auth is supported on <strong>Visa</strong>, <strong>Mastercard</strong>, and <strong>Amex Credit Cards</strong>.</td>
                                        </tr>
                                    </tbody>
                                </table>
                                <div style="margin-top:0.75rem;display:flex;flex-wrap:wrap;gap:0.5rem;">
                                    <span style="display:inline-block;padding:4px 12px;border-radius:20px;font-size:0.78rem;font-weight:600;background:#fff3e0;color:#e65100;border:1px solid #ffcc80;">&#9201; 7-day hold period</span>
                                    <span style="display:inline-block;padding:4px 12px;border-radius:20px;font-size:0.78rem;font-weight:600;background:#e8f5e9;color:#2e7d32;border:1px solid #a5d6a7;">&#10004; Full or partial capture</span>
                                    <span style="display:inline-block;padding:4px 12px;border-radius:20px;font-size:0.78rem;font-weight:600;background:#e3f2fd;color:#1565c0;border:1px solid #90caf9;">&#128260; Auto capture on Day 7</span>
                                    <span style="display:inline-block;padding:4px 12px;border-radius:20px;font-size:0.78rem;font-weight:600;background:#fce4ec;color:#c62828;border:1px solid #ef9a9a;">&#10008; No multiple partial captures</span>
                                </div>
                                <div style="margin-top:0.75rem;padding:0.5rem 0.75rem;background:#fff8e1;border-left:3px solid #ff8f00;border-radius:4px;font-size:0.82rem;color:#5d4037;line-height:1.5;">
                                    <strong>Note:</strong> PayU does not support multiple partial captures on a single authorization request. After a partial amount is captured, the remaining balance is cancelled immediately. If no action is taken within 7 days, PayU auto-captures the full authorized amount by default.
                                </div>
                            </div>
                        </div>

                        <div class="sm-step-guide" style="margin-top:1.25rem;">
                            <div class="sm-guide-overview">
                                <h3>Seamless Pre-Auth Lifecycle</h3>
                                <p>Phase 1: BIN + payment hash prep. Phase 2: <code>_payment</code> with <code>pre_authorize=1</code>. Phase 3: verify hold and capture (or cancel hold).</p>
                            </div>
                            <div class="sm-guide-prereqs">
                                <h3>Prerequisites</h3>
                                <div class="sm-prereq-list">
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">1</span>
                                        <div><strong>pre_authorize=1</strong><br>Holds funds (auth state)</div>
                                    </div>
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">2</span>
                                        <div><strong>capture_transaction</strong><br>Captures the final amount</div>
                                    </div>
                                    <div class="sm-prereq-item">
                                        <span class="sm-prereq-icon">3</span>
                                        <div><strong>cancel_transaction (optional)</strong><br>Cancel the hold if needed</div>
                                    </div>
                                </div>
                            </div>
                        </div>

                        <div class="sm-phase-tabs">
                            <button class="sm-phase-tab active" onclick="smSwitchCardPhase(this,'cards-preauth','pre')">
                                <span class="sm-phase-num">1</span> Pre-Payment
                            </button>
                            <button class="sm-phase-tab" onclick="smSwitchCardPhase(this,'cards-preauth','pay')">
                                <span class="sm-phase-num">2</span> Payment
                            </button>
                            <button class="sm-phase-tab" onclick="smSwitchCardPhase(this,'cards-preauth','post')">
                                <span class="sm-phase-num">3</span> Post-Payment
                            </button>
                        </div>

                        <!-- PRE-PAYMENT PHASE -->
                        <div class="sm-phase-content active" id="cards-preauth-pre">
                            <div class="sm-step-guide">
                                <div class="sm-guide-overview">
                                    <h3>Pre-Payment: Validate &amp; Prepare</h3>
                                    <p>Same as normal S2S: generate the correct payment hash first. The <code>pre_authorize=1</code> flag is included only in the payment request.</p>
                                </div>
                                <div class="sm-guide-prereqs">
                                    <h3>Key steps</h3>
                                    <div class="sm-prereq-list">
                                        <div class="sm-prereq-item">
                                            <span class="sm-prereq-icon">1</span>
                                            <div><strong>getBinInfo</strong><br>BIN capabilities</div>
                                        </div>
                                        <div class="sm-prereq-item">
                                            <span class="sm-prereq-icon">2</span>
                                            <div><strong>Payment hash</strong><br>SHA-512 hash for _payment</div>
                                        </div>
                                    </div>
                                </div>
                            </div>

                            <div class="sm-timeline">
                                <div class="sm-timeline-item" id="nav-pa-bininfo">
                                    <div class="sm-timeline-marker">1</div>
                                    <div class="sm-timeline-content">
                                        <strong>Get BIN Info API</strong>
                                        <p>Retrieve card BIN details before initiating a pre-authorized payment &mdash; issuing bank, card type, network, and capabilities (ATM PIN, OTP, Zero Redirect, SI). Supports single BIN lookup, feature-based filtering, and bulk retrieval.</p>
                                        <div class="sm-api-badge">POST <code>https://test.payu.in/merchant/postservice.php?form=2</code> &nbsp;|&nbsp; Command: <code>getBinInfo</code></div>
                                        <div class="sm-api-badge">Hash: <code>sha512(key|command|var1|salt)</code></div>
                                        <table class="sm-table" style="margin-top:0.75rem;">
                                            <thead><tr><th>Parameter</th><th>Required</th><th>Description</th><th>Example</th></tr></thead>
                                            <tbody>
                                                <tr><td><code>key</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Merchant key provided by PayU</td><td><code>JPg****f</code></td></tr>
                                                <tr><td><code>command</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td><code>getBinInfo</code></td><td><code>getBinInfo</code></td></tr>
                                                <tr><td><code>var1</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Request type: <code>1</code> = single BIN, <code>2</code> = feature-based list, <code>3</code> = all BINs</td><td><code>1</code></td></tr>
                                                <tr><td><code>var2</code></td><td><span class="sm-badge-conditional">Conditional</span></td><td>If var1=1: BIN number. If var1=2: <code>1</code> (ATM PIN) or <code>2</code> (OTP). If var1=3: leave empty.</td><td><code>512345</code></td></tr>
                                                <tr><td><code>var3</code></td><td><span class="sm-badge-optional">Optional</span></td><td>Start index for pagination (default: <code>0</code>)</td><td><code>0</code></td></tr>
                                                <tr><td><code>var4</code></td><td><span class="sm-badge-optional">Optional</span></td><td>Records per page (default: <code>100</code>, range: 1&ndash;1000)</td><td><code>100</code></td></tr>
                                                <tr><td><code>var5</code></td><td><span class="sm-badge-optional">Optional</span></td><td>Set to <code>1</code> for enhanced features (zero redirect, SI support)</td><td><code>1</code></td></tr>
                                                <tr><td><code>hash</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td><code>sha512(key|getBinInfo|var1|salt)</code></td><td><em>(computed)</em></td></tr>
                                            </tbody>
                                        </table>
                                        <div class="sm-info-box" style="margin-top:1rem;">
                                            <strong>BIN API Use Cases</strong>
                                            <table class="sm-table" style="margin-top:0.5rem;font-size:0.85rem;">
                                                <thead><tr><th>Use Case</th><th>var1</th><th>var2</th><th>var3</th><th>var4</th><th>var5</th><th>Description</th></tr></thead>
                                                <tbody>
                                                    <tr><td>Single BIN Query</td><td>1</td><td>512345</td><td>0</td><td>0</td><td>0</td><td>Get info for a specific BIN</td></tr>
                                                    <tr><td>Single BIN + Enhanced</td><td>1</td><td>512345</td><td>0</td><td>0</td><td>1</td><td>Single BIN with zero redirect &amp; SI support</td></tr>
                                                    <tr><td>ATM PIN Support Cards</td><td>2</td><td>1</td><td>1</td><td>20</td><td>0</td><td>Get BINs with ATM PIN support</td></tr>
                                                    <tr><td>OTP Support Cards</td><td>2</td><td>2</td><td>1</td><td>20</td><td>0</td><td>Get BINs with OTP-on-the-fly support</td></tr>
                                                    <tr><td>All Cards &ndash; Page 1</td><td>3</td><td>&nbsp;</td><td>1</td><td>20</td><td>0</td><td>First 20 cards (records 1&ndash;20)</td></tr>
                                                    <tr><td>All Cards &ndash; Page 2</td><td>3</td><td>&nbsp;</td><td>21</td><td>20</td><td>0</td><td>Next 20 cards (records 21&ndash;40)</td></tr>
                                                    <tr><td>Large Batch Query</td><td>3</td><td>&nbsp;</td><td>1</td><td>100</td><td>0</td><td>Get 100 cards at once</td></tr>
                                                    <tr><td>Custom Range</td><td>3</td><td>&nbsp;</td><td>501</td><td>50</td><td>0</td><td>Cards 501&ndash;550</td></tr>
                                                </tbody>
                                            </table>
                                        </div>
                                        <div class="sm-interactive-form" style="margin-top:1rem;">
                                            <div class="sm-pay-section sm-pay-section-mandatory">
                                                <h4>Mandatory Parameters</h4>
                                                <div class="sm-form-row">
                                                    <div class="sm-form-group">
                                                        <label>Merchant Key <span class="required">*</span></label>
                                                        <input type="text" id="sc_pa_bin_key" value="a4vGC2">
                                                    </div>
                                                    <div class="sm-form-group">
                                                        <label>Merchant Salt <span class="required">*</span></label>
                                                        <input type="password" id="sc_pa_bin_salt" value="hKvGJP28d2ZUuCRz5BnDag58QBdCxBli">
                                                    </div>
                                                </div>
                                                <div class="sm-form-row">
                                                    <div class="sm-form-group">
                                                        <label>var1 &ndash; Request Type <span class="required">*</span></label>
                                                        <input type="text" id="sc_pa_bin_var1" value="1">
                                                        <small class="sm-field-hint">1 = Single BIN lookup</small>
                                                    </div>
                                                    <div class="sm-form-group" id="sc_pa_bin_var2_group">
                                                        <label>var2 &ndash; BIN / Feature Code</label>
                                                        <input type="text" id="sc_pa_bin_value" value="550690" maxlength="9" placeholder="e.g. 550690">
                                                        <small class="sm-field-hint" id="sc_pa_bin_var2_hint">BIN number (first 6&ndash;9 digits) for single lookup</small>
                                                    </div>
                                                </div>
                                                <div class="sm-form-row">
                                                    <div class="sm-form-group">
                                                        <label>var3 &ndash; Start Index</label>
                                                        <input type="text" id="sc_pa_bin_var3" value="0" placeholder="0">
                                                        <small class="sm-field-hint">Pagination start index (default: 0)</small>
                                                    </div>
                                                    <div class="sm-form-group">
                                                        <label>var4 &ndash; Records Per Page</label>
                                                        <input type="text" id="sc_pa_bin_var4" value="0" placeholder="100">
                                                        <small class="sm-field-hint">Number of records (1&ndash;1000, default: 100)</small>
                                                    </div>
                                                </div>
                                                <div class="sm-form-row">
                                                    <div class="sm-form-group">
                                                        <label>var5 &ndash; Enhanced Features</label>
                                                        <select id="sc_pa_bin_var5">
                                                            <option value="0">0 &ndash; Standard response</option>
                                                            <option value="1" selected>1 &ndash; Include zero redirect &amp; SI support</option>
                                                        </select>
                                                        <small class="sm-field-hint">Set to 1 for additional fields</small>
                                                    </div>
                                                </div>
                                            </div>
                                            <div class="sm-form-actions">
                                                <button class="button" onclick="smCardGetBinInfoPreAuthPreview()">Preview Request</button>
                                                <button class="button sm-btn-primary" onclick="smCardGetBinInfoPreAuth()">Send getBinInfo</button>
                                            </div>
                                        </div>
                                        <div id="scPaBinReqRes" class="sm-req-res-panel" style="display:none;margin-top:1rem;">
                                            <div class="sm-req-res-grid">
                                                <div class="sm-req-panel">
                                                    <div class="sm-panel-header"><span>Request Sent</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div>
                                                    <pre><code id="scPaBinRequestView"></code></pre>
                                                </div>
                                            <div class="sm-res-panel">
                                                <div class="sm-panel-header"><span>Response Received</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div>
                                                <div id="scPaBinStatusBadge" class="sm-status-badge"></div>
                                                <pre><code id="scPaBinResponseView"></code></pre>
                                            </div>
                                        </div>
                                            <div class="sm-curl-section">
                                                <div class="sm-panel-header"><span>cURL Command</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div>
                                                <pre><code id="scPaBinCurlView"></code></pre>
                                    </div>
                                </div>
                                        <div id="scPaBinSummary" style="display:none;margin-top:1rem;padding:1rem 1.25rem;background:#fff;border:1px solid #e0e0e0;border-radius:10px;box-shadow:0 2px 8px rgba(0,0,0,0.04);"></div>
                                        <div class="sm-info-box" style="margin-top:1rem;border-left:4px solid #e65100;padding:1rem 1.25rem;background:rgba(230,81,0,0.03);">
                                            <h4 style="color:#e65100;margin:0 0 0.75rem;">Response Parameters &mdash; Use in Pre-Auth Payment</h4>
                                            <table class="sm-table" style="font-size:0.85rem;">
                                                <thead><tr><th>Parameter</th><th>Values</th><th>Use Case in Pre-Auth Flow</th></tr></thead>
                                                <tbody>
                                                    <tr><td><code>issuing_bank</code></td><td>e.g. <code>HDFC</code>, <code>ICICI</code></td><td>Identify the issuing bank. Some banks may have pre-auth limits or restrictions</td></tr>
                                                    <tr><td><code>bin</code></td><td>BIN number</td><td>The matched BIN (6&ndash;9 digits). Confirms the BIN PayU resolved for this card</td></tr>
                                                    <tr><td><code>category</code></td><td><code>creditcard</code> / <code>debitcard</code></td><td><strong>Important:</strong> Pre-auth is primarily supported on <strong>credit cards</strong>. Some debit cards may not support pre-auth &mdash; check before proceeding</td></tr>
                                                    <tr><td><code>card_type</code></td><td><code>VISA</code>, <code>MAST</code>, <code>AMEX</code>, <code>MAES</code>, <code>DINR</code></td><td>Determine card network. Pre-auth support varies by network. Set <code>bankcode</code> as <code>CC</code> for pre-auth payment</td></tr>
                                                    <tr><td><code>is_domestic</code></td><td><code>1</code> = Domestic, <code>0</code> = International</td><td>Domestic cards can use S2S Native OTP for pre-auth. International cards redirect to 3DS for authentication</td></tr>
                                                    <tr style="background:rgba(16,132,109,0.06);"><td><code>is_otp_on_the_fly</code></td><td><code>1</code> = Supported, <code>0</code> = Not</td><td><strong>Critical:</strong> If <code>1</code>, card supports <strong>Native OTP</strong> for pre-auth. You can authenticate via <code>submit_otp</code> API in Step 4 instead of bank page redirect. If <code>0</code>, only 3DS Redirect works</td></tr>
                                                    <tr><td><code>is_atmpin_card</code></td><td><code>1</code> / <code>0</code></td><td>If <code>1</code>, card supports ATM PIN based authentication</td></tr>
                                                    <tr><td><code>is_zero_redirect_supported</code></td><td><code>1</code> / <code>0</code></td><td>If <code>1</code>, zero redirect flow is possible for pre-auth. Returned only when <code>var5=1</code></td></tr>
                                                    <tr><td><code>is_si_supported</code></td><td><code>1</code> / <code>0</code></td><td>If <code>1</code>, card supports Standing Instructions &mdash; useful for recurring pre-auth scenarios. Returned only when <code>var5=1</code></td></tr>
                                                </tbody>
                                            </table>
                                        </div>
                                    </div>
                                </div>

                            </div>
                            <div class="sm-next-btn-wrapper">
                                <button class="button sm-btn-secondary" onclick="smSwitchCardPhase(document.querySelector('#sm-cards-preauth .sm-phase-tab:nth-child(2)'),'cards-preauth','pay')">Next: Initiate Pre-Auth Payment &rarr;</button>
                            </div>
                        </div>

                        <!-- PAYMENT PHASE -->
                        <div class="sm-phase-content" id="cards-preauth-pay">
                            <div class="sm-step-guide">
                                <div class="sm-guide-overview">
                                    <h3>Payment: Submit Pre-Authorization</h3>
                                    <p>Call <code>_payment</code> with <code>pre_authorize=1</code> to hold funds. Final debit happens later when you capture.</p>
                                </div>
                                <div class="sm-guide-prereqs">
                                    <h3>Expected result</h3>
                                    <div class="sm-prereq-list">
                                        <div class="sm-prereq-item">
                                            <span class="sm-prereq-icon">✓</span>
                                            <div><strong>Hold state</strong><br>Auth (not captured yet)</div>
                                        </div>
                                    </div>
                                </div>
                            </div>

                            <div class="sm-timeline">
                                <div class="sm-timeline-item" id="nav-pa-hash">
                                    <div class="sm-timeline-marker">2</div>
                                    <div class="sm-timeline-content">
                                        <strong>Generate Payment Hash</strong>
                                        <p>Before calling <code>_payment</code> with <code>pre_authorize=1</code>, you must generate a <strong>SHA-512 hash</strong>. This hash ensures that no one has tampered with the payment request parameters. The hash formula is <strong>identical</strong> to a normal payment.</p>
                                        <div style="margin-top:0.75rem;border:1px solid #e65100;border-radius:10px;overflow:hidden;">
                                            <div style="padding:0.6rem 1rem;background:#fff3e0;border-bottom:1px solid #ffe0b2;">
                                                <strong style="color:#e65100;">Hash Formula for Pre-Auth <code>_payment</code> API</strong>
                                            </div>
                                            <div style="padding:0.85rem 1rem;">
                                                <code style="display:block;background:#f5f5f5;padding:0.75rem;border-radius:6px;font-size:0.9rem;word-break:break-all;border:1px solid #e0e0e0;">sha512(key|txnid|amount|productinfo|firstname|email|udf1|udf2|udf3|udf4|udf5||||||salt)</code>
                                                <table style="width:100%;border-collapse:collapse;font-size:0.85rem;margin-top:0.75rem;">
                                                    <thead><tr style="background:#f5f5f5;"><th style="padding:0.4rem 0.5rem;text-align:left;border-bottom:1px solid #e0e0e0;">Field</th><th style="padding:0.4rem 0.5rem;text-align:left;border-bottom:1px solid #e0e0e0;">Description</th><th style="padding:0.4rem 0.5rem;text-align:left;border-bottom:1px solid #e0e0e0;">Example</th></tr></thead>
                                                    <tbody>
                                                        <tr style="border-bottom:1px solid #f0f0f0;"><td style="padding:0.35rem 0.5rem;"><code>key</code></td><td style="padding:0.35rem 0.5rem;">Merchant Key provided by PayU</td><td style="padding:0.35rem 0.5rem;font-family:monospace;">a4vGC2</td></tr>
                                                        <tr style="border-bottom:1px solid #f0f0f0;"><td style="padding:0.35rem 0.5rem;"><code>txnid</code></td><td style="padding:0.35rem 0.5rem;">Your unique transaction ID</td><td style="padding:0.35rem 0.5rem;font-family:monospace;">TXN_1234567890</td></tr>
                                                        <tr style="border-bottom:1px solid #f0f0f0;"><td style="padding:0.35rem 0.5rem;"><code>amount</code></td><td style="padding:0.35rem 0.5rem;">Pre-auth hold amount</td><td style="padding:0.35rem 0.5rem;font-family:monospace;">10.00</td></tr>
                                                        <tr style="border-bottom:1px solid #f0f0f0;"><td style="padding:0.35rem 0.5rem;"><code>productinfo</code></td><td style="padding:0.35rem 0.5rem;">Product description</td><td style="padding:0.35rem 0.5rem;font-family:monospace;">Test Product</td></tr>
                                                        <tr style="border-bottom:1px solid #f0f0f0;"><td style="padding:0.35rem 0.5rem;"><code>firstname</code></td><td style="padding:0.35rem 0.5rem;">Customer first name</td><td style="padding:0.35rem 0.5rem;font-family:monospace;">Test</td></tr>
                                                        <tr style="border-bottom:1px solid #f0f0f0;"><td style="padding:0.35rem 0.5rem;"><code>email</code></td><td style="padding:0.35rem 0.5rem;">Customer email</td><td style="padding:0.35rem 0.5rem;font-family:monospace;">test@example.com</td></tr>
                                                        <tr style="border-bottom:1px solid #f0f0f0;"><td style="padding:0.35rem 0.5rem;"><code>udf1&ndash;udf5</code></td><td style="padding:0.35rem 0.5rem;">User-defined fields &mdash; pass empty string if not used</td><td style="padding:0.35rem 0.5rem;font-family:monospace;">(empty)</td></tr>
                                                        <tr style="border-bottom:1px solid #f0f0f0;"><td style="padding:0.35rem 0.5rem;"><code>||||||</code></td><td style="padding:0.35rem 0.5rem;">Six pipes for empty udf6&ndash;udf10 (always required)</td><td style="padding:0.35rem 0.5rem;font-family:monospace;">||||||</td></tr>
                                                        <tr><td style="padding:0.35rem 0.5rem;"><code>salt</code></td><td style="padding:0.35rem 0.5rem;">Merchant Salt &mdash; <strong>never expose to client</strong></td><td style="padding:0.35rem 0.5rem;font-family:monospace;">hKvGJP28d2...</td></tr>
                                                    </tbody>
                                                </table>
                                                <div style="margin-top:0.75rem;padding:0.5rem 0.75rem;background:#fce4ec;border-left:3px solid #c62828;border-radius:4px;font-size:0.82rem;color:#b71c1c;line-height:1.5;">
                                                    <strong>&#9888; Security Rules:</strong>
                                                    <ul style="margin:0.25rem 0 0 1rem;padding:0;">
                                                        <li>Hash <strong>MUST</strong> be generated <strong>server-side</strong> &mdash; never expose your Salt on the client/browser</li>
                                                        <li>Empty UDF fields must remain as empty strings (not omitted) in the hash string</li>
                                                        <li>The <code>||||||</code> (six pipes) between <code>udf5</code> and <code>salt</code> are for empty udf6&ndash;udf10 and are <strong>always required</strong></li>
                                                    </ul>
                                                </div>
                                                <div style="margin-top:0.5rem;padding:0.5rem 0.75rem;background:#e3f2fd;border-left:3px solid #1976d2;border-radius:4px;font-size:0.82rem;color:#0d47a1;line-height:1.5;">
                                                    <strong>Not included in hash:</strong> <code>pre_authorize</code>, <code>ccnum</code>, <code>ccvv</code>, <code>ccexpmon</code>, <code>ccexpyr</code>, <code>pg</code>, <code>bankcode</code>, <code>surl</code>, <code>furl</code>, <code>txn_s2s_flow</code> &mdash; these are sent as separate parameters. The <code>pre_authorize=1</code> flag does <strong>not</strong> change the hash formula.
                                                </div>
                                                <div style="margin-top:0.5rem;padding:0.5rem 0.75rem;background:#fff8e1;border-left:3px solid #ff8f00;border-radius:4px;font-size:0.82rem;color:#5d4037;line-height:1.5;">
                                                    <strong>In this Integration Lab:</strong> The hash is auto-computed client-side for testing convenience. <strong>In production, always compute the hash on your server.</strong>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </div>

                                <div class="sm-timeline-item" id="nav-pa-payment">
                                    <div class="sm-timeline-marker">3</div>
                                    <div class="sm-timeline-content">
                                        <strong>Pre-Auth Payment API (<code>_payment</code> with <code>pre_authorize=1</code>)</strong>
                                        <p>Submit a pre-authorization request to hold funds on the customer&rsquo;s card without debiting. The <code>pre_authorize=1</code> parameter is the only difference from a normal card payment.</p>
                                        <div class="sm-api-badge">POST <code>https://test.payu.in/_payment</code></div>
                                        <div class="sm-api-badge">Content-Type: <code>application/x-www-form-urlencoded</code></div>
                                        <table class="sm-table" style="margin-top:0.75rem;">
                                            <thead><tr><th>Parameter</th><th>Required</th><th>Description</th><th>Example</th></tr></thead>
                                            <tbody>
                                                <tr><td><code>key</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Merchant key provided by PayU during onboarding</td><td><code>JPg****f</code></td></tr>
                                                <tr><td><code>txnid</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Unique transaction ID generated by the merchant. PayU rejects duplicate txnids.</td><td><code>ypl938459435</code></td></tr>
                                                <tr><td><code>amount</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Payment amount to hold on the card</td><td><code>18000</code></td></tr>
                                                <tr><td><code>productinfo</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Brief description of the product</td><td><code>iPhone</code></td></tr>
                                                <tr><td><code>firstname</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Customer first name</td><td><code>Ashish</code></td></tr>
                                                <tr><td><code>email</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Customer email address</td><td><code>test@gmail.com</code></td></tr>
                                                <tr><td><code>phone</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Customer phone number</td><td><code>9876543210</code></td></tr>
                                                <tr><td><code>pg</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td><code>CC</code> for Credit Card</td><td><code>CC</code></td></tr>
                                                <tr><td><code>bankcode</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Bank code for the card (e.g. <code>CC</code>, <code>AMEX</code>)</td><td><code>CC</code></td></tr>
                                                <tr><td><code>ccnum</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>13&ndash;19 digit card number (15 for AMEX). Validated with LUHN algorithm.</td><td><code>5123456789012346</code></td></tr>
                                                <tr><td><code>ccname</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Name on card as entered by the customer</td><td><code>Test User</code></td></tr>
                                                <tr><td><code>ccvv</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>3-digit CVV (4-digit CID for AMEX)</td><td><code>123</code></td></tr>
                                                <tr><td><code>ccexpmon</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Card expiry month in MM format (e.g. <code>01</code>, <code>12</code>)</td><td><code>05</code></td></tr>
                                                <tr><td><code>ccexpyr</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Card expiry year in YYYY format (e.g. <code>2030</code>)</td><td><code>2030</code></td></tr>
                                                <tr><td><code>surl</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Success URL &mdash; PayU redirects here on successful authorization</td><td>https://test.payu.in/admin/test_response</td></tr>
                                                <tr><td><code>furl</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Failure URL &mdash; PayU redirects here on failed authorization</td><td>https://test.payu.in/admin/test_response</td></tr>
                                                <tr><td><code>pre_authorize</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Must be <code>1</code> for pre-authorization. This holds funds without debiting.</td><td><code>1</code></td></tr>
                                                <tr><td><code>hash</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>SHA-512 hash (see Generate Payment Hash step above). <code>pre_authorize</code> is NOT included in hash.</td><td><em>(computed)</em></td></tr>
                                                <tr><td><code>txn_s2s_flow</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Must be <code>4</code> for Cards Decoupled (S2S) flow</td><td><code>4</code></td></tr>
                                                <tr><td><code>s2s_client_ip</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>The source IP of the customer</td><td><code>10.200.12.12</code></td></tr>
                                                <tr><td><code>s2s_device_info</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>The customer agent&rsquo;s device information (User-Agent string)</td><td>Mozilla/5.0 (Windows NT 10.0; Win64; x64)</td></tr>
                                                <tr><td><code>address1</code></td><td><span class="sm-badge-optional">Optional</span></td><td>Billing address line 1 (recommended for fraud detection)</td><td>123 Main Street</td></tr>
                                                <tr><td><code>address2</code></td><td><span class="sm-badge-optional">Optional</span></td><td>Billing address line 2</td><td>Suite 100</td></tr>
                                                <tr><td><code>city</code></td><td><span class="sm-badge-optional">Optional</span></td><td>Customer city</td><td>Mumbai</td></tr>
                                                <tr><td><code>state</code></td><td><span class="sm-badge-optional">Optional</span></td><td>Customer state</td><td>Maharashtra</td></tr>
                                                <tr><td><code>country</code></td><td><span class="sm-badge-optional">Optional</span></td><td>Customer country</td><td>India</td></tr>
                                                <tr><td><code>zipcode</code></td><td><span class="sm-badge-optional">Optional</span></td><td>Billing zip code</td><td><code>400004</code></td></tr>
                                                <tr><td><code>udf1</code>&ndash;<code>udf5</code></td><td><span class="sm-badge-optional">Optional</span></td><td>User-defined fields to store additional info per transaction</td><td>&mdash;</td></tr>
                                            </tbody>
                                        </table>
                                        <div class="sm-interactive-form" style="margin-top:1rem;">
