                                                <button class="button sm-btn-secondary" onclick="smCardPreviewPayment('preauth')">Preview Request</button>
                                                <button class="button sm-btn-primary" onclick="smCardSendPayment('preauth')">Send Pre-Auth to PayU</button>
                                            </div>
