                        <!-- Original Content (shown initially) -->
                        <div id="smNbOtpOriginalContent">

                            <!-- API Reference -->
                            <h3>API Reference</h3>
                            <div class="sm-info-box" style="margin-bottom:1rem; background:#f0fff4; border:1px solid #9ae6b4;">
                                <strong>Endpoint:</strong> <code>POST https://test.payu.in/_payment</code> (Test) | <code>POST https://secure.payu.in/_payment</code> (Production)
                            </div>

                            <h4 style="margin-top:1rem;">Request Parameters</h4>
                            <table class="sm-table">
                                <thead><tr><th>Parameter</th><th>Required</th><th>Description</th><th>Example</th></tr></thead>
                                <tbody>
                                    <tr><td><code>key</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Merchant key provided by PayU during onboarding</td><td>a4vGC2</td></tr>
                                    <tr><td><code>salt</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Merchant salt for hash generation (never sent in request)</td><td>hKvGJP28d2...</td></tr>
                                    <tr><td><code>txnid</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Unique transaction ID (max 25 chars)</td><td>NB_1234567890</td></tr>
                                    <tr><td><code>amount</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Transaction amount in INR</td><td>100.00</td></tr>
                                    <tr><td><code>productinfo</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Product/service description</td><td>Test Product</td></tr>
                                    <tr><td><code>firstname</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Customer&rsquo;s first name</td><td>John</td></tr>
                                    <tr><td><code>email</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Customer&rsquo;s email address</td><td>john@example.com</td></tr>
                                    <tr><td><code>phone</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Customer&rsquo;s phone number</td><td>9876543210</td></tr>
                                    <tr><td><code>surl</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Success callback URL</td><td>https://yoursite.com/success</td></tr>
                                    <tr><td><code>furl</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Failure callback URL</td><td>https://yoursite.com/failure</td></tr>
                                    <tr><td><code>hash</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; SHA-512 payment hash (auto-computed)</td><td><em>(computed)</em></td></tr>
                                    <tr><td><code>pg</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Payment gateway type &mdash; fixed <code>NB</code></td><td>NB</td></tr>
                                    <tr><td><code>bankcode</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Bank code from getNetbankingStatus API</td><td>TESTPGNB</td></tr>
                                    <tr><td><code>txn_s2s_flow</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; S2S flow identifier &mdash; fixed <code>4</code></td><td>4</td></tr>
                                    <tr><td><code>s2s_client_ip</code></td><td><span class="sm-badge-conditional">Conditional</span></td><td>String &mdash; Source IP of the customer (required for S2S)</td><td>10.200.12.12</td></tr>
                                    <tr><td><code>s2s_device_info</code></td><td><span class="sm-badge-conditional">Conditional</span></td><td>String &mdash; Customer agent&rsquo;s device information</td><td>Mozilla/5.0</td></tr>
                                    <tr><td><code>udf1</code></td><td><span class="sm-badge-optional">Optional</span></td><td>String &mdash; User-defined field 1</td><td></td></tr>
                                    <tr><td><code>udf2</code></td><td><span class="sm-badge-optional">Optional</span></td><td>String &mdash; User-defined field 2</td><td></td></tr>
                                    <tr><td><code>udf3</code></td><td><span class="sm-badge-optional">Optional</span></td><td>String &mdash; User-defined field 3</td><td></td></tr>
                                    <tr><td><code>udf4</code></td><td><span class="sm-badge-optional">Optional</span></td><td>String &mdash; User-defined field 4</td><td></td></tr>
                                    <tr><td><code>udf5</code></td><td><span class="sm-badge-optional">Optional</span></td><td>String &mdash; User-defined field 5</td><td></td></tr>
                                </tbody>
                            </table>

                            <h4 style="margin-top:1.5rem;">Response Parameters</h4>
                            <table class="sm-table">
                                <thead><tr><th>Parameter</th><th>Description</th><th>Example</th></tr></thead>
                                <tbody>
                                    <tr><td><code>metaData.txnId</code></td><td>String &mdash; Your original transaction ID</td><td>NB_1234567890</td></tr>
                                    <tr><td><code>metaData.txnStatus</code></td><td>String &mdash; Transaction status &mdash; <code>pending</code> means awaiting bank auth</td><td>pending</td></tr>
                                    <tr><td><code>metaData.unmappedStatus</code></td><td>String &mdash; Raw status from payment gateway</td><td>pending</td></tr>
                                    <tr><td><code>metaData.referenceId</code></td><td>String &mdash; PayU internal reference for this transaction</td><td>abc123...</td></tr>
                                    <tr><td><code>result.acsTemplate</code></td><td>String &mdash; <strong>Base64-encoded HTML</strong> containing auto-submit form to redirect customer to bank</td><td>PGh0bWw+Li4u...</td></tr>
                                    <tr><td><code>result.otpPostUrl</code></td><td>String &mdash; PayU response handler URL (used internally by bank redirect)</td><td>https://test.payu.in/ResponseHandler.php</td></tr>
                                </tbody>
                            </table>

                            <h4 style="margin-top:1.5rem;">Callback Parameters (POST to surl/furl)</h4>
                            <table class="sm-table">
                                <thead><tr><th>Parameter</th><th>Description</th><th>Example</th></tr></thead>
                                <tbody>
                                    <tr><td><code>status</code></td><td>Transaction status &mdash; <code>success</code> or <code>failure</code></td><td>success</td></tr>
                                    <tr><td><code>mihpayid</code></td><td>PayU&rsquo;s unique transaction reference ID</td><td>10731087875</td></tr>
                                    <tr><td><code>mode</code></td><td>Payment mode &mdash; <code>NB</code> for Net Banking</td><td>NB</td></tr>
                                    <tr><td><code>txnid</code></td><td>Your original transaction ID</td><td>NB_1234567890</td></tr>
                                    <tr><td><code>amount</code></td><td>Transaction amount</td><td>100.00</td></tr>
                                    <tr><td><code>bankcode</code></td><td>Bank code used for the payment</td><td>TESTPGNB</td></tr>
                                    <tr><td><code>bank_ref_num</code></td><td>Bank reference number</td><td>YESB00000...</td></tr>
                                    <tr><td><code>unmappedstatus</code></td><td>Detailed status &mdash; <code>captured</code> for successful payment</td><td>captured</td></tr>
                                    <tr><td><code>field9</code></td><td>Payment gateway response message</td><td>Transaction Completed Successfully</td></tr>
                                </tbody>
                            </table>

                            <div class="sm-step-guide">
                                <div class="sm-guide-overview">
                                    <h3>Overview</h3>
                                    <p>After calling the <code>_payment</code> API, you receive an <code>acsTemplate</code> (base64-encoded HTML). Decode and render this to redirect the customer to their bank's login page for authentication.</p>
                                </div>
                            </div>

                            <h4>Response Handling Flow</h4>
                            <div class="sm-flow-diagram" style="margin:1.5rem 0;">
                                <div class="sm-flow-step"><span class="sm-flow-num">1</span><span class="sm-flow-label">Receive acsTemplate</span></div>
                                <div class="sm-flow-arrow">&rarr;</div>
                                <div class="sm-flow-step"><span class="sm-flow-num">2</span><span class="sm-flow-label">Base64 Decode</span></div>
                                <div class="sm-flow-arrow">&rarr;</div>
                                <div class="sm-flow-step"><span class="sm-flow-num">3</span><span class="sm-flow-label">Render HTML</span></div>
                                <div class="sm-flow-arrow">&rarr;</div>
                                <div class="sm-flow-step"><span class="sm-flow-num">4</span><span class="sm-flow-label">Customer Auth at Bank</span></div>
                            </div>

                            <h4>Code Example: Decode &amp; Redirect</h4>
                            <div class="sm-code-block">
                                <div class="sm-code-header"><span>JavaScript - Open Bank Page</span><button onclick="smCopyCode(this)">Copy</button></div>
                                <pre><code>// After receiving _payment API response
const response = await payuApiResponse;

if (response.result && response.result.acsTemplate) {
    // Decode base64 acsTemplate
    const html = atob(response.result.acsTemplate);
    
    // Option 1: Open in new window
    const win = window.open('', '_blank');
    win.document.write(html);
    win.document.close();
    
    // Option 2: Redirect in same window
    // document.open();
    // document.write(html);
    // document.close();
}</code></pre>
                            </div>

                            <div class="sm-code-block" style="margin-top:1rem;">
                                <div class="sm-code-header"><span>PHP - Server-side Redirect</span><button onclick="smCopyCode(this)">Copy</button></div>
                                <pre><code>&lt;?php
$response = json_decode($payuResponse, true);

if (isset($response['result']['acsTemplate'])) {
    $html = base64_decode($response['result']['acsTemplate']);
    echo $html;
    exit;
}
?&gt;</code></pre>
                            </div>

                            <h4 style="margin-top:2rem;">After Bank Authentication</h4>
                            <div class="sm-info-box" style="background:#ebf8ff; border:1px solid #90cdf4;">
                                <strong style="color:#2b6cb0;">What happens next?</strong>
                                <p style="margin:0.5rem 0 0; color:#2d3748;">After the customer completes authentication at the bank:</p>
                                <ol style="margin:0.5rem 0 0; padding-left:1.25rem; color:#2d3748; line-height:1.8;">
                                    <li><strong>Redirect:</strong> PayU redirects customer to your <code>surl</code> (success) or <code>furl</code> (failure) with POST parameters</li>
                                    <li><strong>Webhook:</strong> PayU sends payment notification to your webhook URL (if configured)</li>
                                    <li><strong>Validate:</strong> Verify the payment using <code>verify_payment</code> API (recommended)</li>
                                </ol>
                            </div>

                            <div class="sm-info-box warning" style="margin-top:1rem; background:#fffaf0; border:1px solid #fbd38d;">
                                <strong style="color:#c05621;">&#9888; Test Bank Behavior</strong>
                                <p style="margin:0.5rem 0 0; color:#2d3748;">The test bank simulator (<code>TESTPGNB</code>) auto-completes the payment instantly. You may see "Transaction is already in terminal state" — this is <strong>normal</strong> and means the payment was processed successfully.</p>
                            </div>

                            <div class="sm-next-btn-wrapper">
                                <button class="button" onclick="smNbNavTo(document.querySelector('[data-section=sm-nb-verify]'),'sm-nb-verify')">Next: Step 3 - Validate &rarr;</button>
                            </div>
                        </div>
                    </div>

                    <!-- Section: NB Verify Payment -->
                    <div class="seamless-section" id="sm-nb-verify">
                        <h2>Step 3: Validate / Verify Payment</h2>
                        
                        <!-- GUIDE: Overview -->
                        <div class="sm-step-guide">
                            <div class="sm-guide-overview">
                                <h3>Overview</h3>
                                <p>After the customer completes payment on the bank page and is redirected back, use the <code>verify_payment</code> API to confirm the transaction status. This is the authoritative source of payment status and should always be used to determine the final state.</p>
                            </div>

                            <!-- Prerequisites -->
                            <div class="sm-guide-prereqs">
                                <h3>Prerequisites</h3>
                                <div class="sm-prereq-list">
                                    <div class="sm-prereq-item"><span class="sm-prereq-icon">&#10003;</span><div><strong>Merchant Key &amp; Salt</strong><br>Your PayU credentials</div></div>
                                    <div class="sm-prereq-item"><span class="sm-prereq-icon">&#10003;</span><div><strong>Transaction ID</strong><br>The <code>txnid</code> from the payment you want to verify</div></div>
                                </div>
                            </div>
                        </div>

                        <!-- API Reference -->
                        <h3>API Reference</h3>
                        <div class="sm-info-box" style="margin-bottom:1rem; background:#f0fff4; border:1px solid #9ae6b4;">
                            <strong>Endpoint:</strong> <code>POST https://test.payu.in/merchant/postservice.php?form=2</code>
                        </div>
                        <table class="sm-table">
                            <thead><tr><th>Parameter</th><th>Required</th><th>Description</th><th>Example</th></tr></thead>
                            <tbody>
                                <tr><td><code>key</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Merchant key provided by PayU during onboarding</td><td>a4vGC2</td></tr>
                                <tr><td><code>command</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>API command &mdash; fixed <code>verify_payment</code></td><td>verify_payment</td></tr>
                                <tr><td><code>var1</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Transaction ID to verify</td><td>NB_123456</td></tr>
                                <tr><td><code>hash</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>SHA-512 hash (auto-computed from key, command, var1, salt)</td><td><em>(computed)</em></td></tr>
                            </tbody>
                        </table>
                        
                        <div class="sm-code-block" style="margin-top:1rem;">
                            <div class="sm-code-header"><span>Hash Formula</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>sha512(key|command|var1|salt)

Example:
sha512(a4vGC2|verify_payment|NB_123456|YourSaltHere)</code></pre>
                        </div>

                        <!-- Sample Response -->
                        <h3 style="margin-top:1.5rem;">Sample Response</h3>
                        <div class="sm-code-block">
                            <div class="sm-code-header"><span>Success Response</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>{
  "status": 1,
  "msg": "Transaction Fetched Successfully",
  "transaction_details": {
    "NB_123456": {
      "mihpayid": "403993715525331373",
      "mode": "NB",
      "status": "success",
      "unmappedstatus": "captured",
      "key": "a4vGC2",
      "txnid": "NB_123456",
      "amount": "100.00",
      "bank_ref_num": "450699821592111537",
      "bankcode": "TESTPGNB",
      "error": "E000",
      "error_Message": "No Error"
    }
  }
}</code></pre>
                        </div>

                        <h3 style="margin-top:1.5rem;">Try It &mdash; Send Real Request</h3>
                        <div class="sm-interactive-form" id="smNbVerifyForm">
                            <div class="sm-form-row">
                                <div class="sm-form-group"><label>Merchant Key  <span class="required">*</span></label><input type="text" id="sm_nb_verify_key" value="a4vGC2"></div>
                                <div class="sm-form-group"><label>Merchant Salt  <span class="required">*</span></label><input type="password" id="sm_nb_verify_salt" value="hKvGJP28d2ZUuCRz5BnDag58QBdCxBli"></div>
                            </div>
                            <div class="sm-form-row">
                                <div class="sm-form-group"><label>Transaction ID  <span class="required">*</span></label><input type="text" id="sm_nb_verify_txnid" placeholder="Enter txnid from payment"></div>
                                <div class="sm-form-group">&nbsp;</div>
                            </div>
                            <div class="sm-form-actions">
                                <button class="button sm-btn-secondary" onclick="smNbPreviewVerifyRequest()">Preview Request</button>
                                <button class="button sm-btn-primary" onclick="smNbSendVerifyRequest()">Send to PayU &rarr;</button>
                            </div>
                        </div>
                        <div id="smNbVerifyReqRes" class="sm-req-res-panel" style="display:none;">
                            <div class="sm-req-res-grid">
                                <div class="sm-req-panel"><div class="sm-panel-header"><span>Request Sent</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div><pre><code id="smNbVerifyRequestView"></code></pre></div>
                                <div class="sm-res-panel"><div class="sm-panel-header"><span>Response Received</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div><div id="smNbVerifyStatusBadge" class="sm-status-badge"></div><pre><code id="smNbVerifyResponseView"></code></pre></div>
                            </div>
                            <div class="sm-response-guide" id="smNbVerifyResponseGuide" style="display:none;"><h4>Understanding the Response</h4><div id="smNbVerifyResponseExplain"></div></div>
                            <div class="sm-curl-section"><div class="sm-panel-header"><span>cURL Command</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div><pre><code id="smNbVerifyCurlView"></code></pre></div>
                        </div>
                    </div>

                    <!-- Section: NB Normal Refund -->
                    <div class="seamless-section" id="sm-nb-refund">
                        <h2>Normal Refund</h2>
                        
                        <!-- GUIDE: Overview -->
                        <div class="sm-step-guide">
                            <div class="sm-guide-overview">
                                <h3>Overview</h3>
                                <p>Use the <code>cancel_refund_transaction</code> API to initiate a refund for a successful Net Banking transaction. You'll need the <code>mihpayid</code> from the original transaction response.</p>
                            </div>

                            <!-- Prerequisites -->
                            <div class="sm-guide-prereqs">
                                <h3>Prerequisites</h3>
                                <div class="sm-prereq-list">
                                    <div class="sm-prereq-item"><span class="sm-prereq-icon">&#10003;</span><div><strong>Successful Transaction</strong><br>A captured/successful Net Banking transaction</div></div>
                                    <div class="sm-prereq-item"><span class="sm-prereq-icon">&#10003;</span><div><strong>mihpayid</strong><br>PayU's unique transaction ID from the payment response</div></div>
                                    <div class="sm-prereq-item"><span class="sm-prereq-icon">&#10003;</span><div><strong>Unique Token ID</strong><br>Your unique identifier for this refund request</div></div>
                                </div>
                            </div>
                        </div>

                        <!-- API Reference -->
                        <h3>API Reference</h3>
                        <div class="sm-info-box" style="margin-bottom:1rem; background:#f0fff4; border:1px solid #9ae6b4;">
                            <strong>Endpoint:</strong> <code>POST https://test.payu.in/merchant/postservice.php?form=2</code>
                        </div>
                        <table class="sm-table">
                            <thead><tr><th>Parameter</th><th>Required</th><th>Description</th><th>Example</th></tr></thead>
                            <tbody>
                                <tr><td><code>key</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Merchant key provided by PayU during onboarding</td><td>a4vGC2</td></tr>
                                <tr><td><code>command</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>API command &mdash; fixed <code>cancel_refund_transaction</code></td><td>cancel_refund_transaction</td></tr>
                                <tr><td><code>var1</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>PayU transaction ID (mihpayid)</td><td>403993715537135556</td></tr>
                                <tr><td><code>var2</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Unique token/reference ID for refund</td><td>REFUND_123456</td></tr>
                                <tr><td><code>var3</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Refund amount (can be partial)</td><td>500.00</td></tr>
                                <tr><td><code>hash</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>SHA-512 hash (auto-computed from key, command, var1, salt)</td><td><em>(computed)</em></td></tr>
                            </tbody>
                        </table>
                        
                        <div class="sm-code-block" style="margin-top:1rem;">
                            <div class="sm-code-header"><span>Hash Formula</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>sha512(key|command|var1|salt)

Example:
sha512(a4vGC2|cancel_refund_transaction|403993715537135556|YourSaltHere)</code></pre>
                        </div>

                        <!-- Sample Response -->
                        <h3 style="margin-top:1.5rem;">Sample Response</h3>
                        <div class="sm-code-block">
                            <div class="sm-code-header"><span>Success Response</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>{
  "status": 1,
  "msg": "Refund Request Queued",
  "request_id": "10825083",
  "bank_ref_num": null,
  "mihpayid": "403993715537135556",
  "refund_amount": "500.00"
}</code></pre>
                        </div>

                        <div class="sm-info-box warning" style="margin-top:1rem;">
                            <strong>Important Notes</strong>
                            <ul>
                                <li>Refunds are processed asynchronously and may take 5-7 business days</li>
                                <li>Use <code>check_action_status</code> API to track refund status</li>
                                <li>Partial refunds are supported - specify the amount in <code>var3</code></li>
                            </ul>
                        </div>

                        <h3 style="margin-top:1.5rem;">Try It &mdash; Send Refund Request</h3>
                        <div class="sm-interactive-form" id="smNbRefundForm">
                            <div class="sm-form-row">
                                <div class="sm-form-group"><label>Merchant Key <span class="required">*</span></label><input type="text" id="sm_nb_refund_key" value="a4vGC2"></div>
                                <div class="sm-form-group"><label>Merchant Salt <span class="required">*</span></label><input type="text" id="sm_nb_refund_salt" value="hKvGJP28d2ZUuCRz5BnDag58QBdCxBli" autocomplete="off" style="-webkit-text-security: disc;"></div>
                            </div>
                            <div class="sm-form-row">
                                <div class="sm-form-group"><label>PayU Transaction ID (mihpayid) <span class="required">*</span></label><input type="text" id="sm_nb_refund_mihpayid" placeholder="e.g., 403993715537135556"></div>
                                <div class="sm-form-group"><label>Unique Refund Token ID <span class="required">*</span></label><input type="text" id="sm_nb_refund_tokenid" placeholder="e.g., REFUND_123456"></div>
                            </div>
                            <div class="sm-form-row">
                                <div class="sm-form-group"><label>Refund Amount <span class="required">*</span></label><input type="text" id="sm_nb_refund_amount" placeholder="e.g., 500.00"></div>
                                <div class="sm-form-group">&nbsp;</div>
                            </div>
                            <div class="sm-form-actions">
                                <button class="button sm-btn-fill-sample" onclick="smNbFillSampleRefund()">&#9889; Fill Sample Data</button>
                                <button class="button sm-btn-secondary" onclick="smNbPreviewRefundRequest()">Preview Request</button>
                                <button class="button sm-btn-primary" onclick="smNbSendRefundRequest()">Send Refund Request &rarr;</button>
                            </div>
                        </div>

                        <div id="smNbRefundReqRes" class="sm-req-res-panel" style="display:none;">
                            <div class="sm-req-res-grid">
                                <div class="sm-req-panel"><div class="sm-panel-header"><span>Request Sent</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div><pre><code id="smNbRefundRequestView"></code></pre></div>
                                <div class="sm-res-panel"><div class="sm-panel-header"><span>Response Received</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div><div id="smNbRefundStatusBadge" class="sm-status-badge"></div><pre><code id="smNbRefundResponseView"></code></pre></div>
                            </div>
                            <div class="sm-curl-section"><div class="sm-panel-header"><span>cURL Command</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div><pre><code id="smNbRefundCurlView"></code></pre></div>
                        </div>

                        <!-- Refund Status Check -->
                        <h3 style="margin-top:2rem;">Check Refund Status</h3>
                        <p style="color:#4a5568; margin-bottom:1rem;">After initiating a refund, use <code>check_action_status</code> to track its progress.</p>
                        <div class="sm-interactive-form" id="smNbRefundStatusForm">
                            <div class="sm-form-row">
                                <div class="sm-form-group"><label>Merchant Key <span class="required">*</span></label><input type="text" id="sm_nb_refund_status_key" value="a4vGC2"></div>
                                <div class="sm-form-group"><label>Merchant Salt <span class="required">*</span></label><input type="text" id="sm_nb_refund_status_salt" value="hKvGJP28d2ZUuCRz5BnDag58QBdCxBli" autocomplete="off" style="-webkit-text-security: disc;"></div>
                            </div>
                            <div class="sm-form-row">
                                <div class="sm-form-group"><label>Request ID (from refund response) <span class="required">*</span></label><input type="text" id="sm_nb_refund_status_reqid" placeholder="e.g., request_id from refund response"></div>
                                <div class="sm-form-group">&nbsp;</div>
                            </div>
                            <div class="sm-form-actions">
                                <button class="button sm-btn-secondary" onclick="smNbPreviewRefundStatusRequest()">Preview Request</button>
                                <button class="button sm-btn-primary" onclick="smNbSendRefundStatusRequest()">Check Status &rarr;</button>
                            </div>
                        </div>

                        <div id="smNbRefundStatusReqRes" class="sm-req-res-panel" style="display:none;">
                            <div class="sm-req-res-grid">
                                <div class="sm-req-panel"><div class="sm-panel-header"><span>Request Sent</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div><pre><code id="smNbRefundStatusRequestView"></code></pre></div>
                                <div class="sm-res-panel"><div class="sm-panel-header"><span>Response Received</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div><div id="smNbRefundStatusStatusBadge" class="sm-status-badge"></div><pre><code id="smNbRefundStatusResponseView"></code></pre></div>
                            </div>
                            <div class="sm-curl-section"><div class="sm-panel-header"><span>cURL Command</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div><pre><code id="smNbRefundStatusCurlView"></code></pre></div>
                        </div>

                        <div class="sm-next-btn-wrapper">
                            <button class="button" onclick="smNbNavTo(document.querySelector('[data-section=sm-nb-split-refund]'),'sm-nb-split-refund')">Next: Split Refund &rarr;</button>
                        </div>
                    </div>

                    <!-- Section: NB Split Refund -->
                    <div class="seamless-section" id="sm-nb-split-refund">
                        <h2>Split Refund</h2>
                        
                        <!-- GUIDE: Overview -->
                        <div class="sm-step-guide">
                            <div class="sm-guide-overview">
                                <h3>Overview</h3>
                                <p>Split Refund allows you to refund a <strong>split payment transaction</strong> where the original payment was distributed among multiple merchants/aggregators. You can refund the entire split amount or partial amounts to specific split recipients.</p>
                            </div>

                            <!-- Prerequisites -->
                            <div class="sm-guide-prereqs">
                                <h3>Prerequisites</h3>
                                <div class="sm-prereq-list">
                                    <div class="sm-prereq-item"><span class="sm-prereq-icon">&#10003;</span><div><strong>Split Payment Transaction</strong><br>A successful split payment transaction</div></div>
                                    <div class="sm-prereq-item"><span class="sm-prereq-icon">&#10003;</span><div><strong>mihpayid</strong><br>PayU's unique transaction ID from the split payment</div></div>
                                    <div class="sm-prereq-item"><span class="sm-prereq-icon">&#10003;</span><div><strong>Split Details</strong><br>Original split merchant IDs and amounts</div></div>
                                </div>
                            </div>
                        </div>

                        <!-- Required Parameters for API -->
                        <h3>Required Parameters for API</h3>
                        <div class="sm-info-box" style="margin-bottom:1rem; background:#f0fff4; border:1px solid #9ae6b4;">
                            <strong>Endpoint:</strong> <code>POST https://test.payu.in/merchant/postservice.php?form=2</code>
                        </div>
                        <table class="sm-table">
                            <thead><tr><th>Parameter</th><th>Required</th><th>Description</th><th>Example</th></tr></thead>
                            <tbody>
                                <tr><td><code>key</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Merchant key provided by PayU during onboarding</td><td>a4vGC2</td></tr>
                                <tr><td><code>command</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>API command &mdash; fixed <code>cancel_refund_transaction</code></td><td>cancel_refund_transaction</td></tr>
                                <tr><td><code>var1</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>PayU transaction ID (mihpayid)</td><td>403993715537135556</td></tr>
                                <tr><td><code>var2</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Unique token/reference ID for refund</td><td>SPLIT_REFUND_123456</td></tr>
                                <tr><td><code>var3</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Refund amount</td><td>500.00</td></tr>
                                <tr><td><code>var5</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Split refund details JSON</td><td>{"splitInfo":[...]}</td></tr>
                                <tr><td><code>hash</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>SHA-512 hash (auto-computed from key, command, var1, salt)</td><td><em>(computed)</em></td></tr>
                            </tbody>
                        </table>
                        
                        <div class="sm-code-block" style="margin-top:1rem;">
                            <div class="sm-code-header"><span>Hash Formula</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>sha512(key|command|var1|salt)

Example:
sha512(a4vGC2|cancel_refund_transaction|403993715537135556|YourSaltHere)</code></pre>
                        </div>

                        <div class="sm-code-block" style="margin-top:1rem;">
                            <div class="sm-code-header"><span>Split Refund Details (var5) Format</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>{
  "splitInfo": [
    {
      "merchantId": "SPLIT_MERCHANT_1",
      "amount": "300.00"
    },
    {
      "merchantId": "SPLIT_MERCHANT_2", 
      "amount": "200.00"
    }
  ]
}</code></pre>
                        </div>

                        <!-- Sample Response -->
                        <h3 style="margin-top:1.5rem;">Sample Response</h3>
                        <div class="sm-code-block">
                            <div class="sm-code-header"><span>Success Response</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>{
  "status": 1,
  "msg": "Refund Request Queued",
  "request_id": "10825084",
  "bank_ref_num": null,
  "mihpayid": "403993715537135556",
  "refund_amount": "500.00",
  "split_refund_status": "queued"
}</code></pre>
                        </div>

                        <div class="sm-info-box warning" style="margin-top:1rem;">
                            <strong>Important Notes</strong>
                            <ul>
                                <li>Split refunds must match the original split structure</li>
                                <li>Total refund amount across all splits cannot exceed the original transaction amount</li>
                                <li>Each split merchant receives their proportional refund</li>
                                <li>Use <code>check_action_status</code> API to track split refund status</li>
                            </ul>
                        </div>

                        <h3 style="margin-top:1.5rem;">Try It &mdash; Send Split Refund Request</h3>
                        <div class="sm-interactive-form" id="smNbSplitRefundForm">
                            <div class="sm-form-row">
                                <div class="sm-form-group"><label>Merchant Key <span class="required">*</span></label><input type="text" id="sm_nb_split_refund_key" value="a4vGC2"></div>
                                <div class="sm-form-group"><label>Merchant Salt <span class="required">*</span></label><input type="text" id="sm_nb_split_refund_salt" value="hKvGJP28d2ZUuCRz5BnDag58QBdCxBli" autocomplete="off" style="-webkit-text-security: disc;"></div>
                            </div>
                            <div class="sm-form-row">
                                <div class="sm-form-group"><label>PayU Transaction ID (mihpayid) <span class="required">*</span></label><input type="text" id="sm_nb_split_refund_mihpayid" placeholder="e.g., 403993715537135556"></div>
                                <div class="sm-form-group"><label>Unique Refund Token ID <span class="required">*</span></label><input type="text" id="sm_nb_split_refund_tokenid" placeholder="e.g., SPLIT_REFUND_123456"></div>
                            </div>
                            <div class="sm-form-row">
                                <div class="sm-form-group"><label>Total Refund Amount <span class="required">*</span></label><input type="text" id="sm_nb_split_refund_amount" placeholder="e.g., 500.00"></div>
                                <div class="sm-form-group">&nbsp;</div>
                            </div>
                            <div class="sm-form-row">
                                <div class="sm-form-group" style="width:100%;">
                                    <label>Split Refund Details (JSON) <span class="required">*</span></label>
                                    <textarea id="sm_nb_split_refund_details" rows="6" placeholder='{"splitInfo":[{"merchantId":"SPLIT_MERCHANT_1","amount":"300.00"},{"merchantId":"SPLIT_MERCHANT_2","amount":"200.00"}]}'></textarea>
                                </div>
                            </div>
                            <div class="sm-form-actions">
                                <button class="button sm-btn-fill-sample" onclick="smNbFillSampleSplitRefund()">&#9889; Fill Sample Data</button>
                                <button class="button sm-btn-secondary" onclick="smNbPreviewSplitRefundRequest()">Preview Request</button>
                                <button class="button sm-btn-primary" onclick="smNbSendSplitRefundRequest()">Send Split Refund &rarr;</button>
                            </div>
                        </div>

                        <div id="smNbSplitRefundReqRes" class="sm-req-res-panel" style="display:none;">
                            <div class="sm-req-res-grid">
                                <div class="sm-req-panel"><div class="sm-panel-header"><span>Request Sent</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div><pre><code id="smNbSplitRefundRequestView"></code></pre></div>
                                <div class="sm-res-panel"><div class="sm-panel-header"><span>Response Received</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div><div id="smNbSplitRefundStatusBadge" class="sm-status-badge"></div><pre><code id="smNbSplitRefundResponseView"></code></pre></div>
                            </div>
                            <div class="sm-curl-section"><div class="sm-panel-header"><span>cURL Command</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div><pre><code id="smNbSplitRefundCurlView"></code></pre></div>
                        </div>

                        <div class="sm-next-btn-wrapper">
                            <button class="button" onclick="smNbNavTo(document.querySelector('[data-section=sm-nb-settlement]'),'sm-nb-settlement')">Next: Settlement &rarr;</button>
                        </div>
                    </div>

                    <!-- Section: NB TPV -->
                    <div class="seamless-section" id="sm-nb-tpv">
                        <h2>Step 1: Net Banking TPV (Third Party Validation)</h2>

                        <!-- Documentation Links -->
                        <div class="sm-doc-links" style="margin-bottom:1.5rem; padding:1rem; background:linear-gradient(135deg, #ecfdf5 0%, #d1fae5 100%); border:1px solid #34d399; border-radius:8px;">
                            <strong style="color:#065f46;">&#128213; Documentation</strong>
                            <div style="margin-top:0.5rem; display:flex; flex-wrap:wrap; gap:0.75rem;">
                                <a href="https://docs.payu.in/docs/collect-netbanking-payment-with-tpv-payu-hosted-checkout" target="_blank" style="color:#047857; text-decoration:none; font-size:0.9rem;">&#128279; Net Banking TPV Integration Guide</a>
                            </div>
                        </div>

                        <div class="sm-step-guide">
                            <div class="sm-guide-overview">
                                <h3>Overview</h3>
                                <p>TPV ensures that the payment originates from a <strong>specific bank account</strong> belonging to the customer. The merchant provides beneficiary details (account number + IFSC), and PayU validates that the paying account matches before processing. Used in mutual funds, stock trading, insurance, and regulated financial products.</p>
                            </div>

                            <div class="sm-guide-prereqs">
                                <h3>Prerequisites</h3>
                                <div class="sm-prereq-list">
                                    <div class="sm-prereq-item"><span class="sm-prereq-icon">&#10003;</span><div><strong>Merchant Key &amp; Salt</strong><br>Your PayU credentials</div></div>
                                    <div class="sm-prereq-item"><span class="sm-prereq-icon">&#10003;</span><div><strong>Beneficiary Account</strong><br>Customer's verified bank account number</div></div>
                                    <div class="sm-prereq-item"><span class="sm-prereq-icon">&#10003;</span><div><strong>IFSC Code</strong><br>Bank IFSC code for account verification</div></div>
                                    <div class="sm-prereq-item"><span class="sm-prereq-icon">&#10003;</span><div><strong>TPV Enabled</strong><br>TPV feature enabled on your PayU account</div></div>
                                </div>
                            </div>

                            <div class="sm-guide-flow">
                                <h3>TPV Payment Flow</h3>
                                <div class="sm-flow-diagram">
                                    <div class="sm-flow-step"><span class="sm-flow-num">1</span><span class="sm-flow-label">Collect Beneficiary</span></div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step"><span class="sm-flow-num">2</span><span class="sm-flow-label">Initiate Payment</span></div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step"><span class="sm-flow-num">3</span><span class="sm-flow-label">Bank Auth + Validate</span></div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step"><span class="sm-flow-num">4</span><span class="sm-flow-label">Verify</span></div>
                                </div>
                            </div>
                        </div>

                        <!-- API Reference -->
                        <h3>API Reference</h3>
                        <div class="sm-info-box" style="margin-bottom:1rem; background:#f0fff4; border:1px solid #9ae6b4;">
                            <strong>Endpoint:</strong> <code>POST https://test.payu.in/_payment</code> (Test) | <code>POST https://secure.payu.in/_payment</code> (Production)
                        </div>
                        <table class="sm-table">
                            <thead><tr><th>Parameter</th><th>Required</th><th>Description</th><th>Example</th></tr></thead>
                            <tbody>
                                <tr><td><code>key</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Merchant key provided by PayU during onboarding</td><td>a4vGC2</td></tr>
                                <tr><td><code>salt</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Merchant salt for hash generation (never sent in request)</td><td>hKvGJP28d2...</td></tr>
                                <tr><td><code>txnid</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Unique transaction ID</td><td>TPV_123456</td></tr>
                                <tr><td><code>amount</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Transaction amount in INR</td><td>100.00</td></tr>
                                <tr><td><code>productinfo</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Product/service description</td><td>Mutual Fund SIP</td></tr>
                                <tr><td><code>firstname</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Customer's first name</td><td>John</td></tr>
                                <tr><td><code>email</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Customer's email address</td><td>john@example.com</td></tr>
                                <tr><td><code>phone</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Customer's phone number</td><td>9876543210</td></tr>
                                <tr><td><code>surl</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Success callback URL</td><td>https://yoursite.com/success</td></tr>
                                <tr><td><code>furl</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Failure callback URL</td><td>https://yoursite.com/failure</td></tr>
                                <tr><td><code>hash</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>SHA-512 payment hash (auto-computed)</td><td><em>(computed)</em></td></tr>
                                <tr><td><code>pg</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Payment gateway type &mdash; fixed <code>NB</code></td><td>NB</td></tr>
                                <tr><td><code>bankcode</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>TPV-enabled bank code</td><td>SBITPV</td></tr>
                                <tr><td><code>txn_s2s_flow</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>S2S flow identifier &mdash; fixed <code>4</code></td><td>4</td></tr>
                                <tr><td><code>api_version</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>API version for TPV &mdash; fixed <code>6</code></td><td>6</td></tr>
                                <tr><td><code>beneficiarydetail</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>JSON with beneficiary account details</td><td>{"beneficiaryAccountNumber":"..."}</td></tr>
                                <tr><td><code>s2s_client_ip</code></td><td><span class="sm-badge-conditional">Conditional</span></td><td>Source IP of the customer. Required for S2S flow</td><td>10.200.12.12</td></tr>
                                <tr><td><code>s2s_device_info</code></td><td><span class="sm-badge-conditional">Conditional</span></td><td>Customer agent's device information</td><td>Mozilla/5.0</td></tr>
                                <tr><td><code>udf1-udf5</code></td><td><span class="sm-badge-optional">Optional</span></td><td>User-defined fields</td><td></td></tr>
                            </tbody>
                        </table>

                        <h4 style="margin-top:1.5rem;">beneficiarydetail JSON Structure</h4>
                        <table class="sm-table">
                            <thead><tr><th>Field</th><th>Required</th><th>Description</th><th>Example</th></tr></thead>
                            <tbody>
                                <tr><td><code>beneficiaryAccountNumber</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Customer's bank account number</td><td>9876543210123456789</td></tr>
                                <tr><td><code>ifscCode</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Bank IFSC code (11 characters)</td><td>SBIN0001234</td></tr>
                            </tbody>
                        </table>

                        <div class="sm-code-block" style="margin-top:1rem;">
                            <div class="sm-code-header"><span>Hash Formula (TPV with api_version=6)</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>sha512(key|txnid|amount|productinfo|firstname|email|udf1|udf2|udf3|udf4|udf5||||||beneficiarydetail|salt)

Note: 12 pipes between email and beneficiarydetail for api_version=6

Example:
sha512(a4vGC2|TPV_123|100.00|Mutual Fund|John|john@email.com||||||||||||{"beneficiaryAccountNumber":"9876...","ifscCode":"SBIN..."}|YourSalt)</code></pre>
                        </div>

                        <div class="sm-step-guide" style="margin-top:1.5rem;">
                        </div>

                        <h4>Hash Formula</h4>
                        <div class="sm-code-block">
                            <div class="sm-code-header"><span>TPV Payment Hash</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>sha512(key|txnid|amount|productinfo|firstname|email|udf1|udf2|udf3|udf4|udf5||||||beneficiarydetail|SALT)

// beneficiarydetail is a JSON string:
// {"beneficiaryAccountNumber":"1234567890","ifscCode":"SBIN0001234"}

// Key parameters for TPV:
api_version = 6
beneficiarydetail = JSON.stringify({beneficiaryAccountNumber, ifscCode})</code></pre>
