                        <h3>Try It &mdash; Send TPV Payment</h3>
                        <div class="sm-interactive-form" id="smNbTpvForm">
                            <div class="sm-form-row">
                                <div class="sm-form-group"><label>Merchant Key  <span class="required">*</span></label><input type="text" id="sm_nb_tpv_key" value="a4vGC2"></div>
                                <div class="sm-form-group"><label>Merchant Salt  <span class="required">*</span></label><input type="password" id="sm_nb_tpv_salt" value="hKvGJP28d2ZUuCRz5BnDag58QBdCxBli"></div>
                            </div>
                            <div class="sm-form-row">
                                <div class="sm-form-group">
                                    <label>Transaction ID (txnid) <span class="required">*</span></label>
                                    <div style="display:flex; gap:0.5rem; align-items:center;">
                                        <input type="text" id="sm_nb_tpv_txnid" placeholder="Auto-generated" style="flex:1;">
                                        <button type="button" onclick="document.getElementById('sm_nb_tpv_txnid').value = 'TPV_' + Date.now();" style="padding:0.5rem 1rem; font-size:0.85rem; background:linear-gradient(135deg, #10846D 0%, #024538 100%); color:#fff; border:none; border-radius:6px; cursor:pointer; white-space:nowrap;">Get Txn ID</button>
                                    </div>
                                </div>
                                <div class="sm-form-group"><label>Amount  <span class="required">*</span></label><input type="text" id="sm_nb_tpv_amount" value="100.00"></div>
                            </div>
                            <div class="sm-form-row">
                                <div class="sm-form-group"><label>Product Info  <span class="required">*</span></label><input type="text" id="sm_nb_tpv_productinfo" value="Mutual Fund SIP"></div>
                                <div class="sm-form-group">
                                    <label>Bank Code  <span class="required">*</span></label>
                                    <input type="text" id="sm_nb_tpv_bankcode" value="AXNBTPV" placeholder="AXNBTPV - Axis Bank" style="font-family:monospace;">
                                    <small style="color:var(--text-muted); font-size:0.75rem;">Enter TPV bank code (e.g., AXNBTPV for Axis Bank)</small>
                                </div>
                            </div>
                            <div class="sm-form-row">
                                <div class="sm-form-group"><label>First Name  <span class="required">*</span></label><input type="text" id="sm_nb_tpv_firstname" value="Test"></div>
                                <div class="sm-form-group"><label>Email  <span class="required">*</span></label><input type="email" id="sm_nb_tpv_email" value="test@example.com"></div>
                            </div>
