                    </div>

                    <!-- Section: NB TPV Verify -->
                    <div class="seamless-section" id="sm-nb-tpv-verify">
                        <h2>Step 3: Validate TPV Payment</h2>

                        <!-- API Reference -->
                        <h3>API Reference</h3>
                        <div class="sm-info-box" style="margin-bottom:1rem; background:#f0fff4; border:1px solid #9ae6b4;">
                            <strong>Endpoint:</strong> <code>POST https://test.payu.in/merchant/postservice.php?form=2</code>
                        </div>
                        <table class="sm-table">
                            <thead><tr><th>Parameter</th><th>Required</th><th>Description</th><th>Example</th></tr></thead>
                            <tbody>
                                <tr><td><code>key</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Merchant key provided by PayU during onboarding</td><td>a4vGC2</td></tr>
                                <tr><td><code>salt</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Merchant salt used for hash generation (never sent in request)</td><td>mGHSxpD2iB...</td></tr>
                                <tr><td><code>command</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; API command &mdash; fixed <code>verify_payment</code></td><td>verify_payment</td></tr>
                                <tr><td><code>var1</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Transaction ID (<code>txnid</code>) used during TPV payment initiation</td><td>TPV_1775739737886</td></tr>
                                <tr><td><code>hash</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; SHA-512 hash &mdash; <code>sha512(key|verify_payment|var1|salt)</code></td><td><em>(computed)</em></td></tr>
                            </tbody>
                        </table>

                        <h3 style="margin-top:1.5rem;">Response Parameters</h3>
                        <table class="sm-table">
                            <thead><tr><th>Parameter</th><th>Description</th><th>Example</th></tr></thead>
                            <tbody>
                                <tr><td><code>status</code></td><td>Transaction status &mdash; <code>success</code> or <code>failure</code></td><td>success</td></tr>
                                <tr><td><code>mihpayid</code></td><td>PayU&rsquo;s unique transaction reference ID</td><td>10731087875</td></tr>
                                <tr><td><code>mode</code></td><td>Payment mode &mdash; <code>NB</code> for Net Banking TPV</td><td>NB</td></tr>
                                <tr><td><code>txnid</code></td><td>Your original transaction ID</td><td>TPV_1775739737886</td></tr>
                                <tr><td><code>amount</code></td><td>Transaction amount</td><td>100.00</td></tr>
                                <tr><td><code>unmappedstatus</code></td><td>Detailed status &mdash; <code>captured</code> for successful TPV payment</td><td>captured</td></tr>
                                <tr><td><code>bankcode</code></td><td>Bank code confirms the bank used matches expected bank</td><td>AXNBTPV</td></tr>
                                <tr><td><code>bank_ref_num</code></td><td>Bank reference number for the transaction</td><td>YESB00000...</td></tr>
                                <tr><td><code>firstname</code></td><td>Customer first name</td><td>Test</td></tr>
                                <tr><td><code>email</code></td><td>Customer email</td><td>test@example.com</td></tr>
                                <tr><td><code>phone</code></td><td>Customer phone number</td><td>9876543210</td></tr>
                                <tr><td><code>field9</code></td><td>Payment gateway response message</td><td>Transaction Completed Successfully</td></tr>
                            </tbody>
                        </table>

                        <div class="sm-step-guide">
                            <div class="sm-guide-overview">
                                <h3>Overview</h3>
                                <p>After the customer completes bank authentication, use <code>verify_payment</code> to confirm the transaction status. For TPV transactions, the response includes additional validation details confirming that the beneficiary account was verified.</p>
                            </div>
                        </div>

                        <h4>Hash Formula</h4>
                        <div class="sm-code-block">
                            <div class="sm-code-header"><span>Verify Payment Hash</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>sha512(key|command|var1|salt)
sha512(merchantKey|verify_payment|txnid|merchantSalt)</code></pre>
                        </div>

                        <h3>Try It &mdash; Verify TPV Transaction</h3>
                        <div class="sm-interactive-form" id="smNbTpvVerifyForm">
                            <div class="sm-form-row">
                                <div class="sm-form-group"><label>Merchant Key  <span class="required">*</span></label><input type="text" id="sm_nb_tpv_verify_key" value="a4vGC2"></div>
                                <div class="sm-form-group"><label>Merchant Salt  <span class="required">*</span></label><input type="password" id="sm_nb_tpv_verify_salt" value="hKvGJP28d2ZUuCRz5BnDag58QBdCxBli"></div>
                            </div>
                            <div class="sm-form-row">
                                <div class="sm-form-group"><label>Transaction ID  <span class="required">*</span></label><input type="text" id="sm_nb_tpv_verify_txnid" placeholder="From TPV payment initiation"></div>
                                <div class="sm-form-group">&nbsp;</div>
                            </div>
                            <div class="sm-form-actions">
                                <button class="button sm-btn-secondary" onclick="smNbPreviewTpvVerifyRequest()">Preview Request</button>
                                <button class="button sm-btn-primary" onclick="smNbSendTpvVerifyRequest()">Verify Payment &rarr;</button>
                            </div>
                        </div>
                        <div id="smNbTpvVerifyReqRes" class="sm-req-res-panel" style="display:none;">
                            <div class="sm-req-res-grid">
                                <div class="sm-req-panel"><div class="sm-panel-header"><span>Request Sent</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div><pre><code id="smNbTpvVerifyRequestView"></code></pre></div>
                                <div class="sm-res-panel"><div class="sm-panel-header"><span>Response Received</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div><div id="smNbTpvVerifyStatusBadge" class="sm-status-badge"></div><pre><code id="smNbTpvVerifyResponseView"></code></pre></div>
                            </div>
                            <div class="sm-response-guide" id="smNbTpvVerifyResponseGuide" style="display:none;"><h4>Understanding the Response</h4><div id="smNbTpvVerifyResponseExplain"></div></div>
                            <div class="sm-curl-section"><div class="sm-panel-header"><span>cURL Command</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div><pre><code id="smNbTpvVerifyCurlView"></code></pre></div>
                        </div>

                        <div class="sm-info-box" style="margin-top:2rem;">
                            <strong>&#128161; What to Check in TPV Verify Response</strong>
                            <ul>
                                <li><code>status</code> &mdash; "success" means payment completed and account validated</li>
                                <li><code>unmappedstatus</code> &mdash; "captured" for successful TPV payment</li>
                                <li><code>mode</code> &mdash; Should be "NB" for Net Banking TPV</li>
                                <li><code>bankcode</code> &mdash; Confirms the bank used matches the expected bank</li>
                            </ul>
                        </div>

                    </div>

                    <!-- Section: NB PACB -->
                    <div class="seamless-section" id="sm-nb-pacb">
                        <h2>Step 1: Net Banking PACB (Pre-Authorize)</h2>

                        <!-- Documentation Links -->
                        <div class="sm-doc-links" style="margin-bottom:1.5rem; padding:1rem; background:linear-gradient(135deg, #ecfdf5 0%, #d1fae5 100%); border:1px solid #34d399; border-radius:8px;">
                            <strong style="color:#065f46;">&#128213; Documentation</strong>
                            <div style="margin-top:0.5rem; display:flex; flex-wrap:wrap; gap:0.75rem;">
                                <a href="https://docs.payu.in/docs/pre-authorization" target="_blank" style="color:#047857; text-decoration:none; font-size:0.9rem;">&#128279; Pre-Authorization Guide</a>
                                <a href="https://docs.payu.in/reference/capture-transaction" target="_blank" style="color:#047857; text-decoration:none; font-size:0.9rem;">&#128279; Capture Transaction API</a>
                            </div>
                        </div>

                        <div class="sm-step-guide">
                            <div class="sm-guide-overview">
                                <h3>Overview</h3>
                                <p>PACB allows you to pre-authorize (block) funds in the customer's bank account without immediate debit. You can later capture the blocked amount fully or partially.</p>
                            </div>
                        </div>

                        <div class="sm-info-box warning" style="margin-bottom:1.5rem; border-left:4px solid #ff9800; background:rgba(255,152,0,0.08); padding:1.25rem;">
                            <strong>&#9888; Activation Required:</strong> Net Banking PACB must be explicitly enabled on your PayU merchant account. Contact your PayU KAM to activate this feature.
                        </div>

                        <!-- Payment Type Selection Cards -->
                        <h3>Payment Type <span style="color:#dc2626;">*</span></h3>
                        <div class="sm-payment-type-cards" style="display:flex; gap:1rem; margin-bottom:1.5rem; flex-wrap:wrap;">
                            <div class="sm-payment-card active" onclick="smNbSwitchPacbTab('onetime')" id="smNbPacbTabOnetime" style="flex:1; min-width:220px; padding:1.25rem 1.5rem; border:2px solid #10846D; background:rgba(16,132,109,0.05); border-radius:8px; cursor:pointer; text-align:center; transition:all 0.2s;">
                                <div style="font-size:1.1rem; font-weight:600; color:#10846D; margin-bottom:0.25rem;">One-Time Payment</div>
                                <div style="font-size:0.85rem; color:#6b7280;">Single transaction payment</div>
                            </div>
                            <div class="sm-payment-card" onclick="smNbSwitchPacbTab('subscription')" id="smNbPacbTabSubscription" style="flex:1; min-width:220px; padding:1.25rem 1.5rem; border:2px solid #e5e7eb; background:white; border-radius:8px; cursor:pointer; text-align:center; transition:all 0.2s;">
                                <div style="font-size:1.1rem; font-weight:600; color:#374151; margin-bottom:0.25rem;">Subscription Payment</div>
                                <div style="font-size:0.85rem; color:#6b7280;">Recurring payment setup</div>
                            </div>
                        </div>

                        <!-- One-Time Payment Content -->
                        <div id="smNbPacbOnetimeContent">
                            <h3 style="color:#10846D;">PACB One-Time Payment</h3>
                            <p style="margin-bottom:1rem; color:#4a5568;">Block funds once and capture the full or partial amount. Ideal for single transactions where final amount may vary.</p>
                            
                            <div class="sm-flow-diagram" style="margin-bottom:1.5rem;">
                                <div class="sm-flow-step"><span class="sm-flow-num">1</span><span class="sm-flow-label">Pre-Auth</span></div>
                                <div class="sm-flow-arrow">&rarr;</div>
                                <div class="sm-flow-step"><span class="sm-flow-num">2</span><span class="sm-flow-label">Bank Auth</span></div>
                                <div class="sm-flow-arrow">&rarr;</div>
                                <div class="sm-flow-step"><span class="sm-flow-num">3</span><span class="sm-flow-label">Funds Blocked</span></div>
                                <div class="sm-flow-arrow">&rarr;</div>
                                <div class="sm-flow-step"><span class="sm-flow-num">4</span><span class="sm-flow-label">Capture</span></div>
                            </div>

                            <!-- Hash Formula -->
                            <h3>Hash Formula</h3>
                            <div class="sm-code-block">
                                <div class="sm-code-header"><span>PACB Payment Hash</span><button onclick="smCopyCode(this)">Copy</button></div>
                                <pre><code>sha512(key|txnid|amount|productinfo|firstname|email|udf1|udf2|udf3|udf4|udf5||||||salt)

// Key parameter for PACB:
pre_authorize=1        // Enable pre-authorization mode</code></pre>
                            </div>

                            <h3>API Reference</h3>
                        <div class="sm-info-box" style="margin-bottom:1rem; background:#f0fff4; border:1px solid #9ae6b4;">
                            <strong>Endpoint:</strong> <code>POST https://test.payu.in/_payment</code> (Test) | <code>POST https://secure.payu.in/_payment</code> (Production)
                        </div>
                        <table class="sm-table">
                            <thead><tr><th>Parameter</th><th>Required</th><th>Description</th><th>Example</th></tr></thead>
                            <tbody>
                                <tr><td><code>key</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Merchant key provided by PayU during onboarding</td><td>a4vGC2</td></tr>
                                <tr><td><code>salt</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Merchant salt for hash generation (never sent in request)</td><td>hKvGJP28d2...</td></tr>
                                <tr><td><code>txnid</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Unique transaction ID</td><td>PACB_123456</td></tr>
                                <tr><td><code>amount</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Amount to pre-authorize (block)</td><td>500.00</td></tr>
                                <tr><td><code>productinfo</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Product/service description</td><td>Hotel Booking Deposit</td></tr>
                                <tr><td><code>firstname</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Customer's first name</td><td>John</td></tr>
                                <tr><td><code>email</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Customer's email address</td><td>john@example.com</td></tr>
                                <tr><td><code>phone</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Customer's phone number</td><td>9876543210</td></tr>
                                <tr><td><code>surl</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Success callback URL</td><td>https://yoursite.com/success</td></tr>
                                <tr><td><code>furl</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Failure callback URL</td><td>https://yoursite.com/failure</td></tr>
                                <tr><td><code>hash</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>SHA-512 payment hash (auto-computed)</td><td><em>(computed)</em></td></tr>
                                <tr><td><code>pg</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Payment gateway type &mdash; fixed <code>NB</code></td><td>NB</td></tr>
                                <tr><td><code>bankcode</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Bank code from getNetbankingStatus API</td><td>TESTPGNB</td></tr>
                                <tr><td><code>txn_s2s_flow</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>S2S flow identifier &mdash; fixed <code>4</code></td><td>4</td></tr>
                                <tr><td><code>pre_authorize</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Enable pre-authorization &mdash; fixed <code>1</code></td><td>1</td></tr>
                                <tr><td><code>api_version</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>API version for PACB &mdash; fixed <code>6</code></td><td>6</td></tr>
                                <tr><td><code>s2s_client_ip</code></td><td><span class="sm-badge-conditional">Conditional</span></td><td>Source IP of the customer. Required for S2S flow</td><td>10.200.12.12</td></tr>
                                <tr><td><code>s2s_device_info</code></td><td><span class="sm-badge-conditional">Conditional</span></td><td>Customer's device/browser info</td><td>Mozilla/5.0...</td></tr>
                                <tr><td><code>udf1-udf5</code></td><td><span class="sm-badge-optional">Optional</span></td><td>User-defined fields</td><td></td></tr>
                            </tbody>
                        </table>

                        <!-- Sample Response -->
                        <h3 style="margin-top:1.5rem;">Sample Response</h3>
                        <div class="sm-code-block">
                            <div class="sm-code-header"><span>Pre-Auth Success Response</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>{
  "metaData": {
    "message": null,
    "referenceId": "abc123...",
    "txnId": "PACB_123456",
    "txnStatus": "pending",
    "unmappedStatus": "pending"    // After bank auth: "auth" = funds blocked
  },
  "result": {
    "acsTemplate": "PGh0bWw+Li4uPC9odG1sPg==",
    "mihpayid": "403993715537135556"  // Save for capture_transaction
  }
}</code></pre>
                        </div>

                        <h3 style="margin-top:1.5rem;">Try It &mdash; Initiate PACB Pre-Authorization</h3>
                        <div class="sm-interactive-form" id="smNbPacbForm">
                            
                            <!-- Merchant Category Selection -->
                            <div class="sm-section-box" style="margin-bottom:1.5rem; padding:1.25rem; border:1px solid #e2e8f0; border-radius:8px; background:#f8fafc;">
                                <h4 style="color:#374151; margin:0 0 0.75rem 0; font-size:1rem;">Merchant Category</h4>
                                <p style="color:#6b7280; font-size:0.85rem; margin-bottom:1rem;">Select your merchant category to understand which parameters are required for your use case:</p>
                                <div class="sm-form-row">
                                    <div class="sm-form-group" style="flex:1;">
                                        <select id="sm_nb_pacb_merchant_category" onchange="smNbUpdatePacbCategoryInfo(this.value)" style="width:100%;">
                                            <option value="lrs_travel">LRS — Travel & Education (PACB-Import + LRS)</option>
                                            <option value="digital_services">Digital Services — SaaS, MOOCs, Streaming (PACB-Import only)</option>
                                            <option value="physical_goods">Physical Goods — eCommerce Imports (PACB-Import only)</option>
                                        </select>
                                    </div>
                                </div>
                                <div id="sm_nb_pacb_category_info" style="margin-top:0.75rem; padding:0.75rem; border-radius:6px; background:#e8f5e9; font-size:0.85rem;">
                                    <strong>LRS Merchants:</strong> All LRS-specific parameters (lrs_service_type, lrs_mandatory_limit_declaration, lrs_tnc, lrs_tcs_declaration_under_limit, UDF1 PAN, UDF3 DOB) are <strong>MANDATORY</strong>. Enable LRS params below.
                                </div>
                            </div>

                            <!-- Merchant Credentials -->
                            <div class="sm-form-row">
                                <div class="sm-form-group"><label>Merchant Key <span class="required">*</span></label><input type="text" id="sm_nb_pacb_key" value="a4vGC2"></div>
                                <div class="sm-form-group"><label>Merchant Salt <span class="required">*</span></label><input type="password" id="sm_nb_pacb_salt" value="hKvGJP28d2ZUuCRz5BnDag58QBdCxBli"></div>
                            </div>

                            <!-- Basic Payment Details -->
                            <div class="sm-form-row">
                                <div class="sm-form-group">
                                    <label>Transaction ID (txnid) <span class="required">*</span></label>
                                    <div style="display:flex; gap:0.5rem; align-items:center;">
                                        <input type="text" id="sm_nb_pacb_txnid" placeholder="Auto-generated" style="flex:1;">
                                        <button type="button" onclick="document.getElementById('sm_nb_pacb_txnid').value = 'PACB_' + Date.now();" style="padding:0.5rem 1rem; font-size:0.85rem; background:linear-gradient(135deg, #10846D 0%, #024538 100%); color:#fff; border:none; border-radius:6px; cursor:pointer; white-space:nowrap;">Get Txn ID</button>
                                    </div>
                                </div>
                                <div class="sm-form-group"><label>Amount to Block <span class="required">*</span></label><input type="text" id="sm_nb_pacb_amount" value="500.00"></div>
                            </div>
                            <div class="sm-form-row">
                                <div class="sm-form-group"><label>Product Info <span class="required">*</span></label><input type="text" id="sm_nb_pacb_productinfo" value="Hotel Booking Deposit"></div>
                                <div class="sm-form-group">
                                    <label>Bank Code <span class="required">*</span></label>
                                    <select id="sm_nb_pacb_bankcode_select" onchange="document.getElementById('sm_nb_pacb_bankcode').value = this.value;" style="margin-bottom:0.5rem;">
                                        <optgroup label="Test Bank">
                                            <option value="TESTPGNB" selected>TESTPGNB - Test Bank (Sandbox)</option>
                                        </optgroup>
                                        <optgroup label="Private Banks">
                                            <option value="AXIB">AXIB - Axis Bank</option>
                                            <option value="HDFB">HDFB - HDFC Bank</option>
                                            <option value="ICIB">ICIB - ICICI Bank</option>
                                            <option value="YESB">YESB - Yes Bank</option>
                                            <option value="INDB">INDB - IndusInd Bank</option>
                                        </optgroup>
                                        <optgroup label="Public Sector Banks">
                                            <option value="SBIB">SBIB - State Bank of India</option>
                                            <option value="PNBB">PNBB - Punjab National Bank</option>
                                            <option value="BARB">BARB - Bank of Baroda</option>
                                        </optgroup>
                                    </select>
                                    <input type="text" id="sm_nb_pacb_bankcode" value="TESTPGNB" placeholder="Or enter custom bank code" style="font-family:monospace;">
                                </div>
                            </div>

                            <!-- Customer Details -->
                            <div class="sm-form-row">
                                <div class="sm-form-group"><label>First Name <span class="required">*</span></label><input type="text" id="sm_nb_pacb_firstname" value="Test"><small style="color:#6b7280;">For LRS: must match PAN records exactly</small></div>
                                <div class="sm-form-group"><label>Last Name <span class="required">*</span></label><input type="text" id="sm_nb_pacb_lastname" value="User"><small style="color:#6b7280;">Mandatory for S2S integration</small></div>
                            </div>
                            <div class="sm-form-row">
                                <div class="sm-form-group"><label>Email <span class="required">*</span></label><input type="email" id="sm_nb_pacb_email" value="test@example.com"></div>
                                <div class="sm-form-group"><label>Phone <span class="required">*</span></label><input type="text" id="sm_nb_pacb_phone" value="9876543210"></div>
                            </div>

                            <!-- Address Parameters (Required for S2S) -->
                            <div class="sm-section-box" style="margin-top:1.5rem; padding:1.25rem; border:1px solid #e2e8f0; border-radius:8px; border-left:4px solid #3182ce;">
                                <h4 style="color:#3182ce; margin:0 0 0.75rem 0; font-size:1rem;">Address Parameters (Required for S2S)</h4>
                                <div class="sm-form-row">
                                    <div class="sm-form-group"><label>Address Line 1 <span class="required">*</span></label><input type="text" id="sm_nb_pacb_address1" value="123 Main Street"><small style="color:#6b7280;">Mandatory for Merchant Hosted / S2S</small></div>
                                    <div class="sm-form-group"><label>Address Line 2 <span style="color:#6b7280; font-weight:normal;">(Optional)</span></label><input type="text" id="sm_nb_pacb_address2" placeholder="Apartment, suite, etc."><small style="color:#6b7280;">Can be empty or static value</small></div>
                                </div>
                                <div class="sm-form-row">
                                    <div class="sm-form-group"><label>City <span class="required">*</span></label><input type="text" id="sm_nb_pacb_city" value="Mumbai"></div>
                                    <div class="sm-form-group"><label>State <span class="required">*</span></label><input type="text" id="sm_nb_pacb_state" value="Maharashtra"></div>
                                </div>
                                <div class="sm-form-row">
                                    <div class="sm-form-group"><label>Country <span class="required">*</span></label><input type="text" id="sm_nb_pacb_country" value="IN" readonly style="background:#e8f5e9;"><small style="color:#6b7280;">Must be 'IN' (India) - Fixed value</small></div>
                                    <div class="sm-form-group"><label>Zipcode <span class="required">*</span></label><input type="text" id="sm_nb_pacb_zipcode" value="400001"><small style="color:#6b7280;">Billing PIN/ZIP code. Mandatory for cardless EMI.</small></div>
                                </div>
                            </div>

                            <!-- Pre-Authorize Flag -->
                            <div class="sm-form-row" style="margin-top:1rem;">
                                <div class="sm-form-group"><label>Pre-Authorize <span class="required">*</span></label><input type="text" id="sm_nb_pacb_preauth" value="1" readonly style="background:#e8f5e9;"><small style="color:#6b7280;">Set to 1 for PACB flow</small></div>
