                        <!-- Subscription Payment Content (Hidden by default) -->
                        <div id="smNbPacbSubscriptionContent" style="display:none;">
                            <h3 style="color:#10846D;">PACB Subscription Payment</h3>
                            <p style="margin-bottom:1rem; color:#4a5568;">Setup recurring pre-authorizations for subscription-based services. Block and capture funds on a scheduled basis.</p>
                            
                            <div class="sm-flow-diagram" style="margin-bottom:1.5rem;">
                                <div class="sm-flow-step"><span class="sm-flow-num">1</span><span class="sm-flow-label">Register</span></div>
                                <div class="sm-flow-arrow">&rarr;</div>
                                <div class="sm-flow-step"><span class="sm-flow-num">2</span><span class="sm-flow-label">Consent</span></div>
                                <div class="sm-flow-arrow">&rarr;</div>
                                <div class="sm-flow-step"><span class="sm-flow-num">3</span><span class="sm-flow-label">Pre-Auth</span></div>
                                <div class="sm-flow-arrow">&rarr;</div>
                                <div class="sm-flow-step"><span class="sm-flow-num">4</span><span class="sm-flow-label">Capture</span></div>
                                <div class="sm-flow-arrow">&rarr;</div>
                                <div class="sm-flow-step"><span class="sm-flow-num">5</span><span class="sm-flow-label">Recurring</span></div>
                            </div>

                            <div class="sm-info-box" style="margin-bottom:1.5rem; background:#ebf8ff; border:1px solid #90cdf4;">
                                <strong style="color:#2b6cb0;">Subscription vs One-Time PACB</strong>
                                <table style="width:100%; margin-top:0.75rem; font-size:0.9rem;">
                                    <tr><td style="padding:0.5rem 0; border-bottom:1px solid #e2e8f0;"><strong>One-Time:</strong></td><td style="border-bottom:1px solid #e2e8f0;">Single pre-auth &rarr; Single capture</td></tr>
                                    <tr><td style="padding:0.5rem 0;"><strong>Subscription:</strong></td><td>Mandate registration &rarr; Recurring pre-auth &rarr; Scheduled captures</td></tr>
                                </table>
                            </div>

                            <h3>API Reference</h3>
                            <div class="sm-info-box" style="margin-bottom:1rem; background:#f0fff4; border:1px solid #9ae6b4;">
                                <strong>Endpoint:</strong> <code>POST https://test.payu.in/_payment</code>
                            </div>
                            <table class="sm-table">
                                <thead><tr><th>Parameter</th><th>Required</th><th>Description</th><th>Example</th></tr></thead>
                                <tbody>
                                    <tr><td><code>key</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Merchant key</td><td>a4vGC2</td></tr>
                                    <tr><td><code>txnid</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Unique transaction ID</td><td>PACB_SUB_123</td></tr>
                                    <tr><td><code>amount</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Amount to pre-authorize</td><td>1000.00</td></tr>
                                    <tr><td><code>pg</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Payment gateway &mdash; fixed <code>NB</code></td><td>NB</td></tr>
                                    <tr><td><code>bankcode</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Bank code</td><td>TESTPGNB</td></tr>
                                    <tr><td><code>pre_authorize</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Enable pre-auth &mdash; fixed <code>1</code></td><td>1</td></tr>
                                    <tr><td><code>si</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Standing instruction &mdash; fixed <code>1</code></td><td>1</td></tr>
                                    <tr><td><code>si_details</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>JSON with subscription parameters</td><td>{"billingAmount":"1000",...}</td></tr>
                                    <tr><td><code>api_version</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>API version &mdash; fixed <code>7</code></td><td>7</td></tr>
                                    <tr><td><code>hash</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>SHA-512 hash</td><td><em>(computed)</em></td></tr>
                                </tbody>
                            </table>

                            <div class="sm-code-block" style="margin-top:1rem;">
                                <div class="sm-code-header"><span>si_details for Subscription PACB</span><button onclick="smCopyCode(this)">Copy</button></div>
                                <pre><code>{
  "billingAmount": "1000.00",
  "billingCurrency": "INR",
  "billingCycle": "MONTHLY",
  "billingInterval": 1,
  "paymentStartDate": "2026-05-01",
  "paymentEndDate": "2027-04-30",
  "multiCapture": "Y"          // Enable multi-capture per cycle
}</code></pre>
                            </div>

                            <h4 style="margin-top:1.5rem;">Subscription Use Cases</h4>
                            <div class="sm-info-box">
                                <ul style="margin:0; padding-left:1.25rem;">
                                    <li><strong>SaaS subscriptions</strong> - Monthly software license fees</li>
                                    <li><strong>Utility bills</strong> - Recurring electricity/water payments</li>
                                    <li><strong>Insurance premiums</strong> - Monthly/quarterly premium deductions</li>
                                    <li><strong>EMI payments</strong> - Scheduled loan installments</li>
                                </ul>
                            </div>

                            <div class="sm-info-box warning" style="margin-top:1rem;">
                                <strong>&#128712; Note:</strong> For full subscription implementation, use the <strong>NB Mandate (eNACH)</strong> flow which provides comprehensive recurring payment management with mandate registration, status checks, and debit execution.
                                <br><br>
                                <button class="button sm-btn-secondary" onclick="smNbNavTo(document.querySelector('[data-section=sm-nb-mandate]'),'sm-nb-mandate')" style="margin-top:0.5rem;">Go to NB Mandate Flow &rarr;</button>
                            </div>
                        </div><!-- End Subscription Payment Content -->

                        <div class="sm-info-box" style="margin-top:2rem;">
                            <strong>&#128161; PACB Use Cases</strong>
                            <ul>
                                <li><strong>Hotel bookings</strong> - Block amount at check-in, capture actual charges at checkout</li>
                                <li><strong>Car rentals</strong> - Pre-authorize deposit, capture based on actual usage</li>
                                <li><strong>E-commerce</strong> - Block estimated amount, capture actual after shipping calculation</li>
                                <li><strong>Service bookings</strong> - Block full amount, capture partial if service is modified</li>
                            </ul>
                        </div>

                        <div class="sm-info-box warning" style="margin-top:1rem;">
                            <strong>&#9888; Important Notes</strong>
                            <ul>
                                <li>Pre-authorized funds are blocked for a limited period (typically 7-14 days)</li>
                                <li>You must capture before the hold expires, or funds are automatically released</li>
                                <li>You can capture full or partial amount (partial capture releases the remainder)</li>
                                <li>Save the <code>mihpayid</code> from response - you'll need it for capture</li>
                            </ul>
                        </div>

                        <div class="sm-next-btn-wrapper">
                            <button class="button" onclick="smNbNavTo(document.querySelector('[data-section=sm-nb-pacb-redirect]'),'sm-nb-pacb-redirect')">Next: Step 2 - Handle Response &rarr;</button>
                        </div>
                    </div>

                    <!-- Section: NB PACB Handle Response -->
                    <div class="seamless-section" id="sm-nb-pacb-redirect">
                        <h2>Step 2: Handle PACB Response</h2>
                        <div class="sm-step-guide">
                            <div class="sm-guide-overview">
                                <h3>Overview</h3>
                                <p>After calling the PACB <code>_payment</code> API with <code>pre_authorize=1</code>, the customer completes bank authentication. The funds are then <strong>blocked</strong> (not debited) in their account.</p>
                            </div>
                        </div>

                        <div class="sm-info-box" style="background:#ebf8ff; border:1px solid #90cdf4;">
                            <strong style="color:#2b6cb0;">&#128274; Pre-Authorization vs Regular Payment</strong>
                            <table style="width:100%; margin-top:0.5rem; font-size:0.9rem; color:#2d3748;">
                                <tr><td style="padding:4px 0; border-bottom:1px solid #e2e8f0;"><strong>Regular Payment:</strong></td><td style="border-bottom:1px solid #e2e8f0;"><code>unmappedstatus = captured</code> (funds debited)</td></tr>
                                <tr><td style="padding:4px 0;"><strong>PACB Pre-Auth:</strong></td><td><code>unmappedstatus = auth</code> (funds blocked)</td></tr>
                            </table>
                        </div>

                        <div class="sm-next-btn-wrapper">
                            <button class="button" onclick="smNbNavTo(document.querySelector('[data-section=sm-nb-pacb-verify]'),'sm-nb-pacb-verify')">Next: Step 3 - Validate Auth &rarr;</button>
                        </div>
                    </div>

                    <!-- Section: NB PACB Verify Auth -->
                    <div class="seamless-section" id="sm-nb-pacb-verify">
                        <h2>Step 3: Validate Pre-Authorization</h2>
                        <div class="sm-step-guide">
                            <div class="sm-guide-overview">
                                <h3>Overview</h3>
                                <p>Before capturing funds, verify the pre-authorization was successful. Use <code>verify_payment</code> API and check that <code>unmappedstatus</code> is <strong>"auth"</strong>.</p>
                            </div>
                        </div>

                        <div class="sm-info-box" style="background:#f0fff4; border:1px solid #9ae6b4;">
                            <strong style="color:#276749;">&#10003; Expected Response for Successful Pre-Auth</strong>
                            <ul style="margin:0.5rem 0 0; padding-left:1.25rem; color:#2d3748; line-height:1.8;">
                                <li><code>status</code> = "success"</li>
                                <li><code>unmappedstatus</code> = <strong>"auth"</strong></li>
                                <li><code>mihpayid</code> = (save this for capture)</li>
                            </ul>
                        </div>

                        <div class="sm-info-box warning" style="margin-top:1rem; background:#fff5f5; border:1px solid #feb2b2;">
                            <strong style="color:#c53030;">&#9888; If unmappedstatus = "captured"</strong>
                            <p style="margin:0.5rem 0 0; color:#2d3748;">This means PACB is <strong>not enabled</strong> on your account. The funds were immediately debited instead of blocked. Contact your PayU KAM to enable PACB.</p>
                        </div>

                        <div class="sm-next-btn-wrapper">
                            <button class="button" onclick="smNbNavTo(document.querySelector('[data-section=sm-nb-capture]'),'sm-nb-capture')">Next: Step 4 - Capture Funds &rarr;</button>
                        </div>
                    </div>

                    <!-- Section: NB Capture -->
                    <div class="seamless-section" id="sm-nb-capture">
                        <h2>Step 4: Capture PACB Funds</h2>

                        <div class="sm-info-box warning" style="margin-bottom:1.5rem; border-left:4px solid #ff9800; background:rgba(255,152,0,0.08); padding:1.25rem;">
                            <strong>&#9888; Before you capture:</strong> Ensure the original transaction was truly pre-authorized.
                            Verify the transaction first &mdash; <code>unmappedstatus</code> must be <strong>"auth"</strong>.
                            If it shows <strong>"captured"</strong>, the funds were already debited and capture will fail with
                            <strong>"Delayed capture not allowed"</strong>.
                        </div>

                        <div class="sm-step-guide">
                            <div class="sm-guide-overview">
                                <h3>Overview</h3>
                                <p>After a successful pre-authorization, use the <code>capture_transaction</code> API to capture (debit) the blocked funds. You can capture the full amount or a partial amount.</p>
                            </div>

                            <div class="sm-guide-flow">
                                <h3>Capture Flow</h3>
                                <div class="sm-flow-diagram">
                                    <div class="sm-flow-step"><span class="sm-flow-num">1</span><span class="sm-flow-label">Get mihpayid</span></div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step"><span class="sm-flow-num">2</span><span class="sm-flow-label">Call capture_transaction</span></div>
                                    <div class="sm-flow-arrow">&rarr;</div>
                                    <div class="sm-flow-step"><span class="sm-flow-num">3</span><span class="sm-flow-label">Funds Debited</span></div>
                                </div>
                            </div>
                        </div>

                        <!-- API Reference -->
                        <h3>API Reference</h3>
                        <div class="sm-info-box" style="margin-bottom:1rem; background:#f0fff4; border:1px solid #9ae6b4;">
                            <strong>Endpoint:</strong> <code>POST https://test.payu.in/merchant/postservice.php?form=2</code>
                        </div>
                        <table class="sm-table">
                            <thead><tr><th>Parameter</th><th>Required</th><th>Description</th><th>Example</th></tr></thead>
                            <tbody>
                                <tr><td><code>key</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Merchant key provided by PayU during onboarding</td><td>a4vGC2</td></tr>
                                <tr><td><code>command</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>API command &mdash; fixed <code>capture_transaction</code></td><td>capture_transaction</td></tr>
                                <tr><td><code>var1</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>PayU transaction ID (mihpayid)</td><td>403993715537135556</td></tr>
                                <tr><td><code>var2</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Unique capture request ID</td><td>CAP_123456</td></tr>
                                <tr><td><code>var3</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Amount to capture (can be partial)</td><td>500.00</td></tr>
                                <tr><td><code>hash</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>SHA-512 hash (auto-computed from key, command, var1, salt)</td><td><em>(computed)</em></td></tr>
                            </tbody>
                        </table>

                        <div class="sm-code-block" style="margin-top:1rem;">
                            <div class="sm-code-header"><span>Hash Formula</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>sha512(key|command|var1|salt)

Example:
sha512(a4vGC2|capture_transaction|403993715537135556|YourSaltHere)</code></pre>
                        </div>

                        <!-- Sample Response -->
                        <h3 style="margin-top:1.5rem;">Sample Response</h3>
                        <div class="sm-code-block">
                            <div class="sm-code-header"><span>Capture Success Response</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>{
  "status": 1,
  "msg": "Transaction captured successfully",
  "mihpayid": "403993715537135556",
  "bank_ref_num": "450699821592111537",
  "captured_amount": "500.00",
  "original_amount": "500.00"
}</code></pre>
                        </div>

                        <h3 style="margin-top:1.5rem;">Try It &mdash; Capture Pre-Authorized Funds</h3>
                        <div class="sm-interactive-form" id="smNbCaptureForm">
                            <div class="sm-sim-toggle" style="margin-bottom:1rem; padding:1rem 1.25rem; border-radius:8px; background:linear-gradient(135deg, #667eea 0%, #764ba2 100%); border:none; display:flex; align-items:center; gap:1rem; flex-wrap:wrap; box-shadow:0 2px 8px rgba(102,126,234,0.3);">
                                <label class="sm-switch" style="flex-shrink:0;">
                                    <input type="checkbox" id="sm_nb_capture_simulate" checked onchange="smNbToggleCaptureSim(this)">
                                    <span class="sm-switch-slider"></span>
                                </label>
                                <div style="flex:1;">
                                    <div style="font-size:1rem; color:#fff; font-weight:600;">&#9889; Simulation Mode (Enabled)</div>
                                    <div style="font-size:0.85rem; color:rgba(255,255,255,0.85); margin-top:0.25rem;">Simulate a successful capture response without real API call.</div>
                                </div>
                            </div>
                            <div class="sm-form-row">
                                <div class="sm-form-group"><label>Merchant Key  <span class="required">*</span></label><input type="text" id="sm_nb_capture_key" value="a4vGC2"></div>
                                <div class="sm-form-group"><label>Merchant Salt  <span class="required">*</span></label><input type="password" id="sm_nb_capture_salt" value="hKvGJP28d2ZUuCRz5BnDag58QBdCxBli"></div>
                            </div>
                            <div class="sm-form-row">
                                <div class="sm-form-group"><label>PayU ID (mihpayid)  <span class="required">*</span></label><input type="text" id="sm_nb_capture_mihpayid" placeholder="From pre-auth response"></div>
                                <div class="sm-form-group"><label>Amount to Capture  <span class="required">*</span></label><input type="text" id="sm_nb_capture_amount" placeholder="e.g., 500.00"></div>
                            </div>
                            <div class="sm-form-actions">
                                <button class="button sm-btn-secondary" onclick="smNbPreviewCaptureRequest()">Preview Request</button>
                                <button class="button sm-btn-primary" onclick="smNbSendCaptureRequest()">Capture Funds &rarr;</button>
                            </div>
                        </div>
                        <div id="smNbCaptureReqRes" class="sm-req-res-panel" style="display:none;">
                            <div class="sm-req-res-grid">
                                <div class="sm-req-panel"><div class="sm-panel-header"><span>Request Sent</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div><pre><code id="smNbCaptureRequestView"></code></pre></div>
                                <div class="sm-res-panel"><div class="sm-panel-header"><span>Response Received</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div><div id="smNbCaptureStatusBadge" class="sm-status-badge"></div><pre><code id="smNbCaptureResponseView"></code></pre></div>
                            </div>
                            <div class="sm-response-guide" id="smNbCaptureResponseGuide" style="display:none;"><h4>Understanding the Response</h4><div id="smNbCaptureResponseExplain"></div></div>
                            <div class="sm-curl-section"><div class="sm-panel-header"><span>cURL Command</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div><pre><code id="smNbCaptureCurlView"></code></pre></div>
                        </div>

                        <div class="sm-info-box" style="margin-top:2rem;">
                            <strong>&#128161; Capture Options</strong>
                            <ul>
                                <li><strong>Full Capture:</strong> Enter the full pre-authorized amount to debit everything</li>
                                <li><strong>Partial Capture:</strong> Enter a lesser amount - the remainder is automatically released</li>
                                <li><strong>Multiple Captures:</strong> Some banks support multi-capture (contact PayU for enablement)</li>
                            </ul>
                        </div>

                        <div class="sm-next-btn-wrapper">
                            <button class="button" onclick="smNbNavTo(document.querySelector('[data-section=sm-nb-subscription]'),'sm-nb-subscription')">Next: NB Subscription &rarr;</button>
                        </div>
                    </div>

                    <!-- Section: NB Subscription -->
                    <div class="seamless-section" id="sm-nb-subscription">
                        <h2>Step 1: Register Net Banking Mandate (eNACH)</h2>

                        <!-- API Reference -->
                        <h3>API Reference</h3>
                        <div class="sm-info-box" style="margin-bottom:1rem; background:#f0fff4; border:1px solid #9ae6b4;">
                            <strong>Endpoint:</strong> <code>POST https://test.payu.in/_payment</code> (Test) | <code>POST https://secure.payu.in/_payment</code> (Production)
                        </div>
                        <table class="sm-table">
                            <thead><tr><th>Parameter</th><th>Required</th><th>Description</th><th>Example</th></tr></thead>
                            <tbody>
                                <tr><td><code>key</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Merchant key provided by PayU during onboarding</td><td>a4vGC2</td></tr>
                                <tr><td><code>txnid</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Unique transaction ID generated by the merchant. PayU rejects duplicates.</td><td>MANDATE_1713200000</td></tr>
                                <tr><td><code>amount</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Transaction amount. For eNACH, use <code>1.00</code> (actual billing amount is in si_details).</td><td>1.00</td></tr>
                                <tr><td><code>productinfo</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Brief product description (max 100 chars)</td><td>SIP Investment</td></tr>
                                <tr><td><code>firstname</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Customer first name (max 60 chars)</td><td>Test</td></tr>
                                <tr><td><code>lastname</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Customer last name (max 60 chars)</td><td>User</td></tr>
                                <tr><td><code>email</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Customer email address (max 50 chars)</td><td>test@example.com</td></tr>
                                <tr><td><code>phone</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Customer phone number</td><td>9876543210</td></tr>
                                <tr><td><code>surl</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Success callback URL</td><td>https://yoursite.com/callback.php</td></tr>
                                <tr><td><code>furl</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Failure callback URL</td><td>https://yoursite.com/callback.php</td></tr>
                                <tr><td><code>hash</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; SHA-512 payment hash (auto-computed)</td><td><em>(computed)</em></td></tr>
                                <tr><td><code>pg</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Payment gateway type &mdash; fixed <code>ENACH</code></td><td>ENACH</td></tr>
                                <tr><td><code>bankcode</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; eNACH bank code from getNetbankingStatus API</td><td>ICICENCC</td></tr>
                                <tr><td><code>si</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Must be <code>1</code> to enable Standing Instruction / Recurring Payment</td><td>1</td></tr>
                                <tr><td><code>si_details</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; JSON with billing cycle details (see si_details breakdown below)</td><td><em>(see below)</em></td></tr>
                                <tr><td><code>beneficiarydetail</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; JSON with beneficiary bank account details (see beneficiarydetail breakdown below)</td><td><em>(see below)</em></td></tr>
                                <tr><td><code>api_version</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; API version. Must be <code>7</code> so si_details is included in hash</td><td>7</td></tr>
                                <tr><td><code>txn_s2s_flow</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Integer &mdash; S2S flow identifier &mdash; fixed <code>4</code></td><td>4</td></tr>
                                <tr><td><code>free_trial</code></td><td><span class="sm-badge-optional">Optional</span></td><td>String &mdash; Enable free trial. When set to <code>1</code>, a zero-value auth is performed to register the mandate without charging the customer.</td><td>1</td></tr>
                                <tr><td><code>udf1</code></td><td><span class="sm-badge-optional">Optional</span></td><td>String &mdash; User-defined field 1</td><td></td></tr>
                                <tr><td><code>udf2</code></td><td><span class="sm-badge-optional">Optional</span></td><td>String &mdash; User-defined field 2</td><td></td></tr>
                                <tr><td><code>udf3</code></td><td><span class="sm-badge-optional">Optional</span></td><td>String &mdash; User-defined field 3</td><td></td></tr>
                                <tr><td><code>udf4</code></td><td><span class="sm-badge-optional">Optional</span></td><td>String &mdash; User-defined field 4</td><td></td></tr>
                                <tr><td><code>udf5</code></td><td><span class="sm-badge-optional">Optional</span></td><td>String &mdash; User-defined field 5</td><td></td></tr>
                            </tbody>
                        </table>

                        <h3>si_details JSON Parameters</h3>
                        <table class="sm-table">
                            <thead><tr><th>Field</th><th>Required</th><th>Description</th><th>Example</th></tr></thead>
                            <tbody>
                                <tr><td><code>billingAmount</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Maximum amount for each recurring debit</td><td>1000.00</td></tr>
                                <tr><td><code>billingCurrency</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Currency &mdash; must be <code>INR</code></td><td>INR</td></tr>
                                <tr><td><code>billingCycle</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Billing frequency: <code>DAILY</code>, <code>WEEKLY</code>, <code>MONTHLY</code>, <code>YEARLY</code>, or <code>ADHOC</code></td><td>MONTHLY</td></tr>
                                <tr><td><code>billingInterval</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Integer &mdash; Coupled with billingCycle. e.g. MONTHLY &amp; 3 = charge every 3 months</td><td>1</td></tr>
                                <tr><td><code>paymentStartDate</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Mandate start date in <code>YYYY-MM-DD</code>. For eNACH, must be tomorrow or later.</td><td>2026-04-16</td></tr>
                                <tr><td><code>paymentEndDate</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Mandate end date in <code>YYYY-MM-DD</code></td><td>2027-04-16</td></tr>
                            </tbody>
                        </table>

                        <h3>beneficiarydetail JSON Parameters</h3>
                        <table class="sm-table">
                            <thead><tr><th>Field</th><th>Required</th><th>Description</th><th>Example</th></tr></thead>
                            <tbody>
                                <tr><td><code>beneficiaryName</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Account holder name as per bank records</td><td>Test User</td></tr>
                                <tr><td><code>beneficiaryAccountNumber</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Bank account number of the customer</td><td>1234567890123456</td></tr>
                                <tr><td><code>beneficiaryAccountType</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Account type: <code>SAVINGS</code> or <code>CURRENT</code></td><td>SAVINGS</td></tr>
                                <tr><td><code>beneficiaryIfscCode</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; 11-digit IFSC code of the customer&rsquo;s bank branch</td><td>ICIC0001234</td></tr>
                            </tbody>
                        </table>

                        <!-- Documentation Links -->
                        <div class="sm-doc-links" style="margin-bottom:1.5rem; padding:1rem; background:linear-gradient(135deg, #ecfdf5 0%, #d1fae5 100%); border:1px solid #34d399; border-radius:8px;">
                            <strong style="color:#065f46;">&#128213; Documentation</strong>
                            <div style="margin-top:0.5rem; display:flex; flex-wrap:wrap; gap:0.75rem;">
                                <a href="https://docs.payu.in/reference/netbanking-recurring-payment-consent-transaction" target="_blank" style="color:#047857; text-decoration:none; font-size:0.9rem;">&#128279; NB Consent Transaction API</a>
                                <a href="https://docs.payu.in/reference/recurring_payment_api" target="_blank" style="color:#047857; text-decoration:none; font-size:0.9rem;">&#128279; Recurring Payment (si_transaction) API</a>
                            </div>
                        </div>

                        <div class="sm-step-guide">
                            <div class="sm-guide-overview">
                                <h3>Overview</h3>
                                <p>Register recurring payment mandates via eNACH (electronic National Automated Clearing House) for Net Banking. The customer authorizes a standing instruction for future debits from their bank account.</p>
                            </div>
                            <div class="sm-guide-prereqs">
                                <h3>Prerequisites</h3>
                                <div class="sm-prereq-list">
                                    <div class="sm-prereq-item"><span class="sm-prereq-check">&#10003;</span> PayU Merchant Key &amp; Salt</div>
                                    <div class="sm-prereq-item"><span class="sm-prereq-check">&#10003;</span> eNACH enabled on your merchant account</div>
                                    <div class="sm-prereq-item"><span class="sm-prereq-check">&#10003;</span> Bank that supports eNACH mandates</div>
                                </div>
                            </div>
                        </div>

                        <h4>Hash Formula</h4>
                        <div class="sm-code-block">
                            <div class="sm-code-header"><span>Mandate Registration Hash</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>sha512(key|txnid|amount|productinfo|firstname|email|udf1|udf2|udf3|udf4|udf5||||||si_details|SALT)
// Note: 11 pipes between email and si_details, then si_details, then salt</code></pre>
                        </div>

                        <h4>si_details &amp; beneficiarydetail JSON Structures</h4>
                        <div class="sm-code-block">
                            <div class="sm-code-header"><span>JSON Parameters</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>// si_details structure:
{
  "billingAmount": "1000.00",
  "billingCurrency": "INR",
  "billingCycle": "MONTHLY",
  "billingInterval": 1,
  "paymentStartDate": "2026-04-06",
  "paymentEndDate": "2027-04-06"
}

// beneficiarydetail structure (MANDATORY for Net Banking):
{
  "beneficiaryName": "Customer Name",
  "beneficiaryAccountNumber": "1234567890",
  "beneficiaryAccountType": "SAVINGS",
  "beneficiaryIfscCode": "ICIC0001234"
}</code></pre>
                        </div>

                        <h3>Try It &mdash; Register Mandate</h3>
                        <div class="sm-interactive-form" id="smNbMandateRegForm">
