                                <tr><td><code>key</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; Merchant key provided by PayU during onboarding</td><td>a4vGC2</td></tr>
                                <tr><td><code>command</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; API command &mdash; fixed <code>NB_mandate_status</code></td><td>NB_mandate_status</td></tr>
                                <tr><td><code>var1</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; JSON string containing <code>authpayuid</code> and <code>requestId</code> (see var1 breakdown below)</td><td><em>(see below)</em></td></tr>
                                <tr><td><code>hash</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; SHA-512 hash &mdash; <code>sha512(key|NB_mandate_status|var1|salt)</code></td><td><em>(computed)</em></td></tr>
                            </tbody>
                        </table>

                        <h3 style="margin-top:1.5rem;">var1 JSON Parameters</h3>
                        <table class="sm-table">
                            <thead><tr><th>Field</th><th>Required</th><th>Description</th><th>Example</th></tr></thead>
                            <tbody>
                                <tr><td><code>authpayuid</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; The <code>mihpayid</code> received from mandate registration (Step 2 &mdash; Handle Response)</td><td>10731087875</td></tr>
                                <tr><td><code>requestId</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>String &mdash; A unique request identifier for this status check call</td><td>1892432156</td></tr>
                            </tbody>
                        </table>

                        <h3 style="margin-top:1.5rem;">Response Parameters</h3>
                        <table class="sm-table">
                            <thead><tr><th>Parameter</th><th>Description</th><th>Example</th></tr></thead>
                            <tbody>
                                <tr><td><code>status</code></td><td>String &mdash; Mandate status (see status values below)</td><td>SUCCESS</td></tr>
                                <tr><td><code>action</code></td><td>String &mdash; API action performed</td><td>NB_mandate_status</td></tr>
                                <tr><td><code>authpayuid</code></td><td>String &mdash; PayU&rsquo;s unique mandate reference ID</td><td>10731087875</td></tr>
                                <tr><td><code>amount</code></td><td>String &mdash; Mandate billing amount</td><td>100.00</td></tr>
                                <tr><td><code>mandateStartDate</code></td><td>String &mdash; Mandate start date</td><td>2026-04-16</td></tr>
                                <tr><td><code>mandateEndDate</code></td><td>String &mdash; Mandate end date</td><td>2027-04-16</td></tr>
                            </tbody>
                        </table>

                        <div class="sm-step-guide">
                            <div class="sm-guide-overview">
                                <h3>Overview</h3>
                                <p>Use the <code>NB_mandate_status</code> API to verify the current state of the eNACH mandate. This helps you understand if the mandate is active and ready for debit execution.</p>
                            </div>
                            <div class="sm-guide-prereqs">
                                <h3>Prerequisites</h3>
                                <div class="sm-prereq-list">
                                    <div class="sm-prereq-item"><span class="sm-prereq-check">&#10003;</span> <code>authpayuid</code> (mihpayid) from mandate registration response</div>
                                    <div class="sm-prereq-item"><span class="sm-prereq-check">&#10003;</span> Unique <code>requestId</code> for this status check</div>
                                </div>
                            </div>
                        </div>

                        <h4>Hash Formula</h4>
                        <div class="sm-code-block">
                            <div class="sm-code-header"><span>NB_mandate_status Hash</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>sha512(key|command|var1|salt)
sha512(merchantKey|NB_mandate_status|{"authpayuid":"...","requestId":"..."}|merchantSalt)</code></pre>
                        </div>

                        <h4>API Request Format</h4>
                        <div class="sm-code-block">
                            <div class="sm-code-header"><span>NB_mandate_status Request</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>// Endpoint: https://test.payu.in/merchant/postservice.php?form=2

{
  "key": "merchant_key",
  "command": "NB_mandate_status",
  "var1": "{\"authpayuid\":\"10731087875\",\"requestId\":\"1892432156\"}",
  "hash": "sha512(key|NB_mandate_status|var1|salt)"
}</code></pre>
                        </div>

                        <h4>Sample Response</h4>
                        <div class="sm-code-block">
                            <div class="sm-code-header"><span>Success Response</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>{
  "status": "SUCCESS",
  "action": "NB_mandate_status",
  "authpayuid": "10731087875",
  "amount": "100.00",
  "mandateStartDate": "2022-07-19",
  "mandateEndDate": "2023-12-20"
}</code></pre>
                        </div>

                        <div class="sm-info-box" style="margin-top:1rem; background:#f0fff4; border:1px solid #9ae6b4;">
                            <strong style="color:#276749;">&#10003; Mandate Status Values</strong>
                            <table style="width:100%; margin-top:0.5rem; font-size:0.9rem; color:#2d3748;">
                                <tr><td style="padding:4px 0; border-bottom:1px solid #c6f6d5;"><code>INITIATED</code></td><td style="border-bottom:1px solid #c6f6d5;">Mandate registration initiated</td></tr>
                                <tr><td style="padding:4px 0; border-bottom:1px solid #c6f6d5;"><code>SUCCESS</code></td><td style="border-bottom:1px solid #c6f6d5;">Mandate is active and ready for debits</td></tr>
                                <tr><td style="padding:4px 0; border-bottom:1px solid #c6f6d5;"><code>FAILED</code></td><td style="border-bottom:1px solid #c6f6d5;">Mandate registration failed</td></tr>
                                <tr><td style="padding:4px 0; border-bottom:1px solid #c6f6d5;"><code>CANCEL_INITIATED</code></td><td style="border-bottom:1px solid #c6f6d5;">Cancellation request initiated</td></tr>
                                <tr><td style="padding:4px 0; border-bottom:1px solid #c6f6d5;"><code>CANCEL_PENDING</code></td><td style="border-bottom:1px solid #c6f6d5;">Cancellation pending at bank</td></tr>
                                <tr><td style="padding:4px 0; border-bottom:1px solid #c6f6d5;"><code>CANCEL_SUCCESS</code></td><td style="border-bottom:1px solid #c6f6d5;">Mandate successfully cancelled</td></tr>
                                <tr><td style="padding:4px 0;"><code>CANCEL_FAILED</code></td><td>Cancellation request failed</td></tr>
                            </table>
                        </div>

                        <h3>Try It &mdash; Check Mandate Status</h3>
                        <div class="sm-interactive-form" id="smNbMandateStatusForm">
                            <div class="sm-form-row">
                                <div class="sm-form-group"><label>Merchant Key <span class="required">*</span></label><input type="text" id="sm_nb_mandate_status_key" value="a4vGC2"></div>
                                <div class="sm-form-group"><label>Merchant Salt <span class="required">*</span></label><input type="text" id="sm_nb_mandate_status_salt" value="hKvGJP28d2ZUuCRz5BnDag58QBdCxBli" autocomplete="off" style="-webkit-text-security: disc;"></div>
                            </div>
                            <div class="sm-form-row">
                                <div class="sm-form-group"><label>Auth PayU ID (mihpayid) <span class="required">*</span></label><input type="text" id="sm_nb_mandate_status_authpayuid" placeholder="e.g., 10731087875" oninput="smNbAutoGenerateMandateRequestId()"></div>
                                <div class="sm-form-group"><label>Request ID <span class="required">*</span></label><input type="text" id="sm_nb_mandate_status_requestid" placeholder="Unique request ID"></div>
                            </div>
                            <div class="sm-form-actions">
                                <button class="button sm-btn-fill-sample" onclick="smNbFillSampleMandateStatus()">&#9889; Fill Sample Data</button>
                                <button class="button sm-btn-secondary" onclick="smNbPreviewMandateStatusRequest()">Preview Request</button>
                                <button class="button sm-btn-primary" onclick="smNbSendMandateStatusRequest()">Check Status &rarr;</button>
                            </div>
                        </div>

                        <div id="smNbMandateStatusReqRes" class="sm-req-res-panel" style="display:none;">
                            <div class="sm-req-res-grid">
                                <div class="sm-req-panel"><div class="sm-panel-header"><span>Request Sent</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div><pre><code id="smNbMandateStatusRequestView"></code></pre></div>
                                <div class="sm-res-panel"><div class="sm-panel-header"><span>Response Received</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div><div id="smNbMandateStatusStatusBadge" class="sm-status-badge"></div><pre><code id="smNbMandateStatusResponseView"></code></pre></div>
                            </div>
                            <div class="sm-curl-section"><div class="sm-panel-header"><span>cURL Command</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div><pre><code id="smNbMandateStatusCurlView"></code></pre></div>
                        </div>

                        <div class="sm-next-btn-wrapper">
                            <button class="button" onclick="smNbNavTo(document.querySelector('[data-section=sm-nb-mandate-execute]'),'sm-nb-mandate-execute')">Next: Step 4 - Execute Debit &rarr;</button>
                        </div>
                    </div>

                    <!-- Section: NB Mandate Execute -->
                    <div class="seamless-section" id="sm-nb-mandate-execute">
                        <h2>Step 4: Execute Recurring Debit</h2>
                        <div class="sm-step-guide">
                            <div class="sm-guide-overview">
                                <h3>Overview</h3>
                                <p>Once the mandate status is <strong>SUCCESS</strong>, you can execute recurring debits using the <code>si_transaction</code> API. This is a server-to-server call that doesn't require customer 2FA.</p>
                                <p><a href="https://docs.payu.in/reference/recurring_payment_api" target="_blank" style="color:#3182ce;">&#128279; PayU API Reference</a></p>
                            </div>
                        </div>

                        <h3>Required Parameters for API</h3>
                        <div class="sm-info-box" style="margin-bottom:1rem; background:#f0fff4; border:1px solid #9ae6b4;">
                            <strong>Endpoint:</strong> <code>POST https://test.payu.in/merchant/postservice.php?form=2</code>
                        </div>
                        <table class="sm-table">
                            <thead><tr><th>Parameter</th><th>Required</th><th>Description</th><th>Example</th></tr></thead>
                            <tbody>
                                <tr><td><code>form</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Fixed value for API type</td><td>2</td></tr>
                                <tr><td><code>key</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Merchant key provided by PayU during onboarding</td><td>a4vGC2</td></tr>
                                <tr><td><code>command</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>API command &mdash; fixed <code>si_transaction</code></td><td>si_transaction</td></tr>
                                <tr><td><code>var1</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>JSON object with transaction details (see below)</td><td>{"authpayuid":...}</td></tr>
                                <tr><td><code>hash</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>SHA-512 hash (auto-computed from key, command, var1, salt)</td><td><em>(computed)</em></td></tr>
                            </tbody>
                        </table>

                        <h4 style="margin-top:1.5rem;">var1 JSON Structure</h4>
                        <div class="sm-code-block">
                            <div class="sm-code-header"><span>si_transaction var1 JSON</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>{
  "authpayuid": "403993715537190503",      // mihpayid from mandate registration
  "invoiceDisplayNumber": "INV123456",     // Invoice/reference number
  "amount": "100.00",                       // Debit amount
  "txnid": "DEBIT_1775821582262",          // Unique txnid for THIS debit
  "phone": "9999999999",                    // Customer phone
  "email": "test@example.com",              // Customer email
  "udf2": "",                               // User defined field 2
  "udf3": "",                               // User defined field 3
  "udf4": "",                               // User defined field 4
  "udf5": ""                                // User defined field 5
}</code></pre>
                        </div>

                        <div class="sm-code-block" style="margin-top:1rem;">
                            <div class="sm-code-header"><span>Hash Formula</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>sha512(key|si_transaction|var1|salt)

Example:
sha512(a4vGC2|si_transaction|{"authpayuid":"6611192557","invoiceDisplayNumber":"12345678910",...}|YourSaltHere)</code></pre>
                        </div>

                        <h3 style="margin-top:2rem;">Try It &mdash; Execute Debit</h3>
                        <div class="sm-interactive-form" id="smNbMandateExecuteForm">
                            <div class="sm-form-row">
                                <div class="sm-form-group"><label>Merchant Key <span class="required">*</span></label><input type="text" id="sm_nb_mandate_exec_key" value="a4vGC2"></div>
                                <div class="sm-form-group"><label>Merchant Salt <span class="required">*</span></label><input type="password" id="sm_nb_mandate_exec_salt" value="hKvGJP28d2ZUuCRz5BnDag58QBdCxBli"></div>
                            </div>
                            <div class="sm-form-row">
                                <div class="sm-form-group"><label>authpayuid (mihpayid) <span class="required">*</span></label><input type="text" id="sm_nb_mandate_exec_token" placeholder="From mandate registration response" oninput="smNbAutoGenerateExecTxnId()"></div>
                                <div class="sm-form-group"><label>amount <span class="required">*</span></label><input type="text" id="sm_nb_mandate_exec_amount" value="100.00" placeholder="Cannot exceed billingAmount"></div>
                            </div>
                            <div class="sm-form-row">
                                <div class="sm-form-group"><label>Transaction ID <span class="required">*</span></label>
                                    <div style="display:flex; gap:0.5rem; align-items:center;">
                                        <input type="text" id="sm_nb_mandate_exec_txnid" placeholder="Auto-generated unique transaction ID" style="flex:1;">
                                        <button type="button" onclick="document.getElementById('sm_nb_mandate_exec_txnid').value = 'DEBIT_' + Date.now();" style="padding:0.5rem 1rem; font-size:0.85rem; background:linear-gradient(135deg, #10846D 0%, #024538 100%); color:#fff; border:none; border-radius:6px; cursor:pointer; white-space:nowrap;">Get Txn ID</button>
                                    </div>
                                </div>
                                <div class="sm-form-group">&nbsp;</div>
                            </div>
                            <div class="sm-info-box" style="margin-bottom:1rem; background:#e6f7ff; border:1px solid #91d5ff; border-radius:8px; padding:1rem;">
                                <strong style="color:#0050b3;">&#9432; Note:</strong>
                                <p style="margin:0.5rem 0 0; color:#003a8c; font-size:0.9rem;">The Execute Debit (si_transaction) API will only work <strong>after 24 hours</strong> from mandate registration. This is a PayU policy to allow mandate activation and bank confirmation.</p>
                            </div>
                            <div class="sm-form-actions">
                                <button class="button sm-btn-secondary" onclick="smNbPreviewMandateExecRequest()">Preview Request</button>
                                <button class="button sm-btn-primary" onclick="smNbSendMandateExecRequest()">Execute Debit &rarr;</button>
                            </div>
                        </div>

                        <div id="smNbMandateExecReqRes" class="sm-req-res-panel" style="display:none;">
                            <div class="sm-req-res-grid">
                                <div class="sm-req-panel"><div class="sm-panel-header"><span>Request Sent</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div><pre><code id="smNbMandateExecRequestView"></code></pre></div>
                                <div class="sm-res-panel"><div class="sm-panel-header"><span>Response Received</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div><div id="smNbMandateExecStatusBadge" class="sm-status-badge"></div><pre><code id="smNbMandateExecResponseView"></code></pre></div>
                            </div>
                            <div class="sm-curl-section"><div class="sm-panel-header"><span>cURL Command</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div><pre><code id="smNbMandateExecCurlView"></code></pre></div>
                        </div>

                        <div class="sm-info-box warning" style="margin-top:1.5rem; background:#fffaf0; border:1px solid #fbd38d;">
                            <strong style="color:#c05621;">&#9888; Important Notes</strong>
                            <ul style="margin:0.5rem 0 0; padding-left:1.25rem; color:#2d3748; line-height:1.8;">
                                <li>Debit amount cannot exceed the <code>billingAmount</code> in mandate</li>
                                <li>Customer is notified via SMS/email before each debit</li>
                                <li>Failed debits should be retried after 24-48 hours</li>
                                <li>Maintain debit history for reconciliation</li>
                            </ul>
                        </div>

                        <div class="sm-info-box" style="margin-top:1rem; background:#fff5f5; border:1px solid #feb2b2;">
                            <strong style="color:#c53030;">&#128270; Troubleshooting "Some error occurred"</strong>
                            <ul style="margin:0.5rem 0 0; padding-left:1.25rem; color:#2d3748; line-height:1.8;">
                                <li><strong>Invalid authpayuid:</strong> The mihpayid must be from a successful mandate registration</li>
                                <li><strong>Mandate not active:</strong> The mandate must be in "active" state (not pending/cancelled)</li>
                                <li><strong>Test environment:</strong> Test merchants may not have SI enabled - use "Simulate Response" checkbox</li>
                                <li><strong>Amount exceeds limit:</strong> Debit amount cannot exceed billingAmount from mandate registration</li>
                            </ul>
                        </div>

                        <div class="sm-next-btn-wrapper">
                            <button class="button" onclick="smNbNavTo(document.querySelector('[data-section=sm-nb-status]'),'sm-nb-status')">Next: Get Bank Status &rarr;</button>
                        </div>
                    </div>

                    <!-- Section: NB Get Bank Status -->
                    <div class="seamless-section" id="sm-nb-status">
                        <h2>Step 1: Get Active Net Banking List</h2>
                        
                        <!-- GUIDE: Overview -->
                        <div class="sm-step-guide">
                            <div class="sm-guide-overview">
                                <h3>Overview</h3>
                                <p>Use the <code>getNetbankingStatus</code> API to fetch the list of active Net Banking options for your merchant account. This API returns real-time bank availability so you can display only working banks to your customers.</p>
                            </div>

                            <!-- Prerequisites -->
                            <div class="sm-guide-prereqs">
                                <h3>Prerequisites</h3>
                                <div class="sm-prereq-list">
                                    <div class="sm-prereq-item"><span class="sm-prereq-icon">&#10003;</span><div><strong>Merchant Key &amp; Salt</strong><br>Your PayU credentials</div></div>
                                    <div class="sm-prereq-item"><span class="sm-prereq-icon">&#10003;</span><div><strong>Net Banking Enabled</strong><br>NB payment mode enabled on your merchant account</div></div>
                            </div>
                        </div>

                            <!-- Why This Step -->
                            <div class="sm-guide-steps">
                                <h3>Why This Step?</h3>
                                <div class="sm-numbered-steps">
                                    <div class="sm-step"><div class="sm-step-num">1</div><div class="sm-step-content"><strong>Real-time availability</strong><p>Get current bank status - some banks may be temporarily down.</p></div></div>
                                    <div class="sm-step"><div class="sm-step-num">2</div><div class="sm-step-content"><strong>Valid bank codes</strong><p>Get correct <code>ibibo_code</code> values to use as <code>bankcode</code> in payments.</p></div></div>
                                    <div class="sm-step"><div class="sm-step-num">3</div><div class="sm-step-content"><strong>Better UX</strong><p>Only show active banks to customers, reducing failed attempts.</p></div></div>
                                </div>
                            </div>
                        </div>

                        <!-- API Reference -->
                        <h3>API Reference</h3>
                        <div class="sm-info-box" style="margin-bottom:1rem; background:#f0fff4; border:1px solid #9ae6b4;">
                            <strong>Endpoint:</strong> <code>POST https://test.payu.in/merchant/postservice.php?form=2</code>
                        </div>
                        <table class="sm-table">
                            <thead><tr><th>Parameter</th><th>Required</th><th>Description</th><th>Example</th></tr></thead>
                            <tbody>
                                <tr><td><code>key</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Merchant key provided by PayU during onboarding</td><td>a4vGC2</td></tr>
                                <tr><td><code>command</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>API command &mdash; fixed <code>getNetbankingStatus</code></td><td>getNetbankingStatus</td></tr>
                                <tr><td><code>var1</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>Bank code or <code>default</code> for all banks</td><td>default</td></tr>
                                <tr><td><code>hash</code></td><td><span class="sm-badge-mandatory">Mandatory</span></td><td>SHA-512 hash (auto-computed from key, command, var1, salt)</td><td><em>(computed)</em></td></tr>
                            </tbody>
                        </table>
                        
                        <div class="sm-code-block" style="margin-top:1rem;">
                            <div class="sm-code-header"><span>Hash Formula</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>sha512(key|command|var1|salt)

Example (all banks):
sha512(a4vGC2|getNetbankingStatus|default|YourSaltHere)

Example (specific bank):
sha512(a4vGC2|getNetbankingStatus|AXIB|YourSaltHere)</code></pre>
                        </div>

                        <!-- Sample Response -->
                        <h3 style="margin-top:1.5rem;">Sample Response</h3>
                        <div class="sm-code-block">
                            <div class="sm-code-header"><span>Response Array</span><button onclick="smCopyCode(this)">Copy</button></div>
                            <pre><code>[
  {
    "id": "103",
    "ibibo_code": "AXIB",           // Use this as bankcode
    "bank_name": "Axis Bank",
    "mode": "NB",                   // Filter by this for Net Banking
    "up_status": 1,                 // 1 = Up, 0 = Down
    "priority": "1",
    "account_required_on_signup": "1"
  },
  ...
]</code></pre>
                        </div>

                        <h3 style="margin-top:1.5rem;">Try It &mdash; Send Real Request</h3>
                        <div style="background:#ebf8ff; border:1px solid #90cdf4; border-radius:8px; padding:1rem; margin-bottom:1rem;">
                            <strong style="color:#2b6cb0;">&#128161; Quick Start:</strong>
                            <span style="color:#2c5282;">Click "Fetch All Active Banks" to get the complete list of available Net Banking options for your merchant account.</span>
                        </div>
                        <div class="sm-interactive-form" id="smNbStatusForm">
                            <div class="sm-form-row">
                                <div class="sm-form-group"><label>Merchant Key  <span class="required">*</span></label><input type="text" id="sm_nb_status_key" value="a4vGC2"></div>
                                <div class="sm-form-group"><label>Merchant Salt  <span class="required">*</span></label><input type="text" id="sm_nb_status_salt" value="hKvGJP28d2ZUuCRz5BnDag58QBdCxBli" autocomplete="off" style="-webkit-text-security: disc;"></div>
                            </div>
                            <div class="sm-form-row">
                                <div class="sm-form-group"><label>Bank Code (var1)</label><input type="text" id="sm_nb_status_bankcode" placeholder="Leave empty for all banks, or enter specific code"></div>
                                <div class="sm-form-group" style="display:flex; align-items:flex-end;"><button class="button" onclick="document.getElementById('sm_nb_status_bankcode').value=''; smNbSendStatusRequest();" style="background:#38a169; border-color:#38a169;">&#127974; Fetch All Banks (var1=default)</button></div>
                            </div>
                            <div class="sm-form-actions">
                                <button class="button sm-btn-secondary" onclick="smNbPreviewStatusRequest()">Preview Request</button>
                                <button class="button sm-btn-primary" onclick="smNbSendStatusRequest()">Check Specific Bank &rarr;</button>
                            </div>
                        </div>
                        <div id="smNbStatusReqRes" class="sm-req-res-panel" style="display:none;">
                            <div class="sm-req-res-grid">
                                <div class="sm-req-panel"><div class="sm-panel-header"><span>Request Sent</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div><pre><code id="smNbStatusRequestView"></code></pre></div>
                                <div class="sm-res-panel"><div class="sm-panel-header"><span>Response Received</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div><div id="smNbStatusStatusBadge" class="sm-status-badge"></div><pre><code id="smNbStatusResponseView"></code></pre></div>
                            </div>
                            <div class="sm-curl-section"><div class="sm-panel-header"><span>cURL Command</span><button onclick="smCopyCode(this)" class="sm-copy-btn">Copy</button></div><pre><code id="smNbStatusCurlView"></code></pre></div>
                        </div>

                        <!-- Active Banks Display -->
                        <div id="smNbActiveBanksList" style="display:none; margin-top:1.5rem;">
                            <h3 style="color:#2d3748; margin-bottom:1rem;">&#127974; Net Banking Options <span id="smNbBankCount" style="font-size:0.85rem; color:#718096; font-weight:normal;"></span></h3>
                            <p style="color:#4a5568; font-size:0.9rem; margin-bottom:1rem;">Only showing <code>mode: "NB"</code> options. Use the <strong>ibibo_code</strong> as <code>bankcode</code> in your payment request.</p>
